//! TypeScript emission for the Svelte → `.svelte.ts` pipeline.
//!
//! ### Status: scaffolding pass + per-file render name + import hoisting
//!
//! Emits a TypeScript wrapper around each Svelte component:
//!
//! ```text
//! // generated by svelte-check-native; do not edit
//! [module script verbatim]
//! [hoisted imports from instance script]
//! function $$render_<8-char-content-hash>() {
//!     [instance script body, with imports blanked out]
//!     async function __svn_tpl_check() {
//!         [for-loops for each {#each} block]
//!         [action-attrs / bind-pair declarations]
//!     }
//!     void (__svn_tpl_check, ...synthesized names);
//! }
//! $$render_<hash>;
//! ```
//!
//! Per-file `$$render` naming prevents the TS2393 "duplicate function
//! implementation" cascade that fires when multiple components in one
//! tsgo project declare the same global. Hash is derived from the
//! source path so it's stable across runs.
//!
//! Import hoisting prevents TS1232: ES `import` declarations are illegal
//! inside a function body, so we lift every `import` statement out of
//! the wrapped instance script to module top-level.
//!
//! ### What's still NOT here (next emit-fidelity rounds)
//!
//! - Real svelte type shims (`helpers.d.ts` shipped to the cache).
//!   Currently we don't emit any svelte-aware types; users get the real
//!   svelte package's types only if they have it installed in
//!   node_modules.
//! - Component-instantiation type-checking (props, slots, events) —
//!   needed for TS2741 "missing required prop" diagnostics.
//! - Element attribute type-checking — needed for HTML attribute
//!   correctness.
//! - Lifting template `{expr}` interpolations into the template-check
//!   function with proper scope.
//! - Real source maps so line/column point at the `.svelte` source.
//!   Today we use a fixed line offset which only works for diagnostics
//!   inside the verbatim script body.

#![cfg_attr(test, allow(clippy::expect_used, clippy::unwrap_used))]

mod emit_buffer;
pub mod kit_inject;
mod script_split;
mod state_nullish_rewrite;
// SVELTE-4-COMPAT: droppable submodule for Svelte-4 emit rewrites.
// See design/phase_g/DESIGN.md.
mod svelte4;
mod sveltekit;

use std::fmt::Write;
use std::path::Path;

use std::collections::HashSet;

use oxc_allocator::Allocator;
use smol_str::SmolStr;
use svn_analyze::{
    PropsInfo, TemplateSummary, collect_top_level_bindings, collect_typed_top_level_lets,
    collect_typed_uninit_lets, find_store_refs_with_bindings, find_template_refs,
};
use svn_parser::Document;
use svn_parser::{EachBlock, Fragment, Node, SnippetBlock, parse_script_body};

use crate::emit_buffer::EmitBuffer;
use crate::script_split::split_imports;

/// Output of [`emit_document`].
#[derive(Debug, Clone)]
pub struct EmitOutput {
    pub typescript: String,
    /// The synthesized name we used for this file's render function — so
    /// callers (e.g. test code) can assert on it without re-deriving the
    /// hash.
    pub render_name: SmolStr,
    /// Line map: for each contiguous run of verbatim source content that
    /// landed in the overlay, an entry mapping the overlay line range
    /// back to the source line range.
    pub line_map: Vec<LineMapEntry>,
    /// Token map: byte-span entries mapping a specific synthesized span
    /// in the overlay back to a byte span in the `.svelte` source. Used
    /// by the diagnostic mapper to surface errors at user positions
    /// even when the overlay line the error landed on is inside
    /// synthesized scaffolding (the line is NOT covered by `line_map`).
    ///
    /// Entries are pushed by emit at each site that splices user
    /// source into synthesized scaffolding — template interpolations,
    /// component-call prop values, `bind:this` assignments, `$on`
    /// event-name literals. An empty vec is the current default
    /// (Item 1 plumbing only); emit sites will start pushing in the
    /// follow-up PRs (Items 2/3/4 of the v0.3 plan).
    pub token_map: Vec<TokenMapEntry>,
    /// Byte offsets of the start of each line in `typescript`. Entry N
    /// holds the byte offset where line N+1 begins (1-based line
    /// numbering: index 0 is the start of line 1). Appended is a
    /// sentinel equal to `typescript.len()` so a binary search can
    /// clamp the final line. Used to convert a tsgo `(line, column)`
    /// diagnostic position into an overlay byte offset for
    /// TokenMapEntry lookup.
    pub overlay_line_starts: Vec<u32>,
    /// Byte offsets of the start of each line in the `.svelte` source
    /// this overlay was emitted from. Same shape as
    /// `overlay_line_starts`. Used by the diagnostic mapper to
    /// convert a TokenMapEntry's `source_byte` span back into a
    /// 1-based (line, column) for the user-facing diagnostic.
    pub source_line_starts: Vec<u32>,
}

/// Single line mapping from the overlay back to the original `.svelte`
/// source. Both line numbers are 1-based.
///
/// Within `[overlay_start_line, overlay_end_line)`, line N maps to
/// source line `source_start_line + (N - overlay_start_line)`.
///
/// Lines that fall outside any entry's range are synthesized (header
/// comment, function wrapper, void block) and have no source mapping —
/// the diagnostic mapper clamps them to `source_start_line` of the
/// nearest preceding entry, or to line 1 if none exists.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct LineMapEntry {
    pub overlay_start_line: u32,
    pub overlay_end_line: u32,
    pub source_start_line: u32,
}

/// Single byte-span mapping from a synthesized region of the overlay
/// back to a byte range in the `.svelte` source. Both ranges are
/// half-open `[start, end)` byte offsets.
///
/// TokenMapEntry lives alongside [`LineMapEntry`]: line-map covers
/// verbatim script blocks (where overlay line N trivially maps to
/// source line source_start + N - overlay_start), token-map covers
/// synthesized scaffolding where a specific overlay token was
/// spliced in from a specific source position (template `{expr}`
/// interpolations, `new __svn_C_N({...})` call sites with user-source
/// prop values, `bind:this` assignments, `$on` event-name literals).
///
/// The diagnostic mapper prefers the tightest-span TokenMapEntry
/// containing the diagnostic's byte offset; falls back to
/// LineMapEntry when no token-map match exists; drops the
/// diagnostic when neither matches (mirrors upstream svelte-check's
/// source-map-driven filter).
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct TokenMapEntry {
    pub overlay_byte_start: u32,
    pub overlay_byte_end: u32,
    pub source_byte_start: u32,
    pub source_byte_end: u32,
}

/// Emit the TypeScript scaffold for a parsed Svelte document.
///
/// `source_path` is used to derive a per-file unique render-function name
/// (hash of the canonical path). Callers without a real path (unit tests)
/// pass any stable string; the resulting hash will be identical for the
/// same input string, which is fine.
pub fn emit_document(
    doc: &Document<'_>,
    fragment: &Fragment,
    summary: &TemplateSummary,
    source_path: &Path,
) -> EmitOutput {
    emit_document_with_lang(doc, fragment, summary, source_path, true)
}

/// Like [`emit_document`] but lets the caller pick whether the overlay
/// is TypeScript (`is_ts = true` — `.svelte.svn.ts`, TS-strict
/// inference) or JavaScript (`is_ts = false` — `.svelte.svn.js`,
/// JS-loose inference under `checkJs:true + noImplicitAny:false`).
///
/// The CLI dispatches per-file based on the source's `<script lang=>`
/// attribute, mirroring upstream svelte-check's `isTsSvelte(text)`
/// dispatch in
/// `language-tools/packages/svelte-check/src/incremental.ts:213`.
/// Two effects flow from the choice:
///   - TS-only syntax (`!:` definite-assign, `as any` casts, function
///     generics, `declare const`, `interface`/`type` aliases) is
///     replaced with the equivalent JSDoc form for JS overlays.
///   - The `.svelte.svn.js` extension flips tsgo's per-file inference
///     mode — `let x = $state([])` widens to `any[]` in JS, stays
///     `never[]` in TS. Load-bearing for JSDoc-typed Props
///     components that wrap a third-party default export (the
///     CodeMirror integration pattern) and for any JSDoc-typed
///     Props component,
///     where tsgo natively reads `/** @typedef */` / `/** @type */`
///     annotations only under `.js`.
pub fn emit_document_with_lang(
    doc: &Document<'_>,
    fragment: &Fragment,
    summary: &TemplateSummary,
    source_path: &Path,
    is_ts: bool,
) -> EmitOutput {
    let render_name = render_function_name(source_path);
    emit_document_with_render_name(doc, fragment, summary, render_name, source_path, is_ts)
}

fn emit_document_with_render_name(
    doc: &Document<'_>,
    fragment: &Fragment,
    summary: &TemplateSummary,
    render_name: SmolStr,
    source_path: &Path,
    is_ts: bool,
) -> EmitOutput {
    // Set the thread-local so deep emit sites (bind:this casts,
    // each-block `let i`, branch bindings, snippet params) can branch
    // on TS-vs-JS overlay shape without threading `is_ts` through 9+
    // function signatures. Reset on scope exit via `IsTsGuard`.
    let _ts_guard = IsTsGuard::enter(is_ts);
    let estimated_capacity = doc.source.len().saturating_mul(2).saturating_add(256);
    let mut buf = EmitBuffer::with_capacity(estimated_capacity);

    buf.push_str("// generated by svelte-check-native; do not edit\n");

    // Module script content (already at module level — no special handling).
    if let Some(module_script) = &doc.module_script {
        // Pad to a trailing `\n` before calling `append_verbatim` so a
        // single-line script (no terminating newline) still produces a
        // LineMapEntry — append_verbatim only emits one when the text
        // spans at least one newline, and we need source mapping for the
        // overlay region even if the script is one line. The padded `\n`
        // is synthetic filler, semantically equivalent to the old
        // separate `push_str("\n")` that previous code did afterwards.
        let padded;
        let text: &str = if module_script.content.ends_with('\n') {
            module_script.content
        } else {
            padded = format!("{}\n", module_script.content);
            &padded
        };
        buf.append_verbatim(text, doc.source, module_script.content_range);
    }

    // `<script generics="T extends ...">` — pulled from the parser's
    // ScriptSection::generics. Extracted up front so script_split can
    // decide whether to hoist bare `type`/`interface` declarations out
    // of the render body (they'd lose access to the `T` generic if
    // lifted to module scope).
    let generics = extract_generics_attr(doc);

    // Parse the instance script exactly once up front. Every analyze
    // pass that needs the oxc AST of the ORIGINAL script (Props type
    // source, declared props, top-level bindings, typed uninitialized
    // lets, typed top-level lets) derives its facts from this single
    // parse — each was its own reparse + allocator before, which
    // added up to 4-5 repeats of the same work on the hot path. The
    // `rewritten_content` reparse at bindings-collection time is
    // separate (different source string) and only fires when the
    // Svelte-4 reactive rewrite actually touched the script.
    let alloc_instance = Allocator::default();
    let parsed_instance = doc
        .instance_script
        .as_ref()
        .map(|s| parse_script_body(&alloc_instance, s.content, s.lang));

    // Single analyze-time resolution of every Props decision emit
    // makes downstream — type text, type root name, destructure
    // locals, and which of the four priority branches produced the
    // result. See PropsInfo in svn-analyze.
    //
    // script_split consumes `type_root_name` to decide whether a
    // given `type`/`interface` declaration IS the Props annotation.
    // Props always hoists, even when its body references locals via
    // `typeof`, because consumers need the Props type visible at
    // module scope to get typed contextual flow. Non-Props types
    // that reference body-locals via `typeof` stay body-scoped so
    // `keyof typeof X` resolves against the real declaration rather
    // than the lossy declare-const stub.
    let mut props_info: PropsInfo =
        if let (Some(s), Some(parsed)) = (doc.instance_script.as_ref(), parsed_instance.as_ref()) {
            PropsInfo::build(&parsed.program, s.content)
        } else {
            PropsInfo::default()
        };

    // TS-source hard-mode synthesis: when the overlay is TS AND the
    // source script is `<script lang="ts">` AND there's a `$props()`
    // destructure AND PropsInfo found no other type source (no TS
    // annotation / no $$Props / no export-let), synthesise a literal
    // `{ k: T, k?: U, … }` from the destructure and inject it as the
    // Props type source.
    //
    // Mirrors upstream svelte2tsx's `ExportedNames.handle$propsRune`
    // lines 286-399: TS files fall through the JSDoc-comment path
    // (`if (!this.isTsFile)` gate at line 240) and go straight to the
    // "best-effort" synthesis from the destructure object pattern.
    //
    // Rationale for the lang-gate: if we mirrored upstream exactly for
    // JS-source files too, we'd need to convert JSDoc `@typedef` Props
    // into a TS type alias, which is a bigger fix. For the BlockEditor
    // / SectionEditor-style `head` under-fire cluster — the
    // real-diagnostic gap on the CMS-style bench — only
    // TS-source components are load-bearing, so scope the change
    // narrowly and expand later if needed.
    // SvelteKit route files (+page.svelte / +layout.svelte) have their
    // own synthesis path (`sveltekit::synthesize_route_props_type`) that
    // injects `import('./$types.js').PageData` etc. onto the recognized
    // `data` / `form` / `params` destructure keys. Skip the generic TS
    // synthesis on those so the route-aware path wins.
    let is_route_file = sveltekit::route_kind(source_path).is_some();
    if is_ts
        && !is_route_file
        && doc.script_lang() == svn_parser::ScriptLang::Ts
        && props_info.type_text.is_none()
        && !props_info.destructures.is_empty()
        && let Some(literal) = synthesise_js_props_typedef_body(&props_info)
    {
        props_info.type_text = Some(literal);
        props_info.type_root_name = None;
        props_info.source = svn_analyze::PropsSource::SynthesisedFromDestructure;
    }

    // Three-trigger gate for event-type narrowing, matching upstream
    // svelte2tsx (`ComponentEvents.ts:84-86` + `ExportedNames.isRunesMode`).
    // Narrow ONLY when the user opted in via ONE of:
    //   1. `interface $$Events` / `type $$Events` declared.
    //   2. `<script strictEvents>` attribute.
    //   3. Runes mode.
    // Otherwise stay lax (child events flow through the default
    // `(e: any) => any` overload). This matches upstream's behavior
    // for Svelte-4 components that happen to use
    // `createEventDispatcher<T>()` without opting into strict events —
    // narrowing those without opt-in produced 18 legitimate-but-new
    // errors on a Svelte-4 bench in the reverted commit 3c24f18.
    let narrow_events = has_strict_events(doc) || has_strict_events_attr(doc) || is_runes_mode(doc);
    // If the component doesn't already declare `$$Events` but opted in
    // via one of the other two triggers, pull the dispatcher's type
    // argument as the source for a synthesised `type $$Events = T;`.
    // Returns None when the user doesn't use `createEventDispatcher<T>()`
    // or aliases the import — fall-through to the lax shim is safe in
    // both cases.
    let synthesized_events_type: Option<String> = if !narrow_events || has_strict_events(doc) {
        None
    } else {
        parsed_instance
            .as_ref()
            .zip(doc.instance_script.as_ref())
            .and_then(|(p, s)| {
                svn_analyze::find_dispatcher_event_type_source(&p.program, s.content)
            })
    };

    // SVELTE-4-COMPAT: rewrite `$: ...` reactive statements before
    // the Svelte-5-shaped passes run, so downstream code sees the
    // Svelte-5 equivalents:
    //   - `$: b = expr`    → `let b = $derived(expr)` (declaration)
    //   - `$: count++`     → `count++;`                (re-assignment, label dropped)
    //   - `$: console.log` → `() => { $: console.log };` (expr/block wrap)
    // See crates/emit/src/svelte4/reactive.rs.
    let mut reactive_touched_names: Vec<SmolStr> = Vec::new();
    let rewritten_content: Option<String> = doc.instance_script.as_ref().map(|s| {
        let (after_reactive, touched) =
            svelte4::reactive::rewrite_with_touched_names(s.content, s.lang);
        reactive_touched_names = touched;
        // Rewrite `let X: Type = $state(null | undefined)` to
        // `$state<Type>(null | undefined)` so the single-T `$state`
        // shim overload picks `T` from the explicit generic (sourced
        // from the annotation) rather than collapsing to `null` from
        // the argument. See `state_nullish_rewrite` for the full
        // reasoning — this pass is the reason we can keep `$state`
        // as a single-T overload: the literal-type overloads we'd
        // otherwise need for the bind:this pattern collide with
        // TypeScript's overload resolution on
        // `$state<Promise<T>>(new Promise(() => {}))`, where the
        // explicit `<T>` no longer propagates as contextual type to
        // the argument.
        state_nullish_rewrite::rewrite(&after_reactive, s.lang)
    });

    // Hoist imports out of the instance script. Required because the
    // instance body gets wrapped in `function $$render() { ... }` and ES
    // `import` declarations can't appear inside a function (TS1232).
    let split = doc.instance_script.as_ref().map(|s| {
        let content = rewritten_content.as_deref().unwrap_or(s.content);
        split_imports(
            content,
            s.lang,
            generics.is_some(),
            props_info.type_root_name.as_deref(),
        )
    });

    emit_hoisted_imports(&mut buf, split.as_ref(), doc, is_ts);

    // `<script generics="T extends ...">` (extracted above) — expose
    // the type params as generics on the wrapping function so
    // references inside the body resolve. Falls back to no-generics
    // when the attribute is absent.
    //
    // The wrapper is `async` because Svelte 5 components are allowed to
    // use top-level `await` in their `<script>` body (TLA via Vite/SvelteKit
    // is supported); without `async` we'd report TS1308 for those.
    // For JS overlays, synthesise `@typedef {...} $$ComponentProps`
    // when the destructure has non-bindable keys that aren't in the
    // user's `@typedef Props` block — upstream svelte2tsx's
    // selector. Bindable-only extras (e.g. `element = $bindable()`)
    // don't trigger synthesis; upstream treats them as part of the
    // "real" props shape that Props may omit. When the user has
    // no Props at all, synthesis fires unconditionally.
    //
    // Per-default-value type inference in
    // `analyze::infer_default_type` mirrors upstream's
    // `getTypeForDefault` (`= ''` → `string`, `= () => {}` →
    // `Function`, `= {}` → `Record<string, any>`, `= null` → widen
    // to `any`, …) so the synthesised typedef matches upstream's
    // shape on the synth path.
    let synthesised_js_props_typedef = if !is_ts {
        let script = doc
            .instance_script
            .as_ref()
            .map(|s| s.content)
            .unwrap_or("");
        if should_synthesise_js_props(&props_info, script) {
            synthesise_js_props_typedef_body(&props_info)
        } else {
            None
        }
    } else {
        None
    };
    if let Some(body) = synthesised_js_props_typedef.as_deref() {
        // JSDoc `@typedef {<typespec>} Name` — body already includes
        // the outer `{}` for object-literal types, so the JSDoc
        // wrapping pair gives `{{...}}` in the final output.
        buf.push_str("/** @typedef {");
        buf.push_str(body);
        buf.push_str("} $$ComponentProps */\n");
    }

    // TS overlay: wrap inline-literal Props types in a module-scope
    // `type $$ComponentProps = …;` alias and swap the literal for the
    // alias name in downstream emit. Two cases feed this path:
    //
    //   1. `PropsSource::SynthesisedFromDestructure` — the TS-source
    //      hard-mode synthesis block above replaced `type_text` with
    //      a literal from the destructure shape.
    //   2. `PropsSource::RuneAnnotation` with a literal `{ … }`
    //      annotation on the `$props()` destructure — e.g.
    //      `let { site }: { site?: Site } = $props()`. Upstream
    //      svelte2tsx aliases these too (see their emit for
    //      SitePreview.svelte).
    //
    // Consumer error messages then reference `$$ComponentProps` as the
    // target type rather than the inlined literal structure — matches
    // upstream byte-for-byte on excess-prop errors.
    let ty_is_literal = props_info
        .type_text
        .as_deref()
        .is_some_and(|t| t.trim_start().starts_with('{'));
    let should_alias = is_ts
        && ty_is_literal
        && matches!(
            props_info.source,
            svn_analyze::PropsSource::SynthesisedFromDestructure
                | svn_analyze::PropsSource::RuneAnnotation
                | svn_analyze::PropsSource::RuneGeneric
        );
    if should_alias && let Some(body) = props_info.type_text.as_deref() {
        let _ = writeln!(buf, "type $$ComponentProps = {body};");
        props_info.type_text = Some("$$ComponentProps".to_string());
        props_info.type_root_name = Some(SmolStr::new("$$ComponentProps"));
    }

    match &generics {
        Some(g) => {
            let _ = writeln!(buf, "async function {render_name}<{g}>() {{");
        }
        None => {
            let _ = writeln!(buf, "async function {render_name}() {{");
        }
    }
    // Synthesised `type $$Events = <T>;` from a typed
    // `createEventDispatcher<T>()` call, when the three-trigger gate
    // fires and the user didn't already declare the interface.
    // Placed INSIDE the render body so `T` can reference body-local
    // generics (`<script generics="A"> … createEventDispatcher<{a: A}>()`)
    // — at module scope `A` would fire TS2304. The class-wrapper's
    // `events()` method projects this back out to consumers via
    // `Awaited<ReturnType<typeof $$render<…>>>['events']`.
    if let Some(t) = synthesized_events_type.as_deref() {
        let _ = writeln!(buf, "    type $$Events = {t};");
    }
    let ScriptAndTemplateAnalysis {
        prop_names,
        prop_type_source,
        store_refs,
        template_void_refs,
        template_type_refs,
    } = analyze_script_and_template_refs(
        doc,
        source_path,
        fragment,
        parsed_instance.as_ref(),
        split.as_ref(),
        rewritten_content.as_deref(),
        &props_info,
    );

    // Store auto-subscribe aliases: declare a typed `let $store!:
    // __SvnStoreValue<typeof store>;` for every detected `$ident`.
    //
    // Why `let !` and not `const = expr`:
    //   - `$store` references in the body need the alias to be visible
    //     at the top of the function, but the underlying `store` may be
    //     declared FURTHER DOWN in the body (or hoisted above as an
    //     import). A value-position reference like `__svn_store_get(store)`
    //     fires TS2448 ("used before declaration") for body-declared
    //     stores. A type-position reference (`typeof store`) is resolved
    //     lazily by TS and works regardless of declaration order.
    //   - `__SvnStoreValue<typeof store>` extracts the value type out of
    //     the store wrapper using a conditional infer. Without this,
    //     downstream code (`$store.bar`, `$store.map(...)`) would see
    //     `any` and cascade into TS7006/TS18046/TS2339/TS2698 hits.
    //   - The `!` definite-assignment assertion suppresses TS2454; we
    //     never actually assign to `$store` ourselves, but Svelte's
    //     compiler treats the identifier as initialized at runtime.
    for name in &store_refs {
        let base = name.strip_prefix('$').unwrap_or(name);
        if is_ts {
            let _ = writeln!(buf, "    let {name}!: __SvnStoreValue<typeof {base}>;");
        } else {
            // JS-overlay form — `!:` definite-assign is TS-only
            // syntax, so initialise via a JSDoc-typed double-cast
            // through `any` (matches the design fixture pattern in
            // `design/js_overlay/fixture/src/04_store_unwrap.svelte.svn.js`).
            let _ = writeln!(buf, "    /** @type {{__SvnStoreValue<typeof {base}>}} */");
            let _ = writeln!(
                buf,
                "    let {name} = /** @type {{any}} */ (/** @type {{any}} */ (null));"
            );
        }
    }

    // SVELTE-4-COMPAT: `$$slots`, `$$props`, `$$restProps` ambients.
    // Only inject the declaration when the source actually references
    // the name — keeps the overlay tight on Svelte-5-only codebases
    // and avoids shadowing the user's own `$$slots` local if any.
    // Detection is a substring check against the full document source
    // (script + template). Ambiguity risk: a literal `$$slots` inside
    // a string or comment would trigger the declaration, but that's
    // harmless — the `let` just goes unused in the overlay.
    emit_svelte4_ambients(buf.raw_string_mut(), doc, is_ts);

    if let Some(s) = &split {
        if let Some(instance) = &doc.instance_script {
            // Resync the buffer's internal line counter — `emit_svelte4_ambients`
            // above uses `buf.raw_string_mut()` and pushes content without
            // updating `overlay_line`. `append_verbatim` relies on that
            // counter for LineMapEntry.overlay_start_line, so refresh it
            // before calling. Once those helpers take EmitBuffer directly
            // (later phases), this resync can go.
            buf.resync_current_line();
            // Same padding trick as the module-script site: pad a missing
            // trailing `\n` so `append_verbatim`'s LineMapEntry covers
            // the same overlay span `count_lines(&s.body)` accounted for.
            // `s.body` is the script-split output (imports removed), not
            // a slice of `doc.source`; the mapping from overlay → source
            // lines is an approximation starting at the original script's
            // `content_range.start` — same approximation the old manual
            // push was making.
            let padded;
            let text: &str = if s.body.ends_with('\n') {
                &s.body
            } else {
                padded = format!("{}\n", s.body);
                &padded
            };
            buf.append_verbatim(text, doc.source, instance.content_range);
        }
    }

    apply_script_body_rewrites(
        &mut buf,
        summary,
        split.as_ref(),
        &store_refs,
        &reactive_touched_names,
        parsed_instance.as_ref(),
        source_path,
    );

    // Emit the template-check function for both TS and JS overlays.
    // TS-only syntax sites inside (bind: casts, typed lets, each-block
    // `i: number = 0`) are conditionalized on `is_ts` by the
    // sub-emitters; JS overlays get JSDoc equivalents or plain lets.
    emit_template_check_fn(&mut buf, doc, fragment, summary, is_ts);

    let exported_locals: Vec<SmolStr> = split
        .as_ref()
        .map(|s| s.exported_locals.clone())
        .unwrap_or_default();

    let exports_object = build_exports_object(split.as_ref());
    emit_void_block(
        buf.raw_string_mut(),
        summary,
        &store_refs,
        &prop_names,
        &template_void_refs,
        &exported_locals,
        is_ts,
    );

    emit_render_body_return(
        &mut buf,
        doc,
        generics.as_deref(),
        prop_type_source.as_deref(),
        synthesized_events_type.as_deref(),
        exports_object.as_deref(),
        &props_info,
    );

    buf.push_str("}\n");
    let _ = writeln!(buf, "{render_name};");

    // When the template forwards events from a sub-component via the
    // bare `on:EVENT` bubble shorthand (no `={…}` value), upstream's
    // `event-handler.ts` emits
    // `__sveltets_2_bubbleEventDef(__sveltets_2_instanceOf(<Child>).$$events_def, '<event>')`
    // for each bubble. The resulting events literal contains a circular
    // `typeof import('./Child.svelte')` reference that defeats generic
    // inference in `__sveltets_2_with_any_event`, collapsing Props to
    // its `{}` default. The downstream `__sveltets_2_isomorphic_component`
    // inherits that, and `__sveltets_2_ensureComponent(child)` returns
    // a ctor with `props?: {}` — no TS2353/TS2322 on consumer calls.
    //
    // We mirror this by widening the default-export's Props type to
    // `Record<string, any>` when the summary saw any bubble directive.
    // Closes the TS2322 over-fires at component-instantiation
    // sites that pass-through a parent's `page`/`page_slug` to a
    // child that forwards events via `on:delete` / `on:create`
    // (the recursive SitePages/Item pattern that surfaced the
    // need for this widening).
    let prop_type_effective: Option<String> = if summary.has_bubbled_component_event {
        Some("Record<string, any>".to_string())
    } else {
        prop_type_source.clone()
    };
    emit_default_export_declarations(
        &mut buf,
        doc,
        fragment,
        split.as_ref(),
        &render_name,
        generics.as_deref(),
        prop_type_effective.as_deref(),
        exports_object.as_deref(),
        &template_type_refs,
        is_ts,
    );

    // `.svelte` import specifiers are left unchanged. TS resolves
    // them via `allowArbitraryExtensions` + the ambient
    // `Foo.d.svelte.ts` sidecar written by the typecheck cache writer,
    // which re-exports from the real overlay at `Foo.svelte.svn.ts`.
    //
    // Not rewriting also preserves the bundler-mode auto-append path
    // for `import X from './Foo.svelte'` where `Foo.svelte.ts` is the
    // user's runes module (Svelte 5 convention, e.g. bits-ui,
    // shadcn-svelte) — TS tries `.svelte` literal, then `.svelte.ts`,
    // then our ambient, in that order. Rewriting to
    // `./Foo.svelte.svn.ts` would short-circuit the runes-module
    // fallback.

    let (out, line_map, token_map) = buf.finish();
    let overlay_line_starts = compute_line_starts(&out);
    let source_line_starts = compute_line_starts(doc.source);

    // All TokenMapEntries are now pushed inline during emit via
    // `EmitBuffer::append_with_source` (user-authored expression
    // splices) and `EmitBuffer::push_token_map` (synthesized-scaffolding
    // spans like component calls). No post-walk scanners remain.

    EmitOutput {
        typescript: out,
        render_name,
        line_map,
        token_map,
        overlay_line_starts,
        source_line_starts,
    }
}

/// Props, store auto-subscribes, and template-referenced identifier
/// buckets — the analyze pass that runs after hoisted imports but
/// before the template-check wrapper.
struct ScriptAndTemplateAnalysis {
    prop_names: Vec<SmolStr>,
    prop_type_source: Option<String>,
    store_refs: Vec<SmolStr>,
    template_void_refs: Vec<SmolStr>,
    template_type_refs: Vec<SmolStr>,
}

/// Analyze script + template for: destructured prop names, the Props
/// type source (user-provided or SvelteKit-synthesised), `$store`
/// auto-subscribe refs (script + template sides), template-referenced
/// void-refs (script bindings used only in markup — avoids TS6133),
/// and template-referenced type-only imports (kept alive via a module-
/// scope type alias).
///
/// Script-binding collection unions the module script, the instance
/// script (original, with imports visible), and the rewritten content
/// (so reactive-destructure-introduced names — `$: ({a, b} = expr)` →
/// `let {a, b} = …` — participate in subsequent `$a`/`$b` store-alias
/// detection).
fn analyze_script_and_template_refs<'alloc>(
    doc: &svn_parser::Document<'_>,
    source_path: &Path,
    fragment: &svn_parser::Fragment,
    parsed_instance: Option<&svn_parser::ParsedScript<'alloc>>,
    split: Option<&script_split::SplitScript>,
    rewritten_content: Option<&str>,
    props_info: &PropsInfo,
) -> ScriptAndTemplateAnalysis {
    let mut script_bindings: HashSet<String> = HashSet::new();
    if let Some(module_script) = &doc.module_script {
        let alloc_mod = Allocator::default();
        let parsed_mod = parse_script_body(&alloc_mod, module_script.content, module_script.lang);
        collect_top_level_bindings(&parsed_mod.program, &mut script_bindings);
    }

    let (prop_names, prop_type_source): (Vec<SmolStr>, Option<String>) =
        if let (Some(_s), Some(instance), Some(parsed_orig)) =
            (split, &doc.instance_script, parsed_instance)
        {
            let props: Vec<SmolStr> = props_info
                .destructures
                .iter()
                .map(|p| p.local_name.clone())
                .collect();

            // SvelteKit auto-typing: route components (+page.svelte,
            // +layout.svelte) with an untyped `$props()` pick up
            // `PageData` / `LayoutData` / `ActionData` from the file
            // path + the list of destructured prop names. Only fires
            // when PropsInfo saw no user-provided source.
            let ty = props_info.type_text.clone().or_else(|| {
                sveltekit::route_kind(source_path).and_then(|kind| {
                    let names_borrow: Vec<&str> = props.iter().map(|s| s.as_str()).collect();
                    sveltekit::synthesize_route_props_type(kind, &names_borrow)
                })
            });

            collect_top_level_bindings(&parsed_orig.program, &mut script_bindings);
            if let Some(rewritten) = rewritten_content {
                let alloc_rw = Allocator::default();
                let parsed_rw = parse_script_body(&alloc_rw, rewritten, instance.lang);
                collect_top_level_bindings(&parsed_rw.program, &mut script_bindings);
            }
            (props, ty)
        } else {
            (Vec::new(), None)
        };

    // Store auto-subscribe scan happens AFTER both module + instance
    // bindings are collected, so a `$properties` use in instance can
    // resolve to a `properties` declared in `<script module>`.
    let mut store_refs: Vec<SmolStr> = {
        let mut accumulated: Vec<SmolStr> = Vec::new();
        let mut seen: HashSet<String> = HashSet::new();
        let push_unique =
            |found: Vec<SmolStr>, seen: &mut HashSet<String>, out: &mut Vec<SmolStr>| {
                for name in found {
                    if seen.insert(name.to_string()) {
                        out.push(name);
                    }
                }
            };
        if let Some(module_script) = &doc.module_script {
            push_unique(
                find_store_refs_with_bindings(module_script.content, &script_bindings),
                &mut seen,
                &mut accumulated,
            );
        }
        if let Some(instance) = &doc.instance_script {
            push_unique(
                find_store_refs_with_bindings(instance.content, &script_bindings),
                &mut seen,
                &mut accumulated,
            );
        }
        accumulated
    };

    // Type-only imports can be "used" purely inside a template
    // expression (type cast `{foo(item as AppVideo)}`); we intersect
    // with template refs below and emit `type __svn_tpl_type_refs = [A]`
    // so TS doesn't flag the import TS6133.
    let mut type_only_imports: HashSet<String> = HashSet::new();
    if let Some(parsed) = parsed_instance {
        svn_analyze::collect_type_only_import_bindings(&parsed.program, &mut type_only_imports);
    }
    if let Some(module_script) = &doc.module_script {
        let alloc_mod2 = Allocator::default();
        let parsed_mod2 = parse_script_body(&alloc_mod2, module_script.content, module_script.lang);
        svn_analyze::collect_type_only_import_bindings(
            &parsed_mod2.program,
            &mut type_only_imports,
        );
    }

    // Single template walk produces: void-refs (script bindings used
    // only in markup), template-side store-auto-subscribes, and type-
    // only-import type refs.
    let (template_void_refs, template_store_refs, template_type_refs) =
        if script_bindings.is_empty() && type_only_imports.is_empty() {
            (Vec::new(), Vec::new(), Vec::new())
        } else {
            let already: HashSet<&str> = store_refs
                .iter()
                .chain(prop_names.iter())
                .map(|s| s.as_str())
                .collect();
            let mut tpl_voids = Vec::new();
            let mut tpl_stores = Vec::new();
            let mut tpl_types: Vec<SmolStr> = Vec::new();
            let mut type_seen: HashSet<String> = HashSet::new();
            let mut store_seen: HashSet<String> =
                store_refs.iter().map(|s| s.to_string()).collect();
            for name in find_template_refs(fragment, doc.source) {
                if let Some(base) = name.as_str().strip_prefix('$') {
                    if script_bindings.contains(base) && store_seen.insert(name.to_string()) {
                        tpl_stores.push(name.clone());
                        continue;
                    }
                }
                if script_bindings.contains(name.as_str()) && !already.contains(name.as_str()) {
                    tpl_voids.push(name);
                } else if type_only_imports.contains(name.as_str())
                    && type_seen.insert(name.to_string())
                {
                    tpl_types.push(name);
                }
            }
            (tpl_voids, tpl_stores, tpl_types)
        };
    store_refs.extend(template_store_refs);

    ScriptAndTemplateAnalysis {
        prop_names,
        prop_type_source,
        store_refs,
        template_void_refs,
        template_type_refs,
    }
}

/// Emit the `async function __svn_tpl_check() { … }` wrapper that
/// carries every template expression as real TypeScript. The walk
/// produces per-component prop-checks / bind:this assignments / DOM-
/// binding assignments inline — all pinned to the enclosing block's
/// scope (`{#each as item, i}`, `{#snippet args}`) so block-local refs
/// resolve correctly.
///
/// Legacy action-attr and bind-pair declarations are emitted BEFORE
/// the walk (both live at the top of the wrapper). They write directly
/// via `raw_string_mut`, so the buffer's line counter needs
/// `resync_current_line()` before the walk starts — any `LineMapEntry`
/// the walk pushes reads the current overlay line from that counter.
fn emit_template_check_fn(
    buf: &mut EmitBuffer,
    doc: &svn_parser::Document<'_>,
    fragment: &svn_parser::Fragment,
    summary: &svn_analyze::TemplateSummary,
    is_ts: bool,
) {
    buf.push_str("    async function __svn_tpl_check() {\n");
    buf.push_str("        // template type-check body (incremental)\n");
    emit_legacy_action_attrs(buf.raw_string_mut(), summary, is_ts);
    emit_bind_pair_declarations(buf.raw_string_mut(), summary, is_ts);
    // Index component instantiations by source byte offset so the
    // template walker can emit each prop-check inline at the component
    // node's position — i.e. inside the enclosing `{#each}` / `{#if}`
    // / `{#snippet}` scope. Flat-block emission put every check at
    // the top level of `__svn_tpl_check`, which silently broke any
    // check whose prop expressions referenced a binding introduced by
    // a block.
    let instantiations_by_start: std::collections::HashMap<
        u32,
        &svn_analyze::ComponentInstantiation,
    > = summary
        .component_instantiations
        .iter()
        .map(|i| (i.node_start, i))
        .collect();
    let mut action_counter: usize = 0;
    buf.resync_current_line();
    emit_template_body(
        buf,
        doc.source,
        fragment,
        2,
        &instantiations_by_start,
        &mut action_counter,
    );
    buf.push_str("    }\n");
}

/// Apply the three post-body in-place rewrites: widen-untyped-exports →
/// definite-assign → de-narrow-typed-literal-inits. Order is load-
/// bearing: widen inserts `: any` at the name position, and
/// definite-assign looks for a `:` annotation to decide whether to add
/// `!`. Running the passes in the other order means `!` lands first and
/// hides the original `:` annotation from widen's scanner.
///
/// Also builds the `def_assign_names` set from five sources (bind:this
/// targets, export-stripped locals, store-auto-subscribe bases,
/// reactive-rewrite-touched names, typed uninitialized top-level
/// `let`s) — all of which produce declarations that Svelte treats as
/// definitely-assigned at runtime but TS flow analysis can't prove.
fn apply_script_body_rewrites<'alloc>(
    buf: &mut EmitBuffer,
    summary: &svn_analyze::TemplateSummary,
    split: Option<&script_split::SplitScript>,
    store_refs: &[SmolStr],
    reactive_touched_names: &[SmolStr],
    parsed_instance: Option<&svn_parser::ParsedScript<'alloc>>,
    source_path: &Path,
) {
    let mut def_assign_names: Vec<SmolStr> = summary
        .bind_this_targets
        .iter()
        .map(|t| t.name.clone())
        .collect();
    if let Some(s) = split {
        for name in &s.exported_locals {
            if !def_assign_names.iter().any(|n| n == name) {
                def_assign_names.push(name.clone());
            }
        }
    }
    // `$store` auto-subscribe aliases: definite-assign the underlying
    // `store` local. Body-declared `let store: Writable<T>` without
    // initializer fires TS2454 at every `typeof store` read; the
    // rewrite is a no-op for imports / `const` / initialized `let`.
    for name in store_refs {
        let base = SmolStr::from(name.strip_prefix('$').unwrap_or(name));
        if !def_assign_names.iter().any(|n| n == &base) {
            def_assign_names.push(base);
        }
    }
    // SVELTE-4-COMPAT: names touched by reactive destructure /
    // re-assignment. The reactive rewrite wraps block/expr-form `$:`
    // in an uncalled arrow so TS flow analysis misses the assignment.
    for name in reactive_touched_names {
        if !def_assign_names.iter().any(|n| n == name) {
            def_assign_names.push(name.clone());
        }
    }
    // Every top-level `let NAME: Type;` (typed, no init) in the
    // instance script — the Svelte "declare now, assign later from a
    // handler" pattern. Upstream's TS version doesn't observe the
    // uninitialised state across its transform pipeline; a `!` gives
    // us the same behavior.
    if let Some(parsed_orig) = parsed_instance {
        let mut uninit_lets: Vec<SmolStr> = Vec::new();
        collect_typed_uninit_lets(&parsed_orig.program, &mut uninit_lets);
        for name in uninit_lets {
            if !def_assign_names.iter().any(|n| n == &name) {
                def_assign_names.push(name);
            }
        }
    }
    let route_kind = sveltekit::route_kind(source_path);
    if emit_is_ts() {
        if let Some(s) = split {
            widen_untyped_exported_props_in_place(
                buf.raw_string_mut(),
                &s.exported_locals,
                route_kind,
            );
        }
        rewrite_definite_assignment_in_place(buf.raw_string_mut(), &def_assign_names);
    } else {
        // JS overlay: a single inline-initializer rewrite replaces
        // both TS-mode passes. `let NAME;` → `let NAME = /** @type
        // {any} */ (null);` carries both the type-widen (no TS7034/7005)
        // and definite-assign (no TS2454) semantics in a JSDoc-only
        // form — tsgo parses it cleanly under `.svelte.svn.js` without
        // firing TS8010.
        widen_untyped_exports_jsdoc_in_place(buf.raw_string_mut(), &def_assign_names, route_kind);
    }
    // SVELTE-4-COMPAT de-narrow: typed exported props with literal
    // initializers (`export let size: Size = 'medium'`) AND body-local
    // `let X: T = lit;` both narrow to the literal; inserting
    // `NAME = undefined as any;` after the declaration widens back to
    // the declared annotation, so later comparisons don't fire TS2367
    // "no overlap".
    if let Some(s) = split {
        let mut denarrow_targets: Vec<SmolStr> = s.exported_locals.clone();
        if let Some(parsed_orig) = parsed_instance {
            let mut typed_lets: Vec<SmolStr> = Vec::new();
            collect_typed_top_level_lets(&parsed_orig.program, &mut typed_lets);
            for name in typed_lets {
                if !denarrow_targets.iter().any(|n| n == &name) {
                    denarrow_targets.push(name);
                }
            }
        }
        denarrow_typed_exported_props_in_place(buf.raw_string_mut(), &denarrow_targets);
    }
}

/// Build the `{ name: sig; ... }` object-type text for each
/// `export function` / `export const` / `export let` that script_split
/// surfaced. Consumed in two places:
///   - the render body's `return { exports: undefined as any as (…) }`
///     where body-local refs (`typeof handler`, `$$Props['x']`) resolve
///     inside `$$render`'s own scope.
///   - for non-class-wrapper arms, intersected into the default-export's
///     SvelteComponent type directly (may fire TS2304 for body-local
///     refs — rare and acceptable; class-wrapper arms take the other
///     path and avoid it entirely).
fn build_exports_object(split: Option<&script_split::SplitScript>) -> Option<String> {
    let s = split?;
    if s.export_type_infos.is_empty() {
        return None;
    }
    let mut buf = String::from("{ ");
    for info in &s.export_type_infos {
        buf.push_str(info.name.as_str());
        buf.push_str(": ");
        match &info.type_source {
            Some(t) => buf.push_str(t),
            None => buf.push_str("any"),
        }
        buf.push_str("; ");
    }
    buf.push('}');
    Some(buf)
}

/// Emit the class-wrapper's `return { props, events, slots, bindings,
/// exports };` at the tail of `$$render_<hash>`'s body. Only fires when
/// both generics and a Props type source are present (the gate
/// `use_class_wrapper`) — a sibling `declare class __svn_Render_<hash>`
/// later projects each of the five surfaces back out at module scope
/// via `Awaited<ReturnType<typeof $$render<…>>>['<field>']`.
///
/// Using `undefined as any as <T>` (not `null as <T>`) so `<T>` can be
/// a non-nullable type like `{ foo: string }` without firing TS2352.
/// Body-local `typeof X` / `$$Props['x']` refs inside `<T>` resolve
/// inside the render function's scope where X / $$Props live.
///
/// `events_field` expands to `$$Events` when user-declared or
/// synthesised under the three-trigger gate; otherwise stays `{}` to
/// preserve lax event handling.
/// Scan a JS script for a JSDoc `@typedef {Object} Name` block and
/// return the type name. Prefers a typedef named "Props" when
/// multiple are present — the Svelte-4 / JS-Svelte convention that
/// `/** @type {Props} */ let {...} = $props()` reads from. Falls back
/// to the first typedef when no "Props" is present.
///
/// Cheap substring-based match — avoids the full JSDoc parser. The
/// `@typedef` tag is distinctive enough that false positives (e.g.
/// a documented string literal) are vanishingly rare.
fn scan_jsdoc_typedef_name(script: &str) -> Option<String> {
    let mut first: Option<String> = None;
    let mut rest = script;
    while let Some(pos) = rest.find("@typedef") {
        let after = &rest[pos + "@typedef".len()..];
        // Skip optional `{Object}` / `{T}` type-spec block.
        let after = after.trim_start();
        let after = if let Some(stripped) = after.strip_prefix('{') {
            let mut depth = 1u32;
            let mut end = 0usize;
            for (i, c) in stripped.char_indices() {
                match c {
                    '{' => depth += 1,
                    '}' => {
                        depth -= 1;
                        if depth == 0 {
                            end = i + 1;
                            break;
                        }
                    }
                    _ => {}
                }
            }
            &stripped[end..]
        } else {
            after
        };
        let after = after.trim_start();
        // Extract the identifier that follows.
        let name: String = after
            .chars()
            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_' || *c == '$')
            .collect();
        if !name.is_empty() && !name.chars().next().is_some_and(|c| c.is_ascii_digit()) {
            if name == "Props" {
                return Some(name);
            }
            if first.is_none() {
                first = Some(name);
            }
        }
        rest = &rest[pos + "@typedef".len()..];
    }
    first
}

/// Extract the `@property` key names from the user's
/// `@typedef {Object} Props` (or `Props<...>`) block. Used by the
/// synth-vs-use-Props heuristic in `emit_render` and
/// `emit_render_body_return` — when the destructure has non-bindable
/// keys NOT declared in Props, upstream synthesises
/// `$$ComponentProps`; otherwise it keeps the user's Props typedef.
///
/// Returns:
///   - `Some(keys)` when a Props typedef block was found (possibly
///     empty if there are no `@property` lines).
///   - `None` when no Props typedef is present.
///
/// Heuristic-only parser — no full JSDoc AST. Walks the block
/// between the `@typedef` start and the next `*/`, collecting the
/// identifier that follows each `@property {...}` (skipping the
/// type-spec inside balanced `{...}` and the optional `[` for
/// optional markers).
fn scan_jsdoc_props_typedef_keys(script: &str) -> Option<Vec<String>> {
    // Locate the Props typedef block.
    let mut rest = script;
    let mut block_start: Option<usize> = None;
    let mut block_end: usize = 0;
    let mut consumed: usize = 0;
    while let Some(pos) = rest.find("@typedef") {
        let abs = consumed + pos;
        let after = &rest[pos + "@typedef".len()..];
        let after = after.trim_start();
        let after = if let Some(stripped) = after.strip_prefix('{') {
            let mut depth = 1u32;
            let mut end = 0usize;
            for (i, c) in stripped.char_indices() {
                match c {
                    '{' => depth += 1,
                    '}' => {
                        depth -= 1;
                        if depth == 0 {
                            end = i + 1;
                            break;
                        }
                    }
                    _ => {}
                }
            }
            &stripped[end..]
        } else {
            after
        };
        let after = after.trim_start();
        let name: String = after
            .chars()
            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_' || *c == '$')
            .collect();
        if name == "Props" {
            block_start = Some(abs);
            block_end = script[abs..]
                .find("*/")
                .map(|e| abs + e)
                .unwrap_or(script.len());
            break;
        }
        consumed = abs + "@typedef".len();
        rest = &script[consumed..];
    }
    let start = block_start?;
    let block = &script[start..block_end];
    // Walk `@property {<typespec>} [name]` (or `name`) entries.
    let mut keys: Vec<String> = Vec::new();
    let mut cursor = block;
    while let Some(p) = cursor.find("@property") {
        cursor = &cursor[p + "@property".len()..];
        let trimmed = cursor.trim_start();
        let after_type = if let Some(stripped) = trimmed.strip_prefix('{') {
            let mut depth = 1i32;
            let mut end = 0usize;
            for (i, c) in stripped.char_indices() {
                match c {
                    '{' => depth += 1,
                    '}' => {
                        depth -= 1;
                        if depth == 0 {
                            end = i + 1;
                            break;
                        }
                    }
                    _ => {}
                }
            }
            &stripped[end..]
        } else {
            trimmed
        };
        let after_type = after_type.trim_start();
        let rest_name = after_type.strip_prefix('[').unwrap_or(after_type);
        let name: String = rest_name
            .chars()
            .take_while(|c| c.is_ascii_alphanumeric() || *c == '_' || *c == '$')
            .collect();
        if !name.is_empty() {
            keys.push(name);
        }
        cursor = after_type;
    }
    Some(keys)
}

/// Decide whether to synthesise `$$ComponentProps` for a JS overlay
/// vs keep the user's Props typedef. Currently: synthesise only when
/// the user has no Props at all.
///
/// Tried matching upstream's "synth when destructure introduces
/// non-bindable keys not in Props" heuristic — empirically regresses
/// because user Props (when present) is a stricter type than our
/// `any`-laden synthesis can reproduce. CodeMirror's
/// `<CodeMirror completions={...}>` fires TS2353 against `Props`
/// (Props lacks `completions`); under the divergence heuristic we
/// synthesised `$$ComponentProps` WITH `completions` (because it's
/// in the destructure) and silently accepted the call.
///
/// `is_bindable` and `scan_jsdoc_props_typedef_keys` are kept for a
/// future pass that combines user-Props per-key types with
/// destructure-derived shape.
fn should_synthesise_js_props(props_info: &svn_analyze::PropsInfo, script: &str) -> bool {
    if props_info.destructures.is_empty() {
        return false;
    }
    // Synthesise only when no user Props typedef exists.
    scan_jsdoc_props_typedef_keys(script).is_none()
}

/// Build the body of a JSDoc `@typedef <body> $$ComponentProps` from a
/// `$props()` destructure. Returns `Some("{name: any, opt?: string}")`
/// (a complete object-type typespec including the outer `{}`) when
/// there's at least one non-rest entry; `None` when the destructure
/// list is empty (caller falls back to `any`).
///
/// Each entry maps to:
///   - `key: any` for required (no default, not $bindable, not rest)
///   - `key?: <inferred>` for optional, where `<inferred>` is the
///     literal-type derived from the default expression (string for
///     `= ''`, `Function` for `= () => {}`, `Record<string, any>`
///     for `= {}`, etc.); falls back to `any` for unrecognised
///     default expressions.
///   - `[key: string]: any` for `...rest` (loosens the typedef so
///     extra props at consumers don't trigger excess-prop errors)
///
/// Mirrors upstream svelte2tsx's `getTypeForDefault` so consumers'
/// callback / scalar mismatches surface the same TS2322 / TS2353
/// diagnostics. See `infer_default_type` in `crates/analyze/src/props.rs`.
fn synthesise_js_props_typedef_body(props_info: &svn_analyze::PropsInfo) -> Option<String> {
    use std::fmt::Write;
    if props_info.destructures.is_empty() {
        return None;
    }
    let mut body = String::from("{");
    let mut first = true;
    let mut emitted_index_signature = false;
    for entry in &props_info.destructures {
        if entry.is_rest {
            // `...rest` — widen the type with an index signature so any
            // remaining prop the parent passes is accepted. Only one
            // index signature is allowed per type literal.
            if !emitted_index_signature {
                if !first {
                    body.push_str(", ");
                }
                body.push_str("[key: string]: any");
                emitted_index_signature = true;
                first = false;
            }
            continue;
        }
        let key = entry.prop_key.as_str();
        if !first {
            body.push_str(", ");
        }
        first = false;
        let key_text = if is_simple_js_identifier(key) {
            key.to_string()
        } else {
            format!("\"{}\"", key.replace('"', "\\\""))
        };
        let optional = if entry.has_default { "?" } else { "" };
        let value_type = entry
            .default_type_text
            .as_deref()
            .filter(|_| entry.has_default)
            .unwrap_or("any");
        let _ = write!(body, "{key_text}{optional}: {value_type}");
    }
    body.push('}');
    Some(body)
}

fn emit_render_body_return(
    buf: &mut EmitBuffer,
    doc: &svn_parser::Document<'_>,
    generics: Option<&str>,
    prop_type_source: Option<&str>,
    synthesized_events_type: Option<&str>,
    exports_object: Option<&str>,
    props_info: &svn_analyze::PropsInfo,
) {
    // JS overlay: always emit a return so the default-export's
    // `Awaited<ReturnType<typeof $$render>>['props']` extraction
    // resolves to a real Props type. When the script has a
    // `/** @typedef {Object} Props */` block and
    // `/** @type {Props} */ let {...} = $props()`, PropsInfo captures
    // the root name ("Props"), and we reference it here via
    // `/** @type {Props} */({})`. Without a Props name, fall back to
    // `any` (degrades to no excess-prop check, but no regression).
    //
    // `Props` is a function-local JSDoc typedef in the user's script;
    // referencing it inside $$render's return resolves because the
    // return expression is in the same lexical scope. The module-level
    // typedef at the default-export site uses `Awaited<ReturnType<...>>`
    // to pull the type out (JSDoc typedefs don't leak across function
    // boundaries).
    if !emit_is_ts() {
        // Prefer a TS-annotated Props name if PropsInfo captured one,
        // else fall back to scanning the instance script for a JSDoc
        // `@typedef {Object} <Name>` declaration — the standard
        // Svelte-4/JS-Svelte props shape.
        let name_from_ts = prop_type_source.and_then(|ty| {
            let root = ty.trim();
            if !root.is_empty()
                && root
                    .chars()
                    .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '$')
                && !root.chars().next().is_some_and(|c| c.is_ascii_digit())
            {
                Some(root.to_string())
            } else {
                None
            }
        });
        let name_from_jsdoc = doc
            .instance_script
            .as_ref()
            .and_then(|s| scan_jsdoc_typedef_name(s.content));
        // Svelte-4 `export let` synthesis: PropsInfo captures a
        // literal `{k: T, …}` type_text (PropsSource::SynthesisedFromExports)
        // that doesn't match the named-type predicate above. Embed the
        // literal body directly as the JSDoc `@type` so the default
        // export's `Awaited<ReturnType<…>>['props']` resolves to the
        // typed shape (e.g. `{b: any}`) — restoring the required-prop
        // signal that powers TS2741 on consumers.
        let literal_from_exports = prop_type_source
            .filter(|_| {
                matches!(
                    props_info.source,
                    svn_analyze::PropsSource::SynthesisedFromExports
                )
            })
            .map(|ty| ty.trim().to_string());
        // Selection precedence — mirrors the synthesis decision in
        // emit_render (must match or `$$ComponentProps` won't be in
        // scope for this cast):
        //   1. Synthesised `$$ComponentProps` — fires when the
        //      destructure introduces non-bindable keys not in
        //      user Props (or when there's no user Props at all).
        //      See `should_synthesise_js_props`.
        //   2. TS-annotated Props name (`/** @type {Props} */ let {...} = $props()`).
        //   3. User-declared `@typedef {Object} <Name>` block.
        //   4. Svelte-4 `export let` literal shape from PropsInfo.
        //   5. `any` cast — when no Props source exists at all.
        let script = doc
            .instance_script
            .as_ref()
            .map(|s| s.content)
            .unwrap_or("");
        let synthesised_name = if should_synthesise_js_props(props_info, script) {
            synthesise_js_props_typedef_body(props_info).map(|_| "$$ComponentProps".to_string())
        } else {
            None
        };
        let props_expr = match synthesised_name
            .or(name_from_ts)
            .or(name_from_jsdoc)
            .or(literal_from_exports)
        {
            Some(body) => format!("/** @type {{{body}}} */({{}})"),
            None => "/** @type {any} */({})".to_string(),
        };
        let _ = writeln!(buf, "    return {{ props: {props_expr} }};");
        return;
    }
    // TS overlay path. Emit a structured return `{ props, events,
    // slots, exports, bindings }` whose field types drive the default
    // export's `Awaited<ReturnType<typeof $$render>>['props']`
    // extraction at module scope — matches upstream's
    // `__sveltets_2_isomorphic_component($$render())` pattern.
    //
    // Props field source priority:
    //   1. User-declared Props type (`interface $$Props`, `: Props`
    //      annotation on destructure, etc.) — always used when present.
    //   2. For Svelte-4 `export let`, `exports_object` doubles as the
    //      Props shape (every exported local is a prop) — use it
    //      when no user Props type is available.
    //   3. Fall back to `Record<string, any>` when nothing else is
    //      known.
    let exports_field = exports_object.unwrap_or("{}");
    let events_field: &str = if has_strict_events(doc) || synthesized_events_type.is_some() {
        "$$Events"
    } else {
        "{}"
    };
    // With-generics branch preserves the original behaviour for
    // class-wrapper emission: the caller already synthesised the
    // props-ref via the render class, so we emit the typed literal
    // exactly as before to keep the shape stable.
    if generics.is_some() {
        let Some(ty) = prop_type_source else {
            return;
        };
        let _ = writeln!(
            buf,
            "    return {{ props: undefined as any as ({ty}), events: undefined as any as {events_field}, slots: undefined as any as {{}}, bindings: undefined as any as string, exports: undefined as any as ({exports_field}) }};"
        );
        return;
    }
    // No generics. Pick the Props source per priority above.
    let props_ty: String = match prop_type_source {
        Some(ty) => ty.to_string(),
        None => exports_object
            .map(|e| e.to_string())
            .unwrap_or_else(|| "Record<string, any>".to_string()),
    };
    let _ = writeln!(
        buf,
        "    return {{ props: undefined as any as ({props_ty}), events: undefined as any as {events_field}, slots: undefined as any as {{}}, bindings: undefined as any as string, exports: undefined as any as ({exports_field}) }};"
    );
}

/// Emit the hoisted-imports region at module scope, followed by a
/// per-statement LineMapEntry so a diagnostic on a hoisted import line
/// points at the original `<script>` import line. Each hoisted
/// statement was concatenated verbatim into `s.hoisted` — line counts
/// inside a statement match the source 1:1, so we emit one entry per
/// statement.
///
/// `s.hoisted` starts with synthetic `declare const <name>: …;` stubs
/// for body-referenced names — those have NO entry in
/// `hoisted_byte_offsets`, so we skip past them before aligning the
/// walk cursor with the first real offset. Without this skip, every
/// overlay line in the hoist region gets mapped to the wrong source
/// line (every entry's source_offset is applied N-stubs too early).
fn emit_hoisted_imports(
    buf: &mut EmitBuffer,
    split: Option<&script_split::SplitScript>,
    doc: &svn_parser::Document<'_>,
    is_ts: bool,
) {
    let Some(s) = split else { return };
    if s.hoisted.is_empty() {
        return;
    }
    // For JS overlays, drop the synthetic `declare const X: { [key:
    // string]: any } & ((...args: any[]) => any);` stub prelude —
    // `declare const` is TS-only syntax that tsgo refuses to parse in
    // a `.js` file (TS8009/TS8010), and even one such error aborts
    // the whole-program type-check (Types: 340 / Instantiations: 0
    // signal). The stubs exist to keep `typeof X` usable in hoisted
    // Props types, which JS overlays don't carry anyway (Props is
    // expressed via JSDoc @typedef, not a real type alias).
    //
    // TS overlays keep the stubs; JS overlays slice them off. Line
    // map entries cover ONLY the user-import region in both modes —
    // stubs don't map to any source line.
    if let Some(instance) = &doc.instance_script {
        let stub_line_count_ts = count_lines(&s.hoisted[..s.stub_prefix_len.min(s.hoisted.len())]);
        // Overlay cursor starts AFTER the stub block in TS mode (those
        // lines are emitted but not mapped), and at the current line
        // in JS mode (no stubs emitted).
        let mut overlay_cursor =
            current_line(buf.as_str()) + if is_ts { stub_line_count_ts } else { 0 };
        let bytes = s.hoisted.as_bytes();
        let mut byte = s.stub_prefix_len.min(bytes.len());
        for &source_offset in &s.hoisted_byte_offsets {
            // Each hoisted statement runs until either the next `\n`
            // followed by a non-blank line, or the next hoisted
            // offset's projection in the concatenated string. Simplest:
            // count lines until we hit the next statement (we know
            // there's an extra `\n` between statements).
            let stmt_start_byte = byte;
            while byte < bytes.len() && bytes[byte] != b'\n' {
                byte += 1;
            }
            // Multi-line imports: keep walking while indented
            // continuations or close-brace tokens follow.
            while byte < bytes.len() {
                let next = byte + 1;
                if next >= bytes.len() {
                    break;
                }
                let after_nl = bytes[next];
                if after_nl == b'\n' {
                    // Blank line — definitely end of statement.
                    byte += 1;
                    break;
                }
                // Heuristic: if the line starts with an alpha character
                // at column 0, it's a new statement.
                if after_nl.is_ascii_alphabetic() {
                    byte += 1;
                    break;
                }
                byte += 1;
                while byte < bytes.len() && bytes[byte] != b'\n' {
                    byte += 1;
                }
            }
            let stmt_text = &s.hoisted[stmt_start_byte..byte];
            let stmt_line_count = count_lines(stmt_text).max(1);
            let source_line =
                source_line_at(doc.source, instance.content_range.start + source_offset);
            buf.push_line_map(LineMapEntry {
                overlay_start_line: overlay_cursor,
                overlay_end_line: overlay_cursor + stmt_line_count,
                source_start_line: source_line,
            });
            overlay_cursor += stmt_line_count;
            // Skip the trailing newline we wrote.
            if byte < bytes.len() && bytes[byte] == b'\n' {
                byte += 1;
            }
        }
    }
    if is_ts {
        buf.push_str(&s.hoisted);
    } else {
        let user_imports = &s.hoisted[s.stub_prefix_len.min(s.hoisted.len())..];
        buf.push_str(user_imports);
        if !user_imports.ends_with('\n') {
            buf.push_str("\n");
        }
        return;
    }
    if !s.hoisted.ends_with('\n') {
        buf.push_str("\n");
    }
}

/// Emit the `declare class {class_name}<…>`, the 4-arm
/// `declare const __svn_component_default: …` / `declare type
/// __svn_component_default = …` pair, the `type __svn_tpl_type_refs
/// = [...]` alias (when any template-used type imports exist), and
/// the final `export default __svn_component_default;`.
///
/// The arm dispatch is on `(prop_type_source, generics)` × whether
/// the Props source is safe to reference at module scope (either a
/// literal `{ … }` shape, a script-hoisted named type, a type
/// declared in `<script module>`, or a type-imported name).
///
/// Each arm produces two declarations (value + type alias) with the
/// same `__svn_component_default` identifier; users writing `typeof
/// Foo` land on the value and `let x: Foo` lands on the alias.
///
/// Class-wrapper: when Props + generics are both present, a
/// `declare class __svn_Render_<hash><T> { props(): Awaited<…>; }`
/// is emitted first. The 4-arm then substitutes `props_base` with
/// `ReturnType<__svn_Render_<hash><T>['props']>` so body-local
/// `typeof X` references in `interface $$Props { … }` resolve
/// through the render function's scope instead of module scope. See
/// `notes/PLAN.md` Phase 2 for the full rationale.
#[allow(clippy::too_many_arguments)]
fn emit_default_export_declarations(
    buf: &mut EmitBuffer,
    doc: &Document<'_>,
    fragment: &Fragment,
    split: Option<&script_split::SplitScript>,
    render_name: &SmolStr,
    generics: Option<&str>,
    prop_type_source: Option<&str>,
    exports_object: Option<&str>,
    template_type_refs: &[SmolStr],
    is_ts: bool,
) {
    if !is_ts {
        // JS-overlay default-export shape. Captures Props via
        // `Awaited<ReturnType<typeof $$render>>['props']` so consumer
        // overlays see real per-element prop types (e.g. the user's
        // local `@typedef {Object} Props` JSDoc) — not the previous
        // loose `Record<string, any>` which let every excess prop
        // silently pass. Closes ~40 TS2353 under-fire sites on a
        // real-world CMS bench (FieldItem / sidebar components
        // passing `placement="bottom-end"` etc. to children that
        // don't declare that prop).
        //
        // The $$render function was modified earlier to `return {
        // props: /** @type {PropsName} */({}) }` when PropsInfo
        // provided a root name; otherwise it returns an empty object
        // literal and the extracted type falls back to `{}` which
        // degrades gracefully (no excess-prop check but no regression).
        //
        // TS-only machinery below (`interface`, `declare class`, type
        // intersections) is skipped for JS overlays since those parse
        // errors abort tsgo's whole-program check. See
        // design/js_overlay/fixture/src/03_default_export.svelte.svn.js
        // for the vetted shape.
        // `| null` in the const's type would cause downstream
        // `__svn_ensure_component(C)` calls to skip the strict
        // `Component<P>` overload and fall through to the
        // `unknown → props?: any` overload — masking excess-prop
        // checks at every consumer. Use a double-cast so the const's
        // TYPE is `Component<Props>` (matches the strict overload)
        // while its runtime VALUE is `null` (no actual runtime needed
        // in a .d.ts-esque overlay).
        let _ = writeln!(
            buf,
            "/**\n * @typedef {{Awaited<ReturnType<typeof {render_name}>>['props']}} __SvnDefaultProps\n */"
        );
        let _ = writeln!(
            buf,
            "/** @type {{import('svelte').Component<__SvnDefaultProps>}} */"
        );
        let _ = writeln!(
            buf,
            "const __svn_component_default = /** @type {{any}} */ (null);"
        );
        buf.push_str("export default __svn_component_default;\n");
        let _ = template_type_refs;
        let _ = doc;
        let _ = fragment;
        let _ = split;
        let _ = generics;
        let _ = prop_type_source;
        let _ = exports_object;
        return;
    }
    let use_class_wrapper = generics.is_some() && prop_type_source.is_some();
    let exports_clause = exports_object
        .map(|e| format!(" & {e}"))
        .unwrap_or_default();
    let component_exports_arg = exports_object.map(|e| format!(", {e}")).unwrap_or_default();

    // Class-wrapper declaration at module scope. Its `props()` method's
    // return type is resolved THROUGH the render function, which is
    // where body-local `typeof X` refs are in scope. `Awaited<…>`
    // handles the `async` wrapper on $$render — the body is wrapped in
    // an async function so top-level `await` in user code compiles.
    if use_class_wrapper && let Some(g) = generics {
        let class_name = render_class_name(render_name);
        let g_args = generic_arg_names(g);
        // Full upstream class-wrapper shape (addComponentExport.ts:96-138).
        // Each method's return type is `Awaited<ReturnType<typeof $$render<…>>>['<field>']`
        // — all five projections into the render body's return object.
        // With this shape a sibling `$$IsomorphicComponent` can extract
        // every surface (props, events, slots, bindings, exports) at
        // module scope, while body-local `typeof X` refs in $$Props
        // resolve THROUGH the render function's scope where X lives.
        let _ = writeln!(buf, "declare class {class_name}<{g}> {{")
            .and_then(|_| {
                writeln!(
                    buf,
                    "    props(): Awaited<ReturnType<typeof {render_name}<{g_args}>>>['props'];"
                )
            })
            .and_then(|_| {
                writeln!(
                    buf,
                    "    events(): Awaited<ReturnType<typeof {render_name}<{g_args}>>>['events'];"
                )
            })
            .and_then(|_| {
                writeln!(
                    buf,
                    "    slots(): Awaited<ReturnType<typeof {render_name}<{g_args}>>>['slots'];"
                )
            })
            .and_then(|_| {
                writeln!(
                    buf,
                    "    bindings(): Awaited<ReturnType<typeof {render_name}<{g_args}>>>['bindings'];"
                )
            })
            .and_then(|_| {
                writeln!(
                    buf,
                    "    exports(): Awaited<ReturnType<typeof {render_name}<{g_args}>>>['exports'];"
                )
            })
            .and_then(|_| writeln!(buf, "}}"));
    }

    // The Props source has to be "safe" to reference at module scope:
    // either a literal shape (`{ item: T }`) or a named type whose
    // declaration was hoisted by script_split. Bare named types that
    // stay body-scoped (either because they reference the script's
    // generic without re-binding it, or because they reference a
    // body-level const via `typeof`) can't be named from the
    // default-export declaration — emit falls back to `any` for those.
    let prop_ty_is_literal = prop_type_source.is_some_and(|t| t.trim().starts_with('{'));
    let prop_ty_root_name = prop_type_source.and_then(svn_analyze::root_type_name_of);
    // Consider a named Props type module-scope-visible if either (a)
    // script_split hoisted it out of the instance script, (b) it's
    // declared in the `<script module>` section, or (c) it's imported
    // as a type at the module top level (`import type { FooProps }
    // from './types'`).
    let module_script_text = doc.module_script.as_ref().map(|s| s.content).unwrap_or("");
    let prop_ty_module_visible = prop_ty_root_name.as_deref().is_some_and(|n| {
        // `$$ComponentProps` is the reserved name for our TS-source
        // hard-mode synthesis (see `PropsSource::SynthesisedFromDestructure`
        // in `emit_document_with_render_name`). When the name appears as
        // the Props root, the corresponding `type $$ComponentProps = …;`
        // alias was already emitted at module scope by the same pass —
        // so treat it as module-visible without a hoisted-types lookup.
        n == "$$ComponentProps"
            || split.is_some_and(|s| s.hoisted_type_names.contains(n))
            || module_script_declares_type(module_script_text, n)
            || split.is_some_and(|s| imports_name(&s.hoisted, n))
    });
    let ty_safe_in_generic_scope = prop_ty_is_literal || prop_ty_module_visible;
    let ty_safe_in_module_scope = prop_ty_is_literal || prop_ty_module_visible;

    // SVELTE-4-COMPAT detection. Consumers of Svelte-4 components pass
    // `on:event` directives (rewritten to `on<event>` prop keys by us)
    // and `<Foo slot="x">` slot-name attrs, neither of which are
    // declared in the actual Props type. Widening with an
    // `on${string}` index signature + optional `slot` key keeps those
    // consumer writes valid without opening the door on Svelte-5
    // codebases where widening would mask real typos.
    let has_slot = fragment_contains_slot(fragment);
    let svelte4_style = is_svelte4_component(doc, split, has_slot);
    // Narrower gate than `svelte4_style`: only true when the component
    // uses `export let` (Svelte 4's prop-declaration form).
    // `svelte4_style` also catches `export function` / `export const`
    // which are method exports on runes components — those don't
    // describe Props, so gating arm 3's props-base swap on
    // `svelte4_style` would break runes fixtures.
    let has_export_let = doc
        .instance_script
        .as_ref()
        .is_some_and(|s| contains_export_let(s.content))
        || doc
            .module_script
            .as_ref()
            .is_some_and(|s| contains_export_let(s.content));
    // v0.3 Item 3: when the child declares `$$Events`, carry it as
    // `& { readonly __svn_events: $$Events }` on the default export.
    // Consumer-side `__svn_ensure_component` has a typed overload
    // matching this marker and returning `__SvnInstanceTyped<P, E>` —
    // handlers then narrow `e.detail` against the declared payload.
    let typed_events_intersection = if has_strict_events(doc) {
        " & { readonly __svn_events: $$Events }"
    } else {
        ""
    };
    // Conditional index-signature widen mirrors upstream's
    // `__sveltets_2_with_any(…)` factory: adds `SvelteAllProps =
    // {[index: string]: any}` ONLY when the child component uses
    // `$$props` / `$$restProps`. Scan the WHOLE document source — a
    // Svelte 4 component can spread `{...$$props}` in the TEMPLATE
    // (scripts define typed props, template spreads arbitrary extras).
    // Substring check over `doc.source` is accurate because the `$$`
    // prefix is Svelte-reserved.
    let uses_any_props = doc.source.contains("$$props") || doc.source.contains("$$restProps");
    let has_slots = svelte4_style && has_slot;
    // Match upstream's factory-pattern: intersections ONLY when the
    // component shape actually needs them. ANY non-empty intersection
    // (even a benign `{children?: any}`) contaminates tsgo's
    // assignability check — missing-required-prop fires TS2322
    // top-level with TS2741 as sub-message, instead of TS2741 directly.
    let widen_for = |base: &str| -> String {
        if !svelte4_style {
            return String::new();
        }
        match (has_slots, uses_any_props) {
            (false, false) => String::new(),
            (true, false) => format!(" & __SvnSvelte4PropsWiden<{base}>"),
            (false, true) => " & __SvnAllProps".to_string(),
            (true, true) => format!(" & __SvnSvelte4PropsWiden<{base}> & __SvnAllProps"),
        }
    };
    // SVELTE-4-COMPAT: Svelte-4 components that render a `<slot>` are
    // content-containers — consumers typically write `<Foo>body</Foo>`
    // and omit prop values entirely. Mirrors upstream's
    // `__sveltets_2_isomorphic_component_slots` (Partial<P>) vs the
    // plain `__sveltets_2_isomorphic_component` (P) split.
    let svelte4_with_slot = svelte4_style && has_slot;
    let wrap_props = |inner: String| -> String {
        if svelte4_with_slot {
            format!("Partial<{inner}>")
        } else {
            inner
        }
    };
    // When class-wrapper is active, the Props type reaches module
    // scope via `ReturnType<__svn_Render_<hash><g_args>['props']>` —
    // body-scoped type refs in `$$Props` resolve through the render
    // function's scope without module-scope sanitisation.
    let render_class_name_for_props = if use_class_wrapper {
        generics.map(|g| {
            let class_name = render_class_name(render_name);
            let g_args = generic_arg_names(g);
            format!("ReturnType<{class_name}<{g_args}>['props']>")
        })
    } else {
        None
    };
    // Upstream's `$$IsomorphicComponent` (addComponentExport.ts:170-179):
    // a single interface that types both `new C({props})` (Svelte-4 class
    // form) and `C(anchor, props)` (Svelte-5 function form) via a ctor
    // signature + call signature on the same type. Every surface — Props,
    // Events, Slots, Bindings, Exports — flows through the class-wrapper's
    // `ReturnType<…>` projections, so body-local refs in `$$Props`,
    // `$$Events`, and `export function` / `export const` signatures
    // resolve inside the render function's scope (not module scope)
    // without the legacy sanitisation hack.
    //
    // Gate: class-wrapper active AND (Svelte-5 runes mode OR Svelte-4
    // `export let`). `!svelte4_style` is too loose — a runes-mode file
    // that uses `createEventDispatcher` for back-compat trips
    // `is_svelte4_component`'s signal 3 even though it's really a
    // Svelte-5 file. Checking `is_runes_mode` directly excludes that
    // false positive and keeps the gate aligned with upstream's
    // runes/export-let split.
    let use_iso_interface =
        use_class_wrapper && (has_export_let || is_runes_mode(doc)) && generics.is_some();
    if use_iso_interface && let Some(g) = generics {
        let class_name = render_class_name(render_name);
        let g_args = generic_arg_names(g);
        let props_ret = format!("ReturnType<{class_name}<{g_args}>['props']>");
        let events_ret = format!("ReturnType<{class_name}<{g_args}>['events']>");
        let slots_ret = format!("ReturnType<{class_name}<{g_args}>['slots']>");
        let bindings_ret = format!("ReturnType<{class_name}<{g_args}>['bindings']>");
        let exports_ret = format!("ReturnType<{class_name}<{g_args}>['exports']>");
        // `z_$$bindings` can't reference the interface's own free `<T>`
        // — TS interface members aren't under a generic binder. Fill
        // the class's type params with `any` (matches upstream's
        // `toReferencesAnyString()` in Generics.ts).
        let g_param_count = g_args
            .split(',')
            .filter(|p| !p.trim().is_empty())
            .count()
            .max(1);
        let g_args_any: String = std::iter::repeat_n("any", g_param_count)
            .collect::<Vec<_>>()
            .join(", ");
        let bindings_any_ret = format!("ReturnType<{class_name}<{g_args_any}>['bindings']>");
        // Widen base must be module-scope-safe: if the Props type
        // source references body-locals (e.g. `$$Props` declared
        // inside $$render), using it as the `__SvnSvelte4PropsWiden<…>`
        // argument would fire TS2304 at module scope. Route through
        // the class-wrapper's ReturnType projection — same shape,
        // body-local refs resolved via the render function's scope.
        let widen_base: &str = prop_type_source
            .filter(|_| ty_safe_in_generic_scope)
            .unwrap_or(&props_ret);
        let widen = widen_for(widen_base);
        let _ = writeln!(buf, "interface $$IsomorphicComponent {{");
        let _ = writeln!(
            buf,
            "    new <{g}>(options: import('svelte').ComponentConstructorOptions<{props_ret}{widen} & {{ children?: any }}>): import('svelte').SvelteComponent<{props_ret}, {events_ret}, {slots_ret}> & {{ $$bindings?: {bindings_ret} }} & {exports_ret};"
        );
        let _ = writeln!(
            buf,
            "    <{g}>(internal: unknown, props: {props_ret}{widen} & {{ children?: any }}): {exports_ret};"
        );
        let _ = writeln!(buf, "    z_$$bindings?: {bindings_any_ret};");
        let _ = writeln!(buf, "}}");
        let _ = writeln!(
            buf,
            "const __svn_component_default: $$IsomorphicComponent = null as any;"
        );
        let _ = writeln!(
            buf,
            "type __svn_component_default<{g}> = InstanceType<typeof __svn_component_default<{g_args}>>;"
        );
        // Type-position reference for template-used type-only imports
        // needs to happen regardless of the dispatch path — emit here
        // and return so the match below is skipped entirely.
        if !template_type_refs.is_empty() {
            buf.push_str("type __svn_tpl_type_refs = [");
            for (i, name) in template_type_refs.iter().enumerate() {
                if i > 0 {
                    buf.push_str(", ");
                }
                buf.push_str(name.as_str());
            }
            buf.push_str("];\n");
            buf.push_str("void (0 as any as __svn_tpl_type_refs);\n");
        }
        buf.push_str("export default __svn_component_default;\n");
        return;
    }
    match (prop_type_source, generics) {
        (Some(ty), Some(g)) if ty_safe_in_generic_scope => {
            let widen = widen_for(ty);
            let props_base = render_class_name_for_props.as_deref().unwrap_or(ty);
            let props = wrap_props(format!("{props_base}{widen}"));
            let _ = writeln!(
                buf,
                "declare const __svn_component_default: <{g}>(__anchor: any, props: Partial<{props_base}{widen}>) => {};",
                exports_object.unwrap_or("any"),
            );
            let _ = writeln!(
                buf,
                "declare type __svn_component_default<{g}> = import('svelte').SvelteComponent<{props}>{exports_clause};"
            );
        }
        (Some(ty), None) if ty_safe_in_module_scope => {
            let widen = widen_for(ty);
            let props = wrap_props(format!("{ty}{widen}"));
            let _ = writeln!(
                buf,
                "declare const __svn_component_default: import('svelte').Component<{props}{component_exports_arg}>{typed_events_intersection};"
            );
            let _ = writeln!(
                buf,
                "declare type __svn_component_default = import('svelte').SvelteComponent<{props}>{exports_clause};"
            );
        }
        (_, Some(g)) => {
            // Props type isn't safe at module scope (or not present),
            // but the component declares generics. The exports_object
            // still references generics verbatim, so wrap the whole
            // declaration in the generic scope so those bind.
            //
            // SVELTE-4 only: use the (sanitized) exports_object as the
            // props base rather than `Record<string, any>`. In Svelte 4
            // `export let foo` is both a PROP and an exported member
            // (bind:-accessible), so exports_object doubles as the
            // Props type. Typing the props slot this way restores
            // contextual-type flow. Svelte 5 runes keep the plain-
            // record fallback: exports there are method-style and
            // don't describe the Props shape. Priority:
            //   1. `ReturnType<Render<g_args>['props']>` when class-
            //      wrapper is active.
            //   2. (sanitized) `exports_object` when Svelte-4
            //      `export let` is the Props shape.
            //   3. `Record<string, any>` as a final lax fallback.
            let use_exports_as_props = has_export_let && exports_object.is_some();
            let props_base: &str = if let Some(cw) = render_class_name_for_props.as_deref() {
                cw
            } else if use_exports_as_props {
                exports_object.unwrap_or("Record<string, any>")
            } else {
                "Record<string, any>"
            };
            let widen = widen_for(props_base);
            let props = wrap_props(format!("{props_base}{widen}"));
            let _ = writeln!(
                buf,
                "declare const __svn_component_default: <{g}>(__anchor: any, props: Partial<{props_base}{widen}>) => {};",
                exports_object.unwrap_or("any"),
            );
            let _ = writeln!(
                buf,
                "declare type __svn_component_default<{g}> = import('svelte').SvelteComponent<{props}>{exports_clause};"
            );
        }
        _ => {
            // TS-overlay no-generics fallback. Source the Props shape
            // from the render function's return via
            // `Awaited<ReturnType<typeof $$render>>['props']` —
            // matches upstream's `__sveltets_2_isomorphic_component(
            // $$render())` pattern and keeps parity with our JS
            // overlay path. The render body's return was already
            // wired to emit a typed `props` field (sourcing from
            // user Props type → exports_object → Record<string, any>
            // in that priority order).
            //
            // Without this, the Props slot would fall back to
            // `Record<string, any>`, which loses contextual typing
            // on consumer arrow callbacks (e.g. `onclick={(e) => …}`
            // fires TS7006 because the loose record never pinned
            // `e`'s type).
            let props_ref = format!(
                "Awaited<ReturnType<typeof {render_name}>>['props']",
                render_name = render_name
            );
            let widen = widen_for(&props_ref);
            let props = wrap_props(format!("{props_ref}{widen}"));
            let _ = writeln!(
                buf,
                "declare const __svn_component_default: import('svelte').Component<{props}{component_exports_arg}>{typed_events_intersection};"
            );
            let _ = writeln!(
                buf,
                "declare type __svn_component_default = import('svelte').SvelteComponent<{props}>{exports_clause};"
            );
        }
    }

    // Type-position reference for every type-only import that was
    // consumed only in a template expression (e.g. as cast target).
    // TS considers the type used, so the import isn't flagged TS6133.
    if !template_type_refs.is_empty() {
        buf.push_str("type __svn_tpl_type_refs = [");
        for (i, name) in template_type_refs.iter().enumerate() {
            if i > 0 {
                buf.push_str(", ");
            }
            buf.push_str(name.as_str());
        }
        buf.push_str("];\n");
        buf.push_str("void (0 as any as __svn_tpl_type_refs);\n");
    }
    buf.push_str("export default __svn_component_default;\n");
}

/// Byte-scan a script section for `type NAME`, `interface NAME`,
/// `export type NAME`, or `export interface NAME` declarations.
/// Returns true if `name` appears as a declared type. Used by emit to
/// check whether a Props type referenced from a consumer-scope
/// declaration will resolve at module scope.
///
/// Not a full parser — matches the common case of a top-of-line type
/// keyword followed by whitespace and the identifier. String-literal
/// and comment false-positives (writing `// interface Foo` in a
/// comment) resolve toward "visible"; emit then declares `Component<Foo>`
/// which fires TS2304 only if the user genuinely forgot to declare
/// Foo, a clear error they can fix.
fn module_script_declares_type(text: &str, name: &str) -> bool {
    if name.is_empty() {
        return false;
    }
    for prefix in ["type ", "interface "] {
        let needle = format!("{prefix}{name}");
        for (idx, _) in text.match_indices(&needle) {
            let before_ok = idx == 0 || {
                let b = text.as_bytes()[idx - 1];
                !b.is_ascii_alphanumeric() && b != b'_' && b != b'$'
            };
            let after_idx = idx + needle.len();
            let after_ok = after_idx == text.len() || {
                let b = text.as_bytes()[after_idx];
                !b.is_ascii_alphanumeric() && b != b'_' && b != b'$'
            };
            if before_ok && after_ok {
                return true;
            }
        }
    }
    false
}

/// Byte-scan hoisted import declarations for `name` appearing in an
/// `import type { ... }` or `import { ... }` clause. Used to check
/// whether a Props type referenced by the consumer emit comes from a
/// type-only module import.
fn imports_name(hoisted: &str, name: &str) -> bool {
    if name.is_empty() {
        return false;
    }
    // Fast path: check any `import` statement that mentions the name
    // as a braced specifier. Matches `{ name }`, `{ name, ... }`,
    // `{ ..., name }`, `{ name as Alias }`, `{ type name }`, etc.
    for (idx, _) in hoisted.match_indices(name) {
        let before = idx.checked_sub(1).map(|i| hoisted.as_bytes()[i]);
        let after = hoisted.as_bytes().get(idx + name.len()).copied();
        let bounded = before.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_' && b != b'$')
            && after.is_none_or(|b| !b.is_ascii_alphanumeric() && b != b'_' && b != b'$');
        if !bounded {
            continue;
        }
        // Scan backward to the nearest `import`, stopping at a prior
        // `;` or `\n\n` (statement boundary). If we hit `import` with
        // an open `{` between it and the name, it's an import
        // specifier.
        let before_text = &hoisted[..idx];
        if let Some(import_pos) = before_text.rfind("import") {
            let between = &before_text[import_pos + "import".len()..];
            if between.contains('{') && !between.contains('}') {
                return true;
            }
        }
    }
    false
}

/// 1-based line number of the next character that would be appended to `s`.
#[inline]
fn current_line(s: &str) -> u32 {
    1 + s.bytes().filter(|&b| b == b'\n').count() as u32
}

/// Byte offsets of the start of each line in `s`. Index 0 is the start
/// of line 1; index N is the start of line N+1 (i.e. the position just
/// past the Nth `\n`). A final sentinel equal to `s.len()` is appended
/// so `starts[line_count]` is always valid and equals the end of the
/// last line's content — lets the consumer clamp a past-EOF (line,
/// col) to the end of the buffer without bounds-checking.
pub fn compute_line_starts(s: &str) -> Vec<u32> {
    let mut starts: Vec<u32> = Vec::with_capacity(s.bytes().filter(|&b| b == b'\n').count() + 2);
    starts.push(0);
    for (idx, b) in s.bytes().enumerate() {
        if b == b'\n' {
            starts.push((idx + 1) as u32);
        }
    }
    starts.push(s.len() as u32);
    starts
}

/// 1-based line number at the given byte offset in `source`.
#[inline]
fn source_line_at(source: &str, offset: u32) -> u32 {
    1 + source[..offset as usize]
        .bytes()
        .filter(|&b| b == b'\n')
        .count() as u32
}

/// Count the number of complete lines in `text` (the count of `\n` plus
/// 1 if the text doesn't end with a newline and is non-empty). Used to
/// derive an end-line for line-map entries.
#[inline]
fn count_lines(text: &str) -> u32 {
    let nl = text.bytes().filter(|&b| b == b'\n').count() as u32;
    if text.is_empty() {
        0
    } else if text.ends_with('\n') {
        nl
    } else {
        nl + 1
    }
}

/// Derive a per-file render function name. Hash of the source path's
/// canonical form prevents collisions when multiple components in the
/// same overlay project would otherwise both produce `function $$render()`
/// (TS2393 "Duplicate function implementation").
///
/// The hash is the first 8 hex chars of blake3 — collision-free for any
/// realistic project size.
fn render_function_name(source_path: &Path) -> SmolStr {
    let bytes = source_path.as_os_str().to_string_lossy();
    let hash = blake3::hash(bytes.as_bytes());
    let hex = hash.to_hex();
    let short = &hex.as_str()[..8];
    SmolStr::from(format!("$$render_{short}"))
}

/// Companion-class name for [`render_function_name`]. Used by the
/// class-wrapper emit path (Phase 2 / R1 of `notes/PLAN.md`) to
/// extract body-scoped Props types at module scope via
/// `ReturnType<__svn_Render_<hash><T>['props']>`.
///
/// Matches upstream svelte2tsx's `class __sveltets_Render<T>` shape
/// but with our per-file hash prefix — same reason as `$$render_<hash>`:
/// two components in the same overlay project would collide on a bare
/// `class __svn_Render { … }`.
fn render_class_name(render_fn_name: &str) -> SmolStr {
    // `render_fn_name` is `$$render_<hash>`. Transform to
    // `__svn_Render_<hash>`.
    let short = render_fn_name
        .strip_prefix("$$render_")
        .unwrap_or(render_fn_name);
    SmolStr::from(format!("__svn_Render_{short}"))
}

/// Extract just the type-parameter NAMES from a Svelte-5 generics
/// attribute value.
///
/// Input is what the user wrote in `<script lang="ts" generics="…">`.
/// We splice that string verbatim into the declaration site of
/// `async function $$render_<hash><…>()` and any class-wrapper
/// declaration — both expect the full parameter syntax (with `extends`
/// constraints and `= default` defaults).
///
/// At instantiation sites we need just the names: `typeof foo<T, U>`
/// not `typeof foo<T extends X, U = Y>`. This helper strips
/// constraints and defaults, preserving comma-separated order.
///
/// Handles:
/// - `T` → `T`
/// - `T extends Item` → `T`
/// - `T extends Item, U` → `T, U`
/// - `T extends Array<U>, U` → `T, U` (bracket depth tracked so the
///   inner `U` doesn't get counted as a separator)
/// - `T = string` → `T`
fn generic_arg_names(generics: &str) -> String {
    let mut out = String::new();
    let mut depth_angle: i32 = 0;
    let mut depth_paren: i32 = 0;
    let mut depth_bracket: i32 = 0;
    let mut current_name = String::new();
    let mut in_name = true;
    let bytes = generics.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        let b = bytes[i];
        match b {
            b'<' => depth_angle += 1,
            b'>' => depth_angle -= 1,
            b'(' => depth_paren += 1,
            b')' => depth_paren -= 1,
            b'[' => depth_bracket += 1,
            b']' => depth_bracket -= 1,
            _ => {}
        }
        let at_depth_zero = depth_angle == 0 && depth_paren == 0 && depth_bracket == 0;
        if at_depth_zero && b == b',' {
            let trimmed = current_name.trim();
            if !trimmed.is_empty() {
                if !out.is_empty() {
                    out.push_str(", ");
                }
                out.push_str(trimmed);
            }
            current_name.clear();
            in_name = true;
            i += 1;
            continue;
        }
        // At depth zero, `extends` / `=` terminate the param name.
        if in_name && at_depth_zero {
            if b.is_ascii_whitespace() {
                if !current_name.is_empty() {
                    // Check if the next non-whitespace token is `extends`.
                    let mut j = i;
                    while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                        j += 1;
                    }
                    if generics[j..].starts_with("extends") {
                        in_name = false;
                    }
                }
                current_name.push(b as char);
                i += 1;
                continue;
            }
            if b == b'=' {
                in_name = false;
                i += 1;
                continue;
            }
            current_name.push(b as char);
        }
        i += 1;
    }
    let trimmed = current_name.trim();
    if !trimmed.is_empty() {
        if !out.is_empty() {
            out.push_str(", ");
        }
        out.push_str(trimmed);
    }
    out
}

/// Extract the `generics=` attribute value from the instance `<script>`
/// if present.
///
/// Svelte 5's syntax for declaring generic type params on a component:
///
/// ```svelte
/// <script lang="ts" generics="T extends Item, K extends keyof T">
/// ```
///
/// The value is spliced verbatim into our wrapping function as
/// `function $$render<T extends Item, K extends keyof T>() { ... }` so
/// any references to `T` / `K` inside the script body resolve correctly.
///
/// Parsing lives in the structural parser (`ScriptSection::generics`);
/// this helper just re-types the already-extracted `Option<String>` as
/// a `SmolStr` and guards against callers that pass in a document
/// without an instance script.
fn extract_generics_attr(doc: &Document<'_>) -> Option<SmolStr> {
    let script = doc.instance_script.as_ref()?;
    script.generics.as_deref().map(SmolStr::from)
}

/// Walk the fragment tree and emit per-construct scaffolding.
///
/// Currently emits a `for`-of loop for each `{#each}` block and recurses
/// into other block bodies / element children. Component-prop excess
/// checks are emitted inline at each `<Component>` position so they
/// sit inside the correct enclosing block scope.
fn emit_template_body(
    buf: &mut EmitBuffer,
    source: &str,
    fragment: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    // Hoist `{#snippet name(...)}` names declared at this fragment so
    // sibling component-prop checks (`<X slot={name}>`) resolve them.
    // When any hoist happens, the whole walk is wrapped in a fresh `{}`
    // lexical scope so the declarations don't leak to other fragments
    // at the same depth — e.g. two `<Wrapper>{#snippet action()}...`
    // siblings would otherwise redeclare `action` in the same scope
    // and fire TS2451.
    let snippets: Vec<&SnippetBlock> = fragment
        .nodes
        .iter()
        .filter_map(|n| match n {
            Node::SnippetBlock(b) => Some(b),
            _ => None,
        })
        .collect();
    if snippets.is_empty() {
        for node in &fragment.nodes {
            emit_template_node(buf, source, node, depth, insts, action_counter);
        }
        return;
    }
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let _ = writeln!(buf, "{indent}{{");
    let is_ts = emit_is_ts();
    for s in &snippets {
        if is_ts {
            let _ = writeln!(buf, "{inner}const {}: any = undefined;", s.name);
        } else {
            let _ = writeln!(buf, "{inner}const {} = undefined;", s.name);
        }
        let _ = writeln!(buf, "{inner}void {};", s.name);
    }
    for node in &fragment.nodes {
        emit_template_node(buf, source, node, depth + 1, insts, action_counter);
    }
    let _ = writeln!(buf, "{indent}}}");
}

/// SVELTE-4-COMPAT: when a template element carries `let:name` or
/// `let:name={alias}` directives, those names bind for the duration
/// of the element's subtree. Upstream svelte2tsx destructures them
/// from the child component's `$$slot_def` — a precise, typed
/// binding. We emit a looser `let name: any;` block so the names
/// resolve inside the subtree. Type precision is lost (the narrower
/// flow-sensitive typing upstream does is the next iteration's
/// job), but TS2304 goes away and any expression referencing the
/// let-name type-checks as `any`.
///
/// If there are no `let:` directives, this is a straight passthrough
/// to `emit_template_body`.
fn emit_children_with_let_bindings(
    buf: &mut EmitBuffer,
    source: &str,
    attributes: &[svn_parser::Attribute],
    children: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let let_names = collect_let_directive_names(source, attributes);
    if let_names.is_empty() {
        emit_template_body(buf, source, children, depth, insts, action_counter);
        return;
    }
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let _ = writeln!(buf, "{indent}{{");
    for name in &let_names {
        let _ = writeln!(buf, "{inner}let {name}: any;");
        let _ = writeln!(buf, "{inner}void {name};");
    }
    for node in &children.nodes {
        emit_template_node(buf, source, node, depth + 1, insts, action_counter);
    }
    let _ = writeln!(buf, "{indent}}}");
}

/// Extract every binding name introduced by `let:X` directives on
/// `attributes`. Handles both shorthand (`let:item` → "item") and
/// aliased form (`let:item={i}` → "i"). Non-identifier destructure
/// patterns (`let:item={{a, b}}`) aren't narrowed — we take the
/// original directive name as the binding instead, which is a
/// harmless no-op but avoids parse-ambiguity.
fn collect_let_directive_names(source: &str, attributes: &[svn_parser::Attribute]) -> Vec<SmolStr> {
    use svn_parser::{Attribute, Directive, DirectiveKind, DirectiveValue};
    let mut out: Vec<SmolStr> = Vec::new();
    for attr in attributes {
        if let Attribute::Directive(Directive {
            kind: DirectiveKind::Let,
            name,
            value,
            ..
        }) = attr
        {
            let bound = match value {
                Some(DirectiveValue::Expression {
                    expression_range, ..
                }) => {
                    let start = expression_range.start as usize;
                    let end = expression_range.end as usize;
                    let slice = source.get(start..end).unwrap_or("").trim();
                    if is_simple_identifier(slice) {
                        SmolStr::from(slice)
                    } else {
                        name.clone()
                    }
                }
                _ => name.clone(),
            };
            if !out.iter().any(|n| n == &bound) {
                out.push(bound);
            }
        }
    }
    out
}

#[inline]
fn is_simple_identifier(s: &str) -> bool {
    let mut chars = s.chars();
    match chars.next() {
        Some(c) if c.is_ascii_alphabetic() || c == '_' || c == '$' => {}
        _ => return false,
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '$')
}

fn emit_template_node(
    buf: &mut EmitBuffer,
    source: &str,
    node: &Node,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    match node {
        Node::EachBlock(b) => emit_each_block(buf, source, b, depth, insts, action_counter),
        Node::IfBlock(b) => {
            // Emit as a real `if/else if/else` chain so TS's control-flow
            // analysis narrows union / nullable / type-guard references
            // inside each arm. Without this, `{#if shape.kind === 'circle'}`
            // leaves `shape.radius` reading as "Property 'radius' does not
            // exist on type 'Shape'" inside the nested component-prop
            // check, and `{#if maybe}{...maybe...}{/if}` reads as "`maybe`
            // is possibly undefined". Conditions are wrapped in an extra
            // pair of parens to stay robust against operator-precedence
            // oddities in the raw source text.
            //
            // Immediately inside each branch we emit a `void [<ident>, …]`
            // statement listing every root identifier from the condition.
            // tsgo fires TS2774 ("this condition will always return true
            // since this function is always defined") on `&&` operands of
            // non-nullable function type — but the check is suppressed if
            // the same identifier symbol appears in the block body.
            // Svelte templates that poll a context object for component
            // references (`{#if editable && ctx.GhostButton}<ctx.GhostButton/>`)
            // tend to USE those references inside the block; the synthesized
            // list mirrors that usage when the user's body doesn't otherwise
            // reference every condition operand by value. Wrapping as a
            // plain array literal avoids re-introducing the `&&` chain that
            // triggered the check in the first place.
            let indent = "    ".repeat(depth);
            let main_cond = source
                .get(b.condition_range.start as usize..b.condition_range.end as usize)
                .unwrap_or("true")
                .trim();
            let _ = writeln!(buf, "{indent}if (({main_cond})) {{");
            emit_condition_ref_marker(buf, source, b.condition_range, depth + 1);
            emit_template_body(buf, source, &b.consequent, depth + 1, insts, action_counter);
            for arm in &b.elseif_arms {
                let arm_cond = source
                    .get(arm.condition_range.start as usize..arm.condition_range.end as usize)
                    .unwrap_or("true")
                    .trim();
                let _ = writeln!(buf, "{indent}}} else if (({arm_cond})) {{");
                emit_condition_ref_marker(buf, source, arm.condition_range, depth + 1);
                emit_template_body(buf, source, &arm.body, depth + 1, insts, action_counter);
            }
            if let Some(alt) = &b.alternate {
                let _ = writeln!(buf, "{indent}}} else {{");
                emit_template_body(buf, source, alt, depth + 1, insts, action_counter);
            }
            let _ = writeln!(buf, "{indent}}}");
        }
        Node::AwaitBlock(b) => {
            if let Some(p) = &b.pending {
                emit_template_body(buf, source, p, depth, insts, action_counter);
            }
            if let Some(t) = &b.then_branch {
                // `{:then v}` — upstream svelte2tsx emits
                //   `const $$_value = await (PROMISE); { const v = $$_value; ... }`
                // so `v` is typed as the resolved promise value (e.g.
                // `Promise<T[] | undefined>` → `v: T[] | undefined`).
                // Without the `await` binding, naive `const v: any = …`
                // loses downstream narrowing — descendants like
                // `{#each v as d}` read `d` as `any`, letting bugs
                // like `vizColorsCssVarMap[d.color]` pass without a
                // TS7053 when upstream tsgo is silent.
                emit_await_then_branch(
                    buf,
                    source,
                    b.expression_range,
                    t.context_range.as_ref(),
                    &t.body,
                    depth,
                    insts,
                    action_counter,
                );
            }
            if let Some(c) = &b.catch_branch {
                // `{:catch e}` — upstream types `e` as `any` (errors
                // don't carry shape info in JS). Keep the existing
                // `const e: any = undefined;` pattern.
                emit_branch_with_binding(
                    buf,
                    source,
                    c.context_range.as_ref(),
                    &c.body,
                    depth,
                    insts,
                    action_counter,
                );
            }
        }
        Node::KeyBlock(b) => emit_template_body(buf, source, &b.body, depth, insts, action_counter),
        Node::SnippetBlock(b) => emit_snippet_block(buf, source, b, depth, insts, action_counter),
        Node::Element(e) => {
            // `<slot>` is the Svelte-4 named-slot mechanism — its attrs are
            // slot props passed to the consumer via `let:propName`, NOT
            // HTML attributes. Upstream svelte2tsx emits these via
            // `__sveltets_createSlot("name", {...})` against the
            // synthesized component slot type; we don't model that yet,
            // so skip the createElement emit entirely (which would
            // otherwise fire TS2353 for every slot prop against the real
            // HTMLSlotElement attribute shape).
            let dom_emit = dom_element_emit_enabled() && e.name.as_str() != "slot";
            let inner_depth = if dom_emit { depth + 1 } else { depth };
            // Action declarations emitted BEFORE createElement so the
            // 3-arg overload can reference them in its second arg. See
            // emit_dom_action_decls / emit_dom_element_open.
            let action_indices = if dom_emit {
                emit_dom_action_decls(
                    buf,
                    source,
                    e.name.as_str(),
                    &e.attributes,
                    inner_depth,
                    action_counter,
                )
            } else {
                let first = *action_counter;
                first..first
            };
            if dom_emit {
                emit_dom_element_open(
                    buf,
                    source,
                    e.name.as_str(),
                    true,
                    &e.attributes,
                    depth,
                    &action_indices,
                );
                emit_dom_directive_checks(buf, source, &e.attributes, inner_depth);
            }
            emit_element_bind_checks_inline(
                buf,
                source,
                e.name.as_str(),
                &e.attributes,
                inner_depth,
            );
            if dom_emit {
                emit_dom_action_void_refs(buf, &action_indices, inner_depth);
            } else {
                // Emit action decls + void refs in a non-dom-emit path
                // (retains pre-Phase-2 behavior when the feature was
                // gated off).
                emit_use_directives_inline_legacy(
                    buf,
                    source,
                    e.name.as_str(),
                    &e.attributes,
                    inner_depth,
                    action_counter,
                );
            }
            emit_children_with_let_bindings(
                buf,
                source,
                &e.attributes,
                &e.children,
                inner_depth,
                insts,
                action_counter,
            );
            if dom_emit {
                emit_dom_element_close(buf, depth);
            }
        }
        Node::Component(c) => emit_component_node(buf, source, c, depth, insts, action_counter),
        Node::SvelteElement(s) => {
            // `<svelte:element this={tagExpr}>` is dynamic — fall back
            // to `HTMLElement` for bind:this and skip bind:value
            // dispatch (empty tag_name → resolve_bind_value_type
            // returns None).
            let dom_emit = dom_element_emit_enabled();
            let inner_depth = if dom_emit { depth + 1 } else { depth };
            let action_indices = if dom_emit {
                emit_dom_action_decls(buf, source, "", &s.attributes, inner_depth, action_counter)
            } else {
                let first = *action_counter;
                first..first
            };
            if dom_emit {
                emit_svelte_element_open(buf, source, s, depth, &action_indices);
                emit_dom_directive_checks(buf, source, &s.attributes, inner_depth);
            }
            emit_element_bind_checks_inline(buf, source, "", &s.attributes, inner_depth);
            if dom_emit {
                emit_dom_action_void_refs(buf, &action_indices, inner_depth);
            } else {
                emit_use_directives_inline_legacy(
                    buf,
                    source,
                    "",
                    &s.attributes,
                    inner_depth,
                    action_counter,
                );
            }
            emit_children_with_let_bindings(
                buf,
                source,
                &s.attributes,
                &s.children,
                inner_depth,
                insts,
                action_counter,
            );
            if dom_emit {
                emit_dom_element_close(buf, depth);
            }
        }
        Node::Interpolation(i) => emit_interpolation(buf, source, i, depth),
        Node::Text(_) | Node::Comment(_) => {}
    }
}

/// Emit a template `{EXPR}` interpolation as a bare expression
/// statement in the current scope so tsgo type-checks EXPR against
/// any enclosing control-flow narrowing (`{#if}` / `{:else if}` /
/// `{#each …}`) and against the script-declared types of referenced
/// identifiers.
///
/// Without emitting the expression here, a pattern like
///     `{#if form?.success}{form.error}{/if}`
/// has no `form.error` reference inside the `if`-body in the overlay,
/// so the TS2339 diagnostic upstream fires on accessing `.error` in
/// the truthy-narrowed branch never materializes. `find_template_refs`
/// voids the ROOT identifier (`form`) elsewhere, which kept TS6133
/// happy but forfeited type-checking of the FULL expression — the
/// whole point of type-checking the template.
///
/// `{@const NAME = EXPR}` still routes through `emit_at_const_if_any`
/// — that has to emit a `const` declaration at the block scope, not a
/// bare expression. Other `{@tag}` forms (`@html`, `@debug`, `@render`)
/// also need their own shapes; the generic `(EXPR);` here handles the
/// plain `{EXPR}` case and falls through for anything that looks like
/// a `{@` directive.
fn emit_interpolation(
    buf: &mut EmitBuffer,
    source: &str,
    interp: &svn_parser::Interpolation,
    depth: usize,
) {
    // Directive tags route through emit_at_const_if_any — @const is
    // the only tag we emit structured code for today. Other @-tags
    // (`@html`, `@render`, `@debug`, `@attach`) are side-effect-only
    // at the TS overlay layer; the early-return preserves that.
    //
    // Parser classifies each interpolation's kind at parse time
    // (svn_parser::InterpolationKind) so we don't re-peek at the
    // source bytes here.
    if interp.kind != svn_parser::InterpolationKind::Expression {
        emit_at_const_if_any(buf, source, interp, depth);
        return;
    }
    let expr_start = interp.expression_range.start as usize;
    let expr_end = interp.expression_range.end as usize;
    let Some(expr_raw) = source.get(expr_start..expr_end) else {
        return;
    };
    let trimmed = expr_raw.trim();
    if trimmed.is_empty() {
        return;
    }
    // Shift the source range to point at the trimmed expression so the
    // TokenMapEntry's overlay span exactly matches the source bytes
    // tsgo would blame for a diagnostic. Preserves the pre-migration
    // scanner's "overlay length == source length" invariant.
    let leading_ws = expr_raw.len() - expr_raw.trim_start().len();
    let trimmed_source_start = interp.expression_range.start + leading_ws as u32;
    let trimmed_source_end = trimmed_source_start + trimmed.len() as u32;
    // Emit shape: `INDENT(EXPR);\n`. Paren-wrap protects against
    // multi-clause / assignment-looking expressions parsing as
    // statement heads. `append_with_source` records the EXPR slice's
    // TokenMapEntry at emit time, replacing the earlier post-walk
    // `/*svn_I*/` sentinel + scan approach.
    let indent = "    ".repeat(depth);
    buf.append_synthetic(&indent);
    buf.append_synthetic("(");
    buf.append_with_source(
        trimmed,
        svn_core::Range::new(trimmed_source_start, trimmed_source_end),
    );
    buf.append_synthetic(");\n");
}

/// If `interp` is an `{@const <pattern> = <expr>}` tag, emit it inline
/// as a real `const <pattern> = <expr>;` statement in the current
/// template-check scope.
///
/// Without inline emission, the `@const`-declared name lives only as a
/// top-of-function `let NAME: any = undefined;` stub (see
/// `at_const_names` in the analyze crate). That works for "does the
/// name resolve?" checks but drops the expression's inferred type. A
/// pattern like
///     `{@const featureType = persistentFeature.settings.type}`
///     `{#if featureType === 'persistent-comment'}`
/// needs `featureType` to carry the discriminant literal type so TS's
/// control-flow analysis narrows it inside the `{#if}`. Emitting
/// inline pins the type. The top-level `let NAME: any` stub stays in
/// place so forward references (rare but possible) still resolve; the
/// inline `const` shadows it inside the block.
///
/// Destructured patterns (`{@const [a, { b }] = tuple}`) fall out for
/// free — we copy the source text verbatim and TS handles the pattern.
fn emit_at_const_if_any(
    buf: &mut EmitBuffer,
    source: &str,
    interp: &svn_parser::Interpolation,
    depth: usize,
) {
    // Parser labels each interpolation's kind at parse time; any
    // non-`@const` directive falls through to side-effect-only (no
    // structured emit).
    if interp.kind != svn_parser::InterpolationKind::AtConst {
        return;
    }
    // Body = expression_range (parser already trimmed the keyword).
    let body_start = interp.expression_range.start as usize;
    let body_end = interp.expression_range.end as usize;
    let Some(body) = source.get(body_start..body_end) else {
        return;
    };
    let body = body.trim();
    if body.is_empty() {
        return;
    }
    let indent = "    ".repeat(depth);
    // `const <pattern> = <expr>` — the body already carries `X = Y`
    // (pattern-or-name on the left of `=`, expression on the right).
    // Re-emitting inside the template-check `const` keyword pins the
    // inferred type so downstream `{#if NAME === '…'}` narrows.
    let _ = writeln!(buf, "{indent}const {body};");

    // Void every binding introduced by the pattern. Without this tsgo
    // fires TS6133 ("declared but never read") on `@const` tags whose
    // binding isn't referenced elsewhere in the enclosing block —
    // which can happen when the user only uses the binding inside a
    // conditional branch that isn't taken in a given type narrowing,
    // or when the `@const` is a side-effect helper like `{@const _ =
    // track()}`. Scanning the pattern LHS is the minimal fix; the
    // real-runtime semantics treat `{@const}` as a reactive value so
    // users don't expect the "unused local" warning to fire.
    // Take everything up to the first top-level `=` as the binding
    // pattern. Inside destructure brackets/braces `=` is a default
    // value, not the initializer — so track depth. Also trim a
    // top-level type annotation (`foo: SomeType`) because emitting
    // `void SomeType` would fire TS2693 ("only refers to a type").
    let lhs = split_lhs(body);
    for name in collect_pattern_names(&lhs) {
        let _ = writeln!(buf, "{indent}void {name};");
    }
}

/// Extract the binding-pattern prefix of an `{@const}` body, discarding
/// the type annotation and the initializer.
///
/// Examples:
///   - `foo = 1` → `foo`
///   - `foo: Record<A, B> = {}` → `foo`
///   - `[a, { b }] = tuple` → `[a, { b }]`
///   - `{ a = 1, b } = obj` → `{ a = 1, b }`
///
/// A top-level `:` terminates the pattern, preserving `:` inside
/// destructures (`{ key: binding }`). A top-level `=` outside any
/// brackets terminates the pattern. Depth-tracked so defaults and
/// nested types don't trip the scan.
fn split_lhs(body: &str) -> String {
    let bytes = body.as_bytes();
    let mut depth = 0i32;
    let mut end = bytes.len();
    let mut i = 0usize;
    while i < bytes.len() {
        match bytes[i] {
            b'{' | b'[' | b'(' | b'<' => depth += 1,
            b'}' | b']' | b')' | b'>' if depth > 0 => depth -= 1,
            b'=' if depth == 0 => {
                end = i;
                break;
            }
            b':' if depth == 0 => {
                end = i;
                break;
            }
            _ => {}
        }
        i += 1;
    }
    body[..end].trim().to_string()
}

/// Collect every identifier introduced by a (possibly destructuring)
/// binding pattern on the LHS of an `{@const}` tag.
///
/// Examples of what's collected:
///   - `foo` → [foo]
///   - `{ a, b: c, ...rest }` → [a, c, rest]
///   - `[a, { b }, ...rest]` → [a, b, rest]
///
/// Byte-scanning is enough for this lenient use — tsgo catches
/// anything we'd miss as a real diagnostic on the user's pattern, and
/// the only downstream consumer is `void <name>;` which is
/// forgiving.
fn collect_pattern_names(lhs: &str) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    let bytes = lhs.as_bytes();
    let mut i = 0usize;
    // In object-pattern `{ key: value }`, the binding is on the RHS of
    // the colon; track that state.
    let mut after_colon = false;
    // Track whether the previous non-space char was a comma, opener,
    // or `...` — those positions are where a new binding starts in
    // array/object patterns.
    let mut at_binding_start = true;
    let mut depth = 0i32;

    while i < bytes.len() {
        let b = bytes[i];
        match b {
            b'{' | b'[' => {
                depth += 1;
                i += 1;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b'}' | b']' => {
                depth -= 1;
                i += 1;
                after_colon = false;
                at_binding_start = false;
                continue;
            }
            b',' => {
                i += 1;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b':' => {
                // `key: value` inside an object pattern — the next
                // ident is the binding, not the key.
                i += 1;
                after_colon = true;
                at_binding_start = false;
                continue;
            }
            b'=' if depth > 0 => {
                // Default value in a destructure (`{ a = 1 }`); skip
                // until the next `,` or closing brace.
                let mut paren_depth = 0i32;
                i += 1;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' => paren_depth += 1,
                        b')' | b']' | b'}' if paren_depth > 0 => paren_depth -= 1,
                        b',' | b'}' | b']' if paren_depth == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
                continue;
            }
            b'.' if i + 2 < bytes.len() && &bytes[i..i + 3] == b"..." => {
                // Rest element. The following ident is a binding.
                i += 3;
                at_binding_start = true;
                after_colon = false;
                continue;
            }
            b if b.is_ascii_whitespace() => {
                i += 1;
                continue;
            }
            _ => {}
        }
        // Identifier?
        if b.is_ascii_alphabetic() || b == b'_' || b == b'$' {
            let start = i;
            while i < bytes.len() {
                let c = bytes[i];
                if c.is_ascii_alphanumeric() || c == b'_' || c == b'$' {
                    i += 1;
                } else {
                    break;
                }
            }
            let is_top_level = depth == 0;
            let is_binding = if is_top_level {
                // Plain `const foo = ...` — the ident is the binding.
                true
            } else {
                // Inside a pattern. Peek past whitespace to the next
                // non-space char:
                //   `{ a, b }`       → ident followed by `,`/`}` → binding.
                //   `{ a: b }`       → ident followed by `:`     → KEY (not a binding).
                //                     The `b` after `:` (after_colon) is the binding.
                //   `{ a = 1 }`      → ident followed by `=`     → binding with default.
                //   `[a, b]`         → at_binding_start true     → binding.
                //   `...rest`        → at_binding_start set true → binding.
                let mut j = i;
                while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                    j += 1;
                }
                let next = bytes.get(j).copied();
                if after_colon {
                    // `{ key: binding }` — the ident after `:` is always
                    // a binding unless the next char opens a nested
                    // pattern (handled separately by the `{`/`[` cases
                    // above).
                    true
                } else if at_binding_start {
                    // Ambiguity: object-pattern position could be either
                    // shorthand (`{ a }`, binding) or key-with-renamed
                    // binding (`{ a: b }`, key).
                    !matches!(next, Some(b':'))
                } else {
                    // Not at start, not after colon — not a binding.
                    false
                }
            };
            if is_binding {
                out.push(lhs[start..i].to_string());
            }
            at_binding_start = false;
            after_colon = false;
            continue;
        }
        // Anything else — reset markers and advance.
        at_binding_start = false;
        after_colon = false;
        i += 1;
    }
    out
}

/// Emit a `void [<access>, …];` statement listing every identifier /
/// property-access chain referenced inside the condition expression at
/// `range`. A no-op at runtime but a required pacifier for tsgo's
/// TS2774 check, which flags non-nullable-function operands of a
/// conditional `&&`/`||` chain unless the same symbol appears as a
/// value reference inside the enclosing block body.
///
/// We extract identifier chains (`foo`, `foo.bar`, `foo.bar.baz`) rather
/// than whole logical operands because re-emitting a comparison like
/// `displayMode !== 'full'` inside a block that already narrowed
/// `displayMode` to exclude `'full'` fires TS2367 ("this comparison
/// appears to be unintentional because the types have no overlap").
/// Identifier-chain references are narrowing-neutral and still satisfy
/// the check: `isSymbolUsedInConditionBody` walks identifiers in the
/// body and matches on property-access chains with the same symbol.
///
/// We skip negated (`!(…)`) conditions entirely: TS2774 doesn't fire
/// reliably when the condition lives behind `!`, and emitting a
/// property-access marker inside the negated branch can surface type
/// errors (TS18047 / TS2339) that the user's inverted narrowing would
/// normally make unreachable.
fn emit_condition_ref_marker(
    buf: &mut EmitBuffer,
    source: &str,
    range: svn_core::Range,
    depth: usize,
) {
    let Some(cond_text) = source.get(range.start as usize..range.end as usize) else {
        return;
    };
    if cond_text.trim_start().starts_with('!') {
        return;
    }
    let chains = extract_property_chains(cond_text);
    if chains.is_empty() {
        return;
    }
    let indent = "    ".repeat(depth);
    buf.push_str(&indent);
    buf.push_str("void [");
    for (i, chain) in chains.iter().enumerate() {
        if i > 0 {
            buf.push_str(", ");
        }
        buf.push_str(chain);
    }
    buf.push_str("];\n");
}

/// Extract every top-level identifier-or-property-access chain from
/// `text`, deduplicated and in source order.
///
/// Uses oxc to parse `text` as an expression, then walks the AST
/// collecting `Identifier` and `*MemberExpression` chains at the top
/// level of the expression's logical / binary structure. Per CLAUDE.md
/// rule #1 — the old byte walker (~180 LOC) was fragile: string
/// escapes inside template literals, RegExp literals, `?.` after
/// non-identifier, etc. all needed hand-coded handling. The AST
/// walker gets each of these for free.
///
/// Chain suffixes (`.prop`, `?.prop`) are included so
/// `ctx.GhostButton` emits as a single ref. Computed-member subscripts
/// (`foo[key]`) and call-argument lists (`f(x)`) are NOT swallowed:
/// only the callee / object portion contributes, matching the
/// existing template-refs pass convention. Re-emitting argument text
/// can introduce TS18047 / TS2339 from partial narrowing when the
/// enclosing block inverts the original condition.
///
/// Function bodies (arrow parameters, block expressions) are skipped
/// structurally — the AST walker simply doesn't recurse into them —
/// so inner-scope bindings never leak into the marker.
///
/// Keywords and the Svelte auto-subscribe `$ident` form are filtered
/// out post-walk.
///
/// Examples:
/// - `editable && ctx.GhostButton && options.length < max` →
///   `editable`, `ctx.GhostButton`, `options.length`, `max`
/// - `messages.some((m) => m.role === 'x')` → `messages.some`
///   (arrow body isn't recursed, so `m` / `m.role` don't leak)
fn extract_property_chains(text: &str) -> Vec<String> {
    use oxc_ast::ast::{Expression, Statement};

    let alloc = oxc_allocator::Allocator::default();
    // Wrap so oxc parses the content as a single expression statement,
    // regardless of whether it's a bare identifier, a comparison, or a
    // logical chain. Trailing `;` keeps oxc happy even for
    // expressions that wouldn't otherwise stand as statements.
    let src = format!("({text});");
    let parsed = svn_parser::parse_script_body(&alloc, &src, svn_parser::ScriptLang::Ts);
    if parsed.panicked {
        return Vec::new();
    }
    let Some(Statement::ExpressionStatement(stmt)) = parsed.program.body.first() else {
        return Vec::new();
    };
    // Unwrap `(` … `)`.
    let mut expr = &stmt.expression;
    while let Expression::ParenthesizedExpression(p) = expr {
        expr = &p.expression;
    }

    let mut out: Vec<String> = Vec::new();
    let mut seen: HashSet<String> = HashSet::new();

    fn chain_text<'a>(expr: &Expression<'_>, src: &'a str) -> Option<&'a str> {
        // Accept a chain root: Identifier, StaticMemberExpression,
        // ComputedMemberExpression (only if base is a chain root),
        // PrivateFieldExpression (.#foo), or a ChainExpression (the
        // `?.` optional-chaining wrapper).
        //
        // Reject CallExpression, arrow/function expressions, unary,
        // binary, logical, literal, template, regex, etc. — they're
        // not "chain roots" even though their contents may contain
        // chains (which we DON'T want to recurse into here, matching
        // the original byte walker's "skip parens" behaviour for
        // calls).
        use oxc_ast::ast::Expression::*;
        use oxc_span::GetSpan;
        match expr {
            Identifier(_) => Some(&src[expr.span().start as usize..expr.span().end as usize]),
            StaticMemberExpression(m) => {
                // Recurse into `.object` to confirm chain root.
                let _ = chain_text(&m.object, src)?;
                Some(&src[m.span.start as usize..m.span.end as usize])
            }
            ComputedMemberExpression(m) => {
                // `obj[key]` — only accept when `obj` is a chain root
                // AND `key` is a non-reference (literal). Matches old
                // behaviour: we skipped bracket subscripts, so
                // `foo[i]` would yield just `foo` (and the subscript
                // was ignored). Here we simply reject the whole
                // computed-member — the outer walker will keep
                // walking and pick up `foo` separately when it
                // appears elsewhere.
                let _ = chain_text(&m.object, src)?;
                // Keep the `obj` part only.
                Some(&src[m.object.span().start as usize..m.object.span().end as usize])
            }
            PrivateFieldExpression(m) => {
                let _ = chain_text(&m.object, src)?;
                Some(&src[m.span.start as usize..m.span.end as usize])
            }
            ChainExpression(c) => {
                // `?.` wrapper — recurse into its element.
                match &c.expression {
                    oxc_ast::ast::ChainElement::CallExpression(_) => None,
                    oxc_ast::ast::ChainElement::TSNonNullExpression(n) => {
                        chain_text(&n.expression, src)
                    }
                    oxc_ast::ast::ChainElement::ComputedMemberExpression(m) => {
                        let _ = chain_text(&m.object, src)?;
                        Some(&src[m.object.span().start as usize..m.object.span().end as usize])
                    }
                    oxc_ast::ast::ChainElement::StaticMemberExpression(m) => {
                        let _ = chain_text(&m.object, src)?;
                        Some(&src[m.span.start as usize..m.span.end as usize])
                    }
                    oxc_ast::ast::ChainElement::PrivateFieldExpression(m) => {
                        let _ = chain_text(&m.object, src)?;
                        Some(&src[m.span.start as usize..m.span.end as usize])
                    }
                }
            }
            _ => None,
        }
    }

    fn walk(expr: &Expression<'_>, src: &str, out: &mut Vec<String>, seen: &mut HashSet<String>) {
        use oxc_ast::ast::Expression::*;

        // Try as a chain root first. If it matches, record and stop —
        // we don't recurse into a chain's subscripts / call args.
        if let Some(text) = chain_text(expr, src) {
            let trimmed = text.trim();
            if !trimmed.is_empty() {
                let looks_like_keyword = !trimmed.contains('.') && is_keyword_or_special(trimmed);
                if !looks_like_keyword {
                    let key = trimmed.to_string();
                    if seen.insert(key.clone()) {
                        out.push(key);
                    }
                }
            }
            return;
        }

        match expr {
            LogicalExpression(e) => {
                walk(&e.left, src, out, seen);
                walk(&e.right, src, out, seen);
            }
            BinaryExpression(e) => {
                walk(&e.left, src, out, seen);
                walk(&e.right, src, out, seen);
            }
            ConditionalExpression(e) => {
                walk(&e.test, src, out, seen);
                walk(&e.consequent, src, out, seen);
                walk(&e.alternate, src, out, seen);
            }
            SequenceExpression(e) => {
                for ex in &e.expressions {
                    walk(ex, src, out, seen);
                }
            }
            UnaryExpression(e) => {
                walk(&e.argument, src, out, seen);
            }
            AwaitExpression(e) => {
                walk(&e.argument, src, out, seen);
            }
            YieldExpression(e) => {
                if let Some(arg) = &e.argument {
                    walk(arg, src, out, seen);
                }
            }
            UpdateExpression(e) => {
                // ++x / x-- — walk the inner target.
                // The target is a SimpleAssignmentTarget variant.
                match &e.argument {
                    oxc_ast::ast::SimpleAssignmentTarget::AssignmentTargetIdentifier(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::ComputedMemberExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::StaticMemberExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::PrivateFieldExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::TSAsExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::TSSatisfiesExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::TSNonNullExpression(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::TSTypeAssertion(_)
                    | oxc_ast::ast::SimpleAssignmentTarget::TSInstantiationExpression(_) => {
                        // Don't recurse here — UpdateExpression targets
                        // are rarely valuable as chain roots; mirrors
                        // the byte walker's behaviour of treating
                        // `++foo` and `foo++` as producing no chain.
                    }
                }
            }
            ParenthesizedExpression(p) => {
                walk(&p.expression, src, out, seen);
            }
            CallExpression(c) => {
                // Callee contributes, arguments don't — matches the
                // original docstring's `messages.some((m) => m.role)`
                // example (only `messages.some` leaks out).
                walk(&c.callee, src, out, seen);
            }
            TSAsExpression(e) => walk(&e.expression, src, out, seen),
            TSSatisfiesExpression(e) => walk(&e.expression, src, out, seen),
            TSNonNullExpression(e) => walk(&e.expression, src, out, seen),
            TSTypeAssertion(e) => walk(&e.expression, src, out, seen),
            TSInstantiationExpression(e) => walk(&e.expression, src, out, seen),
            // Everything else — literals, arrows, objects, arrays,
            // `new`, await, yield, template literals, etc. — has no
            // top-level chain to extract at this level. The AST
            // boundary means inner bindings don't leak.
            _ => {}
        }
    }

    // Offset-adjust: we parsed `({text});`, but `MemberExpression.span`
    // returns offsets into `src` not `text`. Since `chain_text` slices
    // directly from `src`, and `src = format!("({text});")`, the
    // slices contain substrings of `text` (with leading `(` stripped
    // by the span). Result strings don't include the wrapper chars.
    walk(expr, &src, &mut out, &mut seen);
    out
}

/// Keywords and reserved identifiers that should never appear in a
/// ref-marker void-array. Mirrors the filter in `template_refs` so a
/// condition like `{#if typeof x === 'string'}` doesn't emit a stray
/// `typeof` reference.
fn is_keyword_or_special(s: &str) -> bool {
    matches!(
        s,
        "true"
            | "false"
            | "null"
            | "undefined"
            | "this"
            | "void"
            | "typeof"
            | "new"
            | "instanceof"
            | "in"
            | "of"
            | "as"
            | "let"
            | "const"
            | "var"
            | "function"
            | "if"
            | "else"
            | "for"
            | "while"
            | "do"
            | "return"
            | "yield"
            | "await"
            | "async"
            | "delete"
            | "throw"
            | "try"
            | "catch"
            | "finally"
            | "switch"
            | "case"
            | "default"
            | "break"
            | "continue"
            | "class"
            | "extends"
            | "super"
            | "import"
            | "export"
            | "from"
            | "satisfies"
    ) || s.starts_with('$')
}

/// Emit a `for`-of loop for an `{#each}` block.
///
/// `{#each items}` without an `as` clause is legal Svelte (iterate N times,
/// discard the value); we use `__svn_each_unused` as a placeholder binding
/// so the emitted TypeScript stays syntactically valid.
fn emit_each_block(
    buf: &mut EmitBuffer,
    source: &str,
    b: &EachBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let indent = "    ".repeat(depth);
    let raw_expr = source
        .get(b.expression_range.start as usize..b.expression_range.end as usize)
        .unwrap_or("undefined");
    let expr_text = raw_expr.trim();
    // Trimmed-slice source range so tsgo diagnostics fired anywhere
    // inside the expression (e.g. TS18048 on `.sort((a, b) => …)`
    // callback params) map back to their actual user-source byte
    // positions via the token map. Without this, callback-param
    // diagnostics fall in a synthesized region (the `__svn_each_items(...)`
    // wrapper span) and `map_diagnostic` drops them.
    let expr_source_range: Option<svn_core::Range> = if expr_text.is_empty() {
        None
    } else {
        let leading_ws = (raw_expr.len() - raw_expr.trim_start().len()) as u32;
        let start = b.expression_range.start + leading_ws;
        Some(svn_core::Range::new(start, start + expr_text.len() as u32))
    };
    let binding_text = match &b.as_clause {
        Some(c) => source
            .get(c.context_range.start as usize..c.context_range.end as usize)
            .unwrap_or("__svn_each_unused")
            .to_string(),
        None => "__svn_each_unused".to_string(),
    };
    // `{#each items as item, i}` — `i` is the zero-based iteration index.
    // `__svn_each_items` returns a plain Iterable, which doesn't expose
    // `.entries()`, so declaring the index as a `const i: number` inside
    // the loop body is simpler than rewriting the for-of pattern to
    // destructure an [index, item] pair. Using `0` for the value is a
    // type-only trick — the generated function is never executed.
    let index_binding: Option<&str> = b
        .as_clause
        .as_ref()
        .and_then(|c| c.index_range)
        .and_then(|r| source.get(r.start as usize..r.end as usize));
    let _ = write!(
        buf,
        "{indent}for (const {binding_text} of __svn_each_items("
    );
    match expr_source_range {
        Some(r) => buf.append_with_source(expr_text, r),
        None => buf.push_str(expr_text),
    }
    let _ = writeln!(buf, ")) {{");
    if let Some(ix) = index_binding {
        if emit_is_ts() {
            let _ = writeln!(buf, "{indent}    const {ix}: number = 0;");
        } else {
            let _ = writeln!(buf, "{indent}    /** @type {{number}} */ const {ix} = 0;");
        }
    }
    emit_template_body(buf, source, &b.body, depth + 1, insts, action_counter);
    // Void every identifier that the binding pattern destructures, not
    // just the first. `[id, label]` and `[id, { label }]` both bind two
    // names and TS6133 fires on each unused one.
    for ident in all_identifiers(&binding_text) {
        let _ = writeln!(buf, "{indent}    void {ident};");
    }
    if let Some(ix) = index_binding {
        let _ = writeln!(buf, "{indent}    void {ix};");
    }
    let _ = writeln!(buf, "{indent}}}");

    if let Some(alt) = &b.alternate {
        emit_template_body(buf, source, alt, depth, insts, action_counter);
    }
}

/// Walk `{:then v}` / `{:catch e}` body in a fresh lexical scope that
/// declares the branch's context binding as `any`. Without the
/// declaration, references to the bound name inside the branch (a
/// component-prop check that passes `v` as a prop, a subsequent
/// `{#each v as item}`) fire TS2304.
///
/// Supports destructure patterns (`{:then { a, b }}`, `{:then [x]}`)
/// via `all_identifiers`. An absent context range (`{:then}` with no
/// binding) skips the scope and just walks the body inline.
fn emit_branch_with_binding(
    buf: &mut EmitBuffer,
    source: &str,
    context_range: Option<&svn_core::Range>,
    body: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let Some(range) = context_range else {
        emit_template_body(buf, source, body, depth, insts, action_counter);
        return;
    };
    let binding_text = source
        .get(range.start as usize..range.end as usize)
        .unwrap_or("")
        .trim();
    if binding_text.is_empty() {
        emit_template_body(buf, source, body, depth, insts, action_counter);
        return;
    }
    let idents = all_identifiers(binding_text);
    let indent = "    ".repeat(depth);
    let _ = writeln!(buf, "{indent}{{");
    let is_ts = emit_is_ts();
    for ident in &idents {
        if is_ts {
            let _ = writeln!(buf, "{indent}    const {ident}: any = undefined;");
        } else {
            let _ = writeln!(buf, "{indent}    const {ident} = undefined;");
        }
    }
    emit_template_body(buf, source, body, depth + 1, insts, action_counter);
    for ident in &idents {
        let _ = writeln!(buf, "{indent}    void {ident};");
    }
    let _ = writeln!(buf, "{indent}}}");
}

/// Emit `{:then v}` branch with upstream's await-binding shape:
///     ;async () => {
///         const $$_await = await (PROMISE_EXPR);
///         { const v = $$_await; ...body... }
///     };
/// so `v`'s type flows from the promise's resolved value (upstream
/// svelte2tsx behavior — see htmlxtojsx_v2/nodes/AwaitPendingCatchBlock.ts).
/// The outer `async () => {}` is a bare expression-statement — never
/// called, just provides the async context TS's `await` requires.
/// Necessary because `{#await}` can nest inside a sync snippet
/// callback (`children: () => {…}`), where bare `await` fires TS1375.
/// For `{:then {a, b, c}}` destructure patterns the binding text is
/// emitted verbatim as the destructure target.
#[allow(clippy::too_many_arguments)]
fn emit_await_then_branch(
    buf: &mut EmitBuffer,
    source: &str,
    promise_range: svn_core::Range,
    context_range: Option<&svn_core::Range>,
    body: &Fragment,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let promise_text = source
        .get(promise_range.start as usize..promise_range.end as usize)
        .unwrap_or("")
        .trim();
    if promise_text.is_empty() {
        emit_branch_with_binding(
            buf,
            source,
            context_range,
            body,
            depth,
            insts,
            action_counter,
        );
        return;
    }
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let binding_text = context_range
        .and_then(|r| source.get(r.start as usize..r.end as usize))
        .map(str::trim)
        .filter(|s| !s.is_empty());

    let _ = writeln!(buf, "{indent};(async () => {{");
    match binding_text {
        Some(bind) => {
            let idents = all_identifiers(bind);
            let _ = writeln!(
                buf,
                "{inner}const $$_await = await ({promise_text}); const {bind} = $$_await;"
            );
            emit_template_body(buf, source, body, depth + 1, insts, action_counter);
            for ident in &idents {
                let _ = writeln!(buf, "{inner}void {ident};");
            }
        }
        None => {
            let _ = writeln!(
                buf,
                "{inner}const $$_await = await ({promise_text}); void $$_await;"
            );
            emit_template_body(buf, source, body, depth + 1, insts, action_counter);
        }
    }
    let _ = writeln!(buf, "{indent}}});");
}

/// Emit a lexical-scope block wrapping a `{#snippet name(params)}` body
/// so the snippet's parameter identifiers are in scope for references
/// inside the body (including component-prop checks on `<Component>`
/// nodes nested below the snippet).
///
/// Parameters are typed as `any` — we don't resolve their types from
/// the declared `Snippet<[...]>` shape here. For excess-prop and
/// "cannot find name" detection that's sufficient; precise param
/// typing would require threading the consumer's `Snippet<...>` into
/// the snippet body's type context, which v0.1 punts on.
///
/// Handles both identifier params (`foo, bar`) and destructure params
/// (`{months, weekdays}`, `[a, b]`) via `all_identifiers`. Default
/// values (`foo = 1`) have the default expression stripped before
/// identifier extraction.
fn emit_snippet_block(
    buf: &mut EmitBuffer,
    source: &str,
    b: &SnippetBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let indent = "    ".repeat(depth);
    let params_text = source
        .get(b.parameters_range.start as usize..b.parameters_range.end as usize)
        .unwrap_or("")
        .trim();
    // `{#snippet name()}` with an empty parameter list — skip the
    // scope + placeholder binding entirely. `all_identifiers` never
    // returns an empty vec (it falls back to `__svn_each_unused`),
    // so we intercept the empty-params case before calling it.
    if params_text.is_empty() {
        emit_template_body(buf, source, &b.body, depth, insts, action_counter);
        return;
    }
    // Open a fresh block, then reference the ORIGINAL params text
    // inside an arrow function's signature — that keeps the user's
    // type annotations (e.g. `MouseEventHandler<HTMLButtonElement>`)
    // bound as references. Without this, types only used in a
    // snippet parameter list (and never in the script body) fire
    // TS6133 "declared but never read" on their import.
    //
    // We don't try to thread contextual typing through — top-level
    // snippets have no parent satisfies target to flow from. Each
    // user-named parameter gets re-declared inside the body as `const
    // <name>: any` so the snippet body type-checks without depending
    // on the arrow's inferred param types (which the `null as any`
    // cast erases anyway).
    let annotated = annotate_snippet_params(params_text);
    let idents = all_identifiers(params_text);
    // Emit the body INSIDE a no-op arrow function expression whose
    // params carry the user's type annotations. This serves two
    // purposes simultaneously:
    //   1. The arrow params are the binding introductions — their
    //      type annotations flow into the body, so a snippet like
    //      `{#snippet state(state: VideoState)}` gets `state: VideoState`
    //      bindings rather than `state: any`.
    //   2. Any type imported solely for a snippet param annotation
    //      (e.g. `MouseEventHandler<HTMLButtonElement>`) shows up as
    //      a reference in the emitted code, suppressing TS6133.
    //
    // We use a function *expression* (not a type) so default values
    // and optional-after-required orderings remain legal.
    let _ = writeln!(buf, "{indent}{{");
    let _ = writeln!(buf, "{indent}    void (({annotated}) => {{");
    emit_template_body(buf, source, &b.body, depth + 2, insts, action_counter);
    for ident in &idents {
        let _ = writeln!(buf, "{indent}        void {ident};");
    }
    let _ = writeln!(buf, "{indent}    }});");
    let _ = writeln!(buf, "{indent}}}");
}

/// Emit a typed call per `use:ACTION={PARAMS}` directive so the PARAMS
/// expression gets contextually-typed against ACTION's declared second
/// parameter.
///
/// Shape (mirrors upstream svelte2tsx's `__sveltets_2_ensureAction(…)`
/// with our `__svn_` namespace):
///
/// ```ts
///     const __svn_action_0 = __svn_ensure_action(
///         enhance(__svn_map_element_tag('form'), (({formData}) => {…}))
///     );
///     void __svn_action_0;
/// ```
///
/// The inner `enhance(…)` is a real function call — TS checks that the
/// PARAMS match ACTION's declared parameter shape. For `use:enhance=
/// {({form,data,submit}) => …}` that fires TS2339 on each wrong name
/// because the real `SubmitFunction` parameter type doesn't have them.
///
/// Pre-v0.3.9 we emitted `let __svn_action_attrs_N: any = {};` — a dead
/// placeholder that discarded the PARAMS expression entirely. Every
/// destructure inside a `use:` callback silently passed regardless of
/// correctness, and the user-reported `use:enhance={({form,data,submit})
/// => …}` bug was invisible to our tool while upstream fired 3 TS2339s.
///
/// The legacy `__svn_action_attrs_N` void-ref registration stays for
/// anyone who referenced the name externally (e.g. template spreads);
/// we emit it alongside the new call so no registered name disappears.
/// Register the legacy `let __svn_action_attrs_N: any = {};` compat
/// shims at the top of `__svn_tpl_check`. These are registered names
/// consumed by downstream void-ref emission. The actual `use:` action
/// calls that type-check params against action signatures are emitted
/// inline per-element by [`emit_use_directives_inline`] — so scope-
/// bound identifiers referenced inside the params expression
/// (`{#each items as item, i}`'s `i`, `{@const}` declarations, snippet
/// parameters) stay visible in the emitted TS.
fn emit_legacy_action_attrs(out: &mut String, summary: &TemplateSummary, is_ts: bool) {
    // Keep the old `__svn_action_attrs_N` void registration alive so
    // external references (e.g. template spreads that consumed the
    // action's declared `$$_attributes`) still resolve. The outer
    // void_block emits `void __svn_action_attrs_N;` unconditionally;
    // declaring the binding here avoids TS2304 at that reference site.
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_action_attrs_") {
            if is_ts {
                let _ = writeln!(out, "        let {name}: any = {{}};");
            } else {
                let _ = writeln!(out, "        /** @type {{any}} */ let {name} = {{}};");
            }
            let _ = writeln!(out, "        void {name};");
        }
    }
}

/// Emit a type-compatibility check for each recognized
/// one-way-not-on-element DOM binding:
///
/// ```ts
///     __svn_any_as<DOMRectReadOnly>(rect);
/// ```
///
/// Assignment form isn't usable — `rect = __svn_any() as DOMRectReadOnly`
/// would rewrite the variable's inferred type in every subsequent flow
/// analysis position and fire spurious errors downstream. A phantom
/// function call with the bound variable as its SOLE argument, typed
/// against the binding's target type via a generic, checks the
/// variable's declared type accepts the binding type without mutating
/// the inferred narrowing. `__svn_any_as<T>(value: T): void` is
/// ambient.
///
/// Only emit when the binding's source slice parses as a plain
/// expression TS can evaluate in a call-argument slot. `bind:NAME`
/// bare-shorthand forms give us the DIRECTIVE SPAN as the value
/// range (because the user wrote no `={...}`), which includes the
/// `bind:` prefix — not valid TS. Detect + skip those; the shorthand
/// desugars to `bind:NAME={NAME}` at runtime, so the user's `NAME`
/// local still has the bind-assigned type (checked by the
/// corresponding `BindThisTarget`'s `!` rewrite).
/// v0.3 Item 6: emit `__svn_any_as<TYPE>(expr);` contract checks for
/// every `bind:NAME={expr}` attribute whose NAME is in
/// `dom_binding::type_for`'s table, directly at the current
/// template-walk position. Inline emission places each check inside
/// the walker's enclosing `{#each}` / `{#if}` / `{#snippet}` scope,
/// so a binding expression referencing a block-scoped iterator
/// (`bind:clientWidth={items[i].width}`) resolves against the `i`
/// introduced by that block rather than the top-of-tpl_check scope.
///
/// Bare-shorthand `bind:NAME` is NOT emitted here — its source-range
/// value-text is the whole directive (including the `bind:` prefix),
/// not valid TS as a call argument. The shorthand's declaration-site
/// `!` rewrite covers the definite-assign half of the type-check
/// flow.
/// Emit the typed `use:ACTION={PARAMS}` call inline at the parent
/// element's depth during the template walk. Shape matches
/// [`emit_legacy_action_attrs`]'s prior top-of-tpl_check form:
///
/// ```ts
/// const __svn_action_0 = __svn_ensure_action(
///     enhance(__svn_map_element_tag('form'), (({formData}) => {…}))
/// );
/// void __svn_action_0;
/// ```
///
/// Index comes from `action_counter` — walker walks the template in
/// the same depth-first order as emit, so the Nth use-directive
/// emit encounters matches the Nth `ActionDirective` the walker
/// pushed onto `summary.action_directives`. The `__svn_action_<N>`
/// anchor is required for the post-emit token-map scan
/// (`collect_action_params_token_map`) to pin diagnostics back to
/// the user's PARAMS source range.
///
/// Being inline at element depth puts the call INSIDE any enclosing
/// `{#each} as item, index` / `{@const X = …}` / `{#snippet}` scope,
/// so identifiers defined there resolve correctly when referenced
/// from the callback bodies inside PARAMS. Pre-fix we hoisted all
/// action calls to the top of `__svn_tpl_check`, which left
/// `{#each items as _, i}<div use:a={{on:()=>i}}>` reading `i` as
/// "Cannot find name" (validated on a component-library bench;
/// our Svelte-4/5 control rigs had 6 such fires on real user code).
/// Emit `const __svn_action_N = __svn_ensure_action(...)` declarations
/// for each `use:` directive on an element. Runs BEFORE the
/// `svelteHTML.createElement` call so the action-attribute returns can
/// be passed as the second arg (3-arg overload), which forces tsgo to
/// expand the attrs param type's alias into `Omit<HTMLAttributes<...>,
/// never> & <actions>` — matching upstream's byte-for-byte diagnostic
/// message format.
///
/// Returns the range of indices allocated (`first..first+count`) so
/// the caller can splice the union at the createElement site and emit
/// matching `void __svn_action_N;` references after the element
/// closes.
fn emit_dom_action_decls(
    buf: &mut EmitBuffer,
    source: &str,
    tag_name: &str,
    attributes: &[svn_parser::Attribute],
    depth: usize,
    action_counter: &mut usize,
) -> std::ops::Range<usize> {
    let indent = "    ".repeat(depth);
    let tag_arg = if tag_name.is_empty() {
        "'' as string".to_string()
    } else {
        format!("'{tag_name}'")
    };
    let first = *action_counter;
    for attr in attributes {
        let svn_parser::Attribute::Directive(d) = attr else {
            continue;
        };
        if d.kind != svn_parser::DirectiveKind::Use {
            continue;
        }
        let index = *action_counter;
        *action_counter += 1;
        let action = d.name.as_str();
        match &d.value {
            Some(svn_parser::DirectiveValue::Expression {
                expression_range, ..
            }) => {
                let Some(params) =
                    source.get(expression_range.start as usize..expression_range.end as usize)
                else {
                    // Undo the counter bump on skip so subsequent
                    // indices stay contiguous.
                    *action_counter -= 1;
                    continue;
                };
                // Split the writeln so `params` splices via
                // `append_with_source`, which pushes a TokenMapEntry at
                // emit time covering the params overlay span → the user's
                // `use:ACTION={...}` expression_range. Pre-4.2.6 this
                // mapping was produced by a post-walk scanner
                // (`collect_action_directive_token_map`) that paren-
                // balanced to find the same slice — inline emit is
                // cheaper and uniquely correct.
                let _ = write!(
                    buf,
                    "{indent}const __svn_action_{index} = __svn_ensure_action({action}(__svn_map_element_tag({tag_arg}), ("
                );
                buf.append_with_source(params, *expression_range);
                buf.push_str(")));\n");
            }
            _ => {
                let _ = writeln!(
                    buf,
                    "{indent}const __svn_action_{index} = __svn_ensure_action({action}(__svn_map_element_tag({tag_arg})));"
                );
            }
        }
    }
    first..*action_counter
}

/// Emit `void __svn_action_N;` references for each allocated action
/// index. Placed AFTER the `svelteHTML.createElement` call to prevent
/// the unused-variable diagnostic — the action's value is carried into
/// `createElement`'s second arg, then referenced here to mark it used.
fn emit_dom_action_void_refs(buf: &mut EmitBuffer, indices: &std::ops::Range<usize>, depth: usize) {
    let indent = "    ".repeat(depth);
    for index in indices.clone() {
        let _ = writeln!(buf, "{indent}void __svn_action_{index};");
    }
}

/// Legacy emission for the feature-gated non-dom-emit path: emit both
/// the action declaration and its void-reference in one block, without
/// feeding the action into a createElement 3-arg overload. Preserves
/// the pre-Phase-2 behavior when `SVN_DOM_ELEMENT_EMIT=0` opts out of
/// the DOM-element emit entirely.
fn emit_use_directives_inline_legacy(
    buf: &mut EmitBuffer,
    source: &str,
    tag_name: &str,
    attributes: &[svn_parser::Attribute],
    depth: usize,
    action_counter: &mut usize,
) {
    let indices = emit_dom_action_decls(buf, source, tag_name, attributes, depth, action_counter);
    emit_dom_action_void_refs(buf, &indices, depth);
}

/// Emit a type-check line per `bind:NAME` directive on a DOM element.
///
/// Shape: `{indent}EXPR = null as any as TYPE;` — direct assignment
/// (NOT wrapped in a never-called lambda). Upstream svelte2tsx's
/// `Binding.ts:86-146` emits the same direct form, which type-checks
/// the LHS against the binding's value type AND narrows EXPR's flow
/// type for subsequent uses. A `let x = $state<number>()` (type
/// `number | undefined`) passed through `bind:clientWidth` then
/// flows as `number` at the later `<Child {x}/>` site. The earlier
/// lambda wrapper isolated the assignment from narrowing, producing
/// spurious "possibly undefined" errors that upstream didn't (bench
/// FigmaPopup mainWidth).
///
/// Supports all DOM bind: variants under one loop:
///   - `bind:this` — TYPE = `HTMLElementTagNameMap['tag']` (or
///     `HTMLElement` for the dynamic `<svelte:element>` escape hatch
///     when `tag_name == ""`). Member expressions
///     (`bind:this={refs.input}`) and bare identifiers both work;
///     the assignment is verbatim from source.
///   - `bind:value` — TYPE resolved once per element via
///     `resolve_bind_value_type`, which inspects the literal
///     `type="..."` sibling attribute. Non-form elements return
///     `None` and the directive is skipped.
///   - Other one-way bindings (`bind:checked`, `bind:files`,
///     `bind:group`, `bind:clientWidth`, `bind:naturalHeight`, …) —
///     TYPE from `svn_analyze::dom_binding::type_for(name)`;
///     unknown names are skipped.
///
/// EXPR resolution:
///   - `bind:NAME={expr}` → trimmed EXPR with a source range that
///     exactly covers the trimmed slice; `append_with_source` pushes
///     a TokenMapEntry so diagnostics land at the source position.
///   - `bind:NAME` (shorthand, NAME ≠ `this`) → uses NAME as the
///     target; no source range since there's no user expression to
///     map back to.
///   - `bind:this` without an `={EXPR}` value is not valid Svelte
///     shorthand; skipped.
fn emit_element_bind_checks_inline(
    buf: &mut EmitBuffer,
    source: &str,
    tag_name: &str,
    attributes: &[svn_parser::Attribute],
    depth: usize,
) {
    let indent = "    ".repeat(depth);
    // v0.3 Item 8: `bind:value`'s target type depends on the element
    // tag + literal `type="..."` sibling attribute. Resolve once per
    // element (not per-directive) since every `bind:value` on the
    // same element dispatches to the same target type.
    let bind_value_type = svn_analyze::resolve_bind_value_type(tag_name, attributes);
    for attr in attributes {
        let svn_parser::Attribute::Directive(directive) = attr else {
            continue;
        };
        if directive.kind != svn_parser::DirectiveKind::Bind {
            continue;
        }
        let name = directive.name.as_str();
        let ty: String = if name == "this" {
            element_type_annotation(tag_name)
        } else if name == "value" {
            match bind_value_type {
                Some(t) => t.to_string(),
                None => continue,
            }
        } else {
            match svn_analyze::dom_binding::type_for(name) {
                Some(t) => t.to_string(),
                None => continue,
            }
        };
        let (expr_text, expr_source_range): (std::borrow::Cow<'_, str>, Option<svn_core::Range>) =
            match &directive.value {
                Some(svn_parser::DirectiveValue::Expression {
                    expression_range, ..
                }) => {
                    let Some(slice) =
                        source.get(expression_range.start as usize..expression_range.end as usize)
                    else {
                        continue;
                    };
                    let trimmed = slice.trim();
                    if trimmed.is_empty() {
                        continue;
                    }
                    let leading_ws = (slice.len() - slice.trim_start().len()) as u32;
                    let start = expression_range.start + leading_ws;
                    let end = start + trimmed.len() as u32;
                    (
                        std::borrow::Cow::Borrowed(trimmed),
                        Some(svn_core::Range::new(start, end)),
                    )
                }
                None => {
                    // `bind:this` has no shorthand form — always
                    // carries `={EXPR}`. Skip when missing.
                    if name == "this" {
                        continue;
                    }
                    (std::borrow::Cow::Borrowed(directive.name.as_str()), None)
                }
                // Svelte 5 `bind:X={get, set}` on DOM — two cases:
                //
                // - `bind:this={get, set}`: mirror upstream's direct
                //   `(set)($$_element)` call (svelte2tsx emits this
                //   verbatim). Setter's parameter is checked by
                //   assignability — accepts the element type or any
                //   supertype. Getter ignored.
                //
                // - Other directives (`bind:clientWidth={null, set}`,
                //   `bind:value={get, set}`): route through the
                //   `__svn_get_set_binding` helper with a `satisfies`
                //   trailer so the setter's parameter is unified with
                //   the DOM target's type, exactly like the component
                //   path in `write_prop_shape`. TS1360 fires on
                //   mismatch; see design/get_set_binding/.
                Some(svn_parser::DirectiveValue::BindPair {
                    getter_range,
                    setter_range,
                    ..
                }) => {
                    let getter = &source[getter_range.start as usize..getter_range.end as usize];
                    let setter = &source[setter_range.start as usize..setter_range.end as usize];
                    buf.push_str(&indent);
                    if name == "this" {
                        // Matches upstream `(set)($$_element)` —
                        // getter deliberately ignored (upstream's
                        // binding-this-get-set.v5 fixture drops it too).
                        let _ = writeln!(buf, "({setter})(null as any as {ty});");
                    } else {
                        let _ = writeln!(
                            buf,
                            "void (__svn_get_set_binding({getter}, {setter}) satisfies {ty});"
                        );
                    }
                    continue;
                }
                _ => continue,
            };
        if expr_text.is_empty() {
            continue;
        }
        buf.push_str(&indent);
        match expr_source_range {
            Some(range) => buf.append_with_source(&expr_text, range),
            None => buf.push_str(&expr_text),
        }
        if emit_is_ts() {
            let _ = writeln!(buf, " = null as any as {ty};");
        } else {
            // JS overlay: `as T` is TS-only syntax. Use a JSDoc cast
            // on the RHS instead — `/** @type {T} */(null)` gives the
            // null literal type T, which assigns into the LHS (the
            // bound variable) and fires TS2322 when the LHS's declared
            // type can't accept T. Mirrors upstream svelte2tsx's
            // `rect = null as DOMRectReadOnly;` shape byte-for-byte
            // in behaviour (see
            // `language-tools/packages/svelte2tsx/src/htmlxtojsx_v2/nodes/Binding.ts`).
            let _ = writeln!(buf, " = /** @type {{{ty}}} */ (null);");
        }
    }
}

// Thread-local holding the current emit's `is_ts` flag. Set at the
// top of `emit_document_with_render_name` via `IsTsGuard::enter`,
// read by deep emit sites (bind:this casts, each-block `let i`,
// branch bindings, snippet params) without threading the flag
// through 9+ function signatures. Per-thread because rayon parallelises
// emission — each file runs on whatever rayon worker picks it up, so
// the guard must set+reset per-invocation.
thread_local! {
    static EMIT_IS_TS: std::cell::Cell<bool> = const { std::cell::Cell::new(true) };
}

struct IsTsGuard {
    prev: bool,
}

impl IsTsGuard {
    fn enter(is_ts: bool) -> Self {
        let prev = EMIT_IS_TS.with(|c| c.replace(is_ts));
        Self { prev }
    }
}

impl Drop for IsTsGuard {
    fn drop(&mut self) {
        EMIT_IS_TS.with(|c| c.set(self.prev));
    }
}

fn emit_is_ts() -> bool {
    EMIT_IS_TS.with(|c| c.get())
}

/// Default-ON as of 2026-04-24 after A/B validation across our
/// bench fleet (Svelte-4 control, Svelte-5 control, a CMS bench,
/// a charting-lib bench, a component-lib bench, a reader bench,
/// an ML-playground bench — all at or below prior error counts,
/// with the CMS bench closing +7 upstream-parity diagnostics).
/// Opt OUT via `SVN_DOM_ELEMENT_EMIT=0` / `=false` /
/// `=off` if a user reports a regression while the shape is being
/// tuned. Opt-out path retained for a release or two; delete when
/// Phase 2 (directives + svelte:* namespaces) also lands.
fn dom_element_emit_enabled() -> bool {
    use std::sync::OnceLock;
    static ENABLED: OnceLock<bool> = OnceLock::new();
    *ENABLED.get_or_init(|| {
        !matches!(
            std::env::var("SVN_DOM_ELEMENT_EMIT")
                .ok()
                .as_deref()
                .map(str::trim)
                .map(str::to_ascii_lowercase)
                .as_deref(),
            Some("0" | "false" | "no" | "off")
        )
    })
}

/// Emit the upstream-shape `svelteHTML.createElement("tag", { …attrs });`
/// call for a DOM element. Opens a scoped `{ }` block so element-local
/// let-bindings (`{@const}`, `let:x`, action-attr `const $$action_N`)
/// stay confined to this element — matches upstream Element.ts's
/// transformation result.
///
/// Phase 1 scope:
///   - Plain `name="value"` / `name={expr}` / `name` (boolean) attrs.
///   - Shorthand `{name}` attrs.
///   - Expression `name={expr}` attrs.
///   - Skips Spread (Phase 2) and Directives (Bind/Use handled
///     separately; Class/Style deferred to Phase 2).
///
/// Output shape (matches upstream svelte2tsx):
///   `{ svelteHTML.createElement("tag", { "name": value, name2, … }); `
/// Closing `}` is emitted by the caller after children + bind/use
/// checks recurse into the same scope. `tag_literal` controls whether
/// the first arg is a quoted string literal (`"div"`) — set false for
/// `svelte:element this={tag}` where the caller passes the expression
/// verbatim as `tag_name`.
fn emit_dom_element_open(
    buf: &mut EmitBuffer,
    source: &str,
    tag_name: &str,
    tag_literal: bool,
    attributes: &[svn_parser::Attribute],
    depth: usize,
    action_indices: &std::ops::Range<usize>,
) {
    let indent = "    ".repeat(depth);
    // Build the `__svn_union(__svn_action_0, __svn_action_1, …)`
    // second arg when any `use:` directives are present. Matches
    // upstream `svelte2tsx`'s 3-arg overload emit — the `attrs`
    // parameter type becomes `Elements[Key] & T` (intersection)
    // which tsgo eagerly expands in error messages (the alias form
    // would be preserved in the 2-arg overload). See the shim's
    // `__svn_union` helper.
    let union_prefix = if action_indices.is_empty() {
        String::new()
    } else {
        let mut args = String::new();
        for (i, index) in action_indices.clone().enumerate() {
            if i > 0 {
                args.push_str(", ");
            }
            let _ = write!(args, "__svn_action_{index}");
        }
        format!("__svn_union({args}), ")
    };
    if tag_literal {
        let _ = write!(
            buf,
            "{indent}{{ svelteHTML.createElement(\"{tag_name}\", {union_prefix}{{"
        );
    } else {
        let _ = write!(
            buf,
            "{indent}{{ svelteHTML.createElement({tag_name}, {union_prefix}{{"
        );
    }
    let mut any = false;
    for attr in attributes {
        match attr {
            svn_parser::Attribute::Plain(p) => {
                if dom_attr_should_skip(p.name.as_str()) {
                    continue;
                }
                if !any {
                    buf.push_str("\n");
                    any = true;
                }
                emit_dom_plain_attr(buf, source, p, depth + 1);
            }
            svn_parser::Attribute::Expression(e) => {
                if dom_attr_should_skip(e.name.as_str()) {
                    continue;
                }
                if !any {
                    buf.push_str("\n");
                    any = true;
                }
                emit_dom_expression_attr(buf, source, e, depth + 1);
            }
            svn_parser::Attribute::Shorthand(s) => {
                if dom_attr_should_skip(s.name.as_str()) {
                    continue;
                }
                if !any {
                    buf.push_str("\n");
                    any = true;
                }
                emit_dom_shorthand_attr(buf, source, s, depth + 1);
            }
            svn_parser::Attribute::Spread(s) => {
                let Some(expr) =
                    source.get(s.expression_range.start as usize..s.expression_range.end as usize)
                else {
                    continue;
                };
                let trimmed = expr.trim();
                if trimmed.is_empty() {
                    continue;
                }
                if !any {
                    buf.push_str("\n");
                    any = true;
                }
                let inner = "    ".repeat(depth + 1);
                let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                let start = s.expression_range.start + leading_ws;
                let end = start + trimmed.len() as u32;
                let _ = write!(buf, "{inner}...");
                buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                let _ = writeln!(buf, ",");
            }
            // Directives (bind:, use:, class:, style:, transition:, …)
            // are handled outside createElement — by the existing bind/use
            // passes and by emit_dom_directive_checks.
            svn_parser::Attribute::Directive(_) => {}
        }
    }
    if any {
        let _ = writeln!(buf, "{indent}}});");
    } else {
        buf.push_str("}); ");
    }
}

/// Post-createElement directive checks for `class:` and `style:`
/// attributes. Emit each directive's value expression (or shorthand
/// identifier) as a bare statement inside the element's scoped block.
///
/// - `class:foo={cond}` / `class:foo` (shorthand) → `(cond);` or
///   `(foo);`. Type-checks the reference without constraining the
///   attribute slot.
/// - `style:prop={value}` / `style:color` (shorthand) → wraps the
///   value in `__svn_ensure_type(String, Number, value)` to validate
///   against the CSS-value union.
///
/// Mirrors upstream svelte2tsx's `Class.ts` and `StyleDirective.ts`
/// — directives aren't in the createElement attrs object; their
/// values are type-checked via bare statements in the surrounding
/// scoped block.
fn emit_dom_directive_checks(
    buf: &mut EmitBuffer,
    source: &str,
    attributes: &[svn_parser::Attribute],
    depth: usize,
) {
    let indent = "    ".repeat(depth);
    for attr in attributes {
        let svn_parser::Attribute::Directive(d) = attr else {
            continue;
        };
        match d.kind {
            svn_parser::DirectiveKind::Class => match &d.value {
                Some(svn_parser::DirectiveValue::Expression {
                    expression_range, ..
                }) => {
                    let Some(expr) =
                        source.get(expression_range.start as usize..expression_range.end as usize)
                    else {
                        continue;
                    };
                    let trimmed = expr.trim();
                    if trimmed.is_empty() {
                        continue;
                    }
                    let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                    let start = expression_range.start + leading_ws;
                    let end = start + trimmed.len() as u32;
                    let _ = write!(buf, "{indent}(");
                    buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                    let _ = writeln!(buf, ");");
                }
                _ => {
                    // Shorthand `class:foo` — type-check `foo` as an
                    // identifier reference.
                    let _ = writeln!(buf, "{indent}({name});", name = d.name.as_str());
                }
            },
            // Style directives: wrap the value in
            // `__svn_ensure_type(String, Number, <value>)` so it type-
            // checks against `String | Number | null | undefined`.
            // Mirrors upstream svelte2tsx's `handleStyleDirective` (at
            // `language-tools/packages/svelte2tsx/src/htmlxtojsx_v2/nodes/StyleDirective.ts:11-55`).
            // Fires TS2345 on non-stringish values and TS18046 /
            // TS7005 on reads of `unknown` / implicit-any bindings
            // inside the value expression — matching upstream's
            // diagnostics byte-for-byte on the CMS-bench component-
            // preview patterns.
            //
            // Two value shapes to handle:
            //   - `style:prop={expr}` — `DirectiveValue::Expression`,
            //     emit the trimmed expr verbatim as the 3rd arg.
            //   - `style:prop="…{expr}…"` — `DirectiveValue::Quoted`
            //     with an `AttrValue` carrying `Text`/`Expression`
            //     parts. Build a template literal from the parts and
            //     pass as the 3rd arg. Single-Text and single-Expression
            //     degenerate forms fall out of the template-literal
            //     branch naturally.
            svn_parser::DirectiveKind::Style => match &d.value {
                Some(svn_parser::DirectiveValue::Expression {
                    expression_range, ..
                }) => {
                    let Some(expr) =
                        source.get(expression_range.start as usize..expression_range.end as usize)
                    else {
                        continue;
                    };
                    let trimmed = expr.trim();
                    if trimmed.is_empty() {
                        continue;
                    }
                    let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                    let start = expression_range.start + leading_ws;
                    let end = start + trimmed.len() as u32;
                    let _ = write!(buf, "{indent}__svn_ensure_type(String, Number, ");
                    buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                    let _ = writeln!(buf, ");");
                }
                Some(svn_parser::DirectiveValue::Quoted(av)) => {
                    emit_style_directive_template_literal(buf, source, av, &indent);
                }
                _ => {}
            },
            _ => {}
        }
    }
}

/// Emit the template-literal form for a quoted
/// `style:prop="…{expr}…"` AttrValue. Produces
/// `__svn_ensure_type(String, Number, <template-literal>);` where the
/// template literal splices in each `Text` part verbatim (with
/// backticks, dollar-signs, and backslashes escaped) and each
/// `Expression` part as a `${…}` interpolation. Each expression
/// interpolation carries a TokenMapEntry covering the user-source
/// range so tsgo diagnostics fired inside map back to the correct
/// source position.
///
/// Degenerate cases (parts.len() == 1) fall out of the template-literal
/// branch naturally: a single-Expression part renders as an interp
/// with no surrounding text, which TS still type-checks against
/// `String | Number | null | undefined` via the generic constraint on
/// `__svn_ensure_type`. Upstream's `StyleDirective.ts` splits these
/// into three branches (single-Text, single-Expression, template); our
/// unified branch produces functionally equivalent emit.
fn emit_style_directive_template_literal(
    buf: &mut EmitBuffer,
    source: &str,
    av: &svn_parser::AttrValue,
    indent: &str,
) {
    if av.parts.is_empty() {
        return;
    }
    let _ = write!(buf, "{indent}__svn_ensure_type(String, Number, `");
    for part in &av.parts {
        match part {
            svn_parser::AttrValuePart::Text { content, .. } => {
                for ch in content.chars() {
                    match ch {
                        '`' => buf.push_str("\\`"),
                        '\\' => buf.push_str("\\\\"),
                        '$' => buf.push_str("\\$"),
                        _ => {
                            let mut b = [0u8; 4];
                            buf.push_str(ch.encode_utf8(&mut b));
                        }
                    }
                }
            }
            svn_parser::AttrValuePart::Expression {
                expression_range, ..
            } => {
                let Some(expr) =
                    source.get(expression_range.start as usize..expression_range.end as usize)
                else {
                    continue;
                };
                let trimmed = expr.trim();
                if trimmed.is_empty() {
                    continue;
                }
                let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                let start = expression_range.start + leading_ws;
                let end = start + trimmed.len() as u32;
                buf.push_str("${");
                buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                buf.push_str("}");
            }
        }
    }
    let _ = writeln!(buf, "`);");
}

/// Drop data-* attributes unconditionally: the svelte-jsx typings
/// reject any `data-foo` key at the strict interface, but real Svelte
/// allows them. Upstream wraps with `...__sveltets_2_empty({})` to
/// bypass; we'd need the same helper. Phase 1 skips rather than
/// regress.
fn dom_attr_should_skip(name: &str) -> bool {
    // Skip `data-*` (except sveltekit's typed ones), `aria-*` in
    // preserving-case form, and CSS custom properties. Conservative
    // skip — the goal is to avoid TS2353 regressions on real-world
    // attributes our declaration model doesn't cover in Phase 1.
    if name.starts_with("data-") || name.starts_with("aria-") {
        return true;
    }
    if name.starts_with("--") {
        return true;
    }
    // `xmlns`, `xml:lang`, `xlink:*` etc. are SVG specific; skip in
    // Phase 1 since svg element support needs its own namespace.
    if name.contains(':') {
        return true;
    }
    // `this` is a Svelte directive on `<svelte:element>` (selects the
    // tag) — its expression is consumed by emit_svelte_element_open
    // via the createElement first arg. Emitting it as an attr key
    // would fire a spurious TS2353 against the resolved tag's
    // HTMLAttributes shape.
    if name == "this" {
        return true;
    }
    // `slot="name"` assigns an element to a named slot of the parent
    // component. It's a Svelte directive that shouldn't appear in
    // the createElement attrs literal — upstream svelte2tsx strips it
    // from the createElement call and handles slot binding via
    // `$$slot_def["name"]`. Emitting it would fire TS2353 against
    // SVGAttributes shapes that don't declare `slot`.
    if name == "slot" {
        return true;
    }
    // React-style camelCase synonyms for HTML attributes (`tabIndex`,
    // `className`, `htmlFor`, `readOnly`, `maxLength`, etc.). Real
    // Svelte components frequently carry these (3rd-party-ported
    // patterns from React) but svelte-jsx only declares the
    // lowercase form. Upstream `svelte2tsx` doesn't filter them
    // either — but tsgo's diagnostic on the synthesized key is
    // dropped by upstream's source-map-driven filter for the same
    // reason ours did pre-token-mapping. Mirror that behavior
    // explicitly: real diagnostics on user-facing camelCase attrs
    // would also flag elsewhere (browser ignores them, Svelte
    // forwards as-is), so the skip is safe and matches upstream's
    // observable surface.
    if dom_attr_is_react_camelcase_synonym(name) {
        return true;
    }
    false
}

/// React-style camelCase HTML attribute names that have a lowercase
/// HTML5 counterpart. svelte-jsx declares only the lowercase form;
/// upstream silently drops these via source-map filtering.
fn dom_attr_is_react_camelcase_synonym(name: &str) -> bool {
    matches!(
        name,
        "tabIndex"
            | "className"
            | "htmlFor"
            | "readOnly"
            | "maxLength"
            | "minLength"
            | "colSpan"
            | "rowSpan"
            | "autoFocus"
            | "autoComplete"
            | "autoCorrect"
            | "autoCapitalize"
            | "spellCheck"
            | "contentEditable"
    )
}

/// Close the scoped block opened by `emit_dom_element_open`.
fn emit_dom_element_close(buf: &mut EmitBuffer, depth: usize) {
    let indent = "    ".repeat(depth);
    let _ = writeln!(buf, "{indent}}}");
}

/// Open a `svelteHTML.createElement` scoped block for a
/// `<svelte:*>` element. Dispatches on `SvelteElementKind`:
///   - Body/Head/Window/Document/Options/Fragment: literal
///     `"svelte:<name>"` tag string. IntrinsicElements in our
///     shim has these as named keys.
///   - Element: `<svelte:element this={expr}>` — pass the `this`
///     expression verbatim as the first createElement arg so TS
///     checks the tag against IntrinsicElements keys.
///   - SelfRef/Component/Boundary/missing-this: skip the
///     createElement scope (not DOM elements). Open a bare
///     `{ }` block so child emit still scopes locals correctly.
fn emit_svelte_element_open(
    buf: &mut EmitBuffer,
    source: &str,
    s: &svn_parser::SvelteElement,
    depth: usize,
    action_indices: &std::ops::Range<usize>,
) {
    use svn_parser::SvelteElementKind::*;
    let indent = "    ".repeat(depth);
    match s.kind {
        Body | Head | Window | Document | Options | Fragment => {
            let tag = format!("svelte:{}", s.kind.as_str());
            emit_dom_element_open(
                buf,
                source,
                &tag,
                true,
                &s.attributes,
                depth,
                action_indices,
            );
        }
        Element => {
            // Find `this={expr}` among attributes.
            let this_expr = s.attributes.iter().find_map(|a| {
                let svn_parser::Attribute::Expression(e) = a else {
                    return None;
                };
                if e.name.as_str() != "this" {
                    return None;
                }
                source
                    .get(e.expression_range.start as usize..e.expression_range.end as usize)
                    .map(str::trim)
                    .filter(|s| !s.is_empty())
                    .map(str::to_string)
            });
            match this_expr {
                Some(expr) => {
                    emit_dom_element_open(
                        buf,
                        source,
                        &format!("({expr})"),
                        false,
                        &s.attributes,
                        depth,
                        action_indices,
                    );
                }
                None => {
                    // Missing `this` — bare scope. Child emit still runs.
                    let _ = writeln!(buf, "{indent}{{");
                }
            }
        }
        SelfRef | Component | Boundary => {
            // Not a DOM element — bare scope for children.
            let _ = writeln!(buf, "{indent}{{");
        }
    }
}

/// Attributes that svelte-elements types as `number | undefined | null`.
/// Upstream svelte2tsx's `Attribute.ts::numberOnlyAttributes` — when
/// the attribute value is a pure-numeric Text (no `{expr}` interpolation),
/// emit the value as a bare number literal instead of a string template
/// so TS binds it against the typed number slot. Without this, e.g.
/// `<div tabindex="0">` emits `"tabindex": \`0\`` which fires TS2322
/// "Type 'string' is not assignable to type 'number'".
fn is_number_only_attr(name: &str) -> bool {
    matches!(
        name,
        "aria-colcount"
            | "aria-colindex"
            | "aria-colspan"
            | "aria-level"
            | "aria-posinset"
            | "aria-rowcount"
            | "aria-rowindex"
            | "aria-rowspan"
            | "aria-setsize"
            | "aria-valuemax"
            | "aria-valuemin"
            | "aria-valuenow"
            | "results"
            | "span"
            | "marginheight"
            | "marginwidth"
            | "maxlength"
            | "minlength"
            | "currenttime"
            | "defaultplaybackrate"
            | "volume"
            | "high"
            | "low"
            | "optimum"
            | "start"
            | "size"
            | "border"
            | "cols"
            | "rows"
            | "colspan"
            | "rowspan"
            | "tabindex"
    )
}

fn emit_dom_plain_attr(
    buf: &mut EmitBuffer,
    source: &str,
    p: &svn_parser::PlainAttr,
    depth: usize,
) {
    let indent = "    ".repeat(depth);
    let name = p.name.as_str();
    // Map the synthesized `"name"` key back to the user-source attribute
    // name. TS2353 "does not exist in type" pins on the property key;
    // without this token-map entry the diagnostic mapper drops the
    // diagnostic as falling outside any verbatim region.
    let name_range = svn_core::Range::new(p.range.start, p.range.start + name.len() as u32);
    let key_text = format!("\"{name}\"");
    match &p.value {
        None => {
            // Boolean attribute: `<input required>` → `"required": true,`
            // `<div popover>` carve-out: upstream emits `"": ""`.
            let value = if name == "popover" { "\"\"" } else { "true" };
            buf.push_str(&indent);
            buf.append_with_source(&key_text, name_range);
            let _ = writeln!(buf, ": {value},");
        }
        Some(v) if v.parts.is_empty() => {
            buf.push_str(&indent);
            buf.append_with_source(&key_text, name_range);
            buf.push_str(": \"\",\n");
        }
        Some(v) if v.parts.len() == 1 => {
            match &v.parts[0] {
                svn_parser::AttrValuePart::Text { content, .. } => {
                    // numberOnlyAttributes carve-out: emit bare number
                    // literal when the text parses as a number.
                    if is_number_only_attr(name)
                        && !content.is_empty()
                        && content.trim().parse::<f64>().is_ok()
                    {
                        buf.push_str(&indent);
                        buf.append_with_source(&key_text, name_range);
                        let _ = writeln!(buf, ": {},", content.trim());
                        return;
                    }
                    // Backtick template literal so the user source's
                    // quote style doesn't affect the check. Backticks
                    // in content force JSON escape fallback.
                    let escaped = content.replace('\\', "\\\\").replace('`', "\\`");
                    buf.push_str(&indent);
                    buf.append_with_source(&key_text, name_range);
                    let _ = writeln!(buf, ": `{escaped}`,");
                }
                svn_parser::AttrValuePart::Expression {
                    expression_range, ..
                } => {
                    let Some(expr) =
                        source.get(expression_range.start as usize..expression_range.end as usize)
                    else {
                        return;
                    };
                    let trimmed = expr.trim();
                    if trimmed.is_empty() {
                        return;
                    }
                    let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                    let start = expression_range.start + leading_ws;
                    let end = start + trimmed.len() as u32;
                    buf.push_str(&indent);
                    buf.append_with_source(&key_text, name_range);
                    buf.push_str(": (");
                    buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                    let _ = writeln!(buf, "),");
                }
            }
        }
        Some(v) => {
            // Multi-part (text + interpolations). Template literal
            // with `${expr}` placeholders so the whole attribute
            // binds as a string. Follows upstream Attribute.ts's
            // multi-value branch.
            buf.push_str(&indent);
            buf.append_with_source(&key_text, name_range);
            buf.push_str(": `");
            for part in &v.parts {
                match part {
                    svn_parser::AttrValuePart::Text { content, .. } => {
                        let escaped = content.replace('\\', "\\\\").replace('`', "\\`");
                        buf.push_str(&escaped);
                    }
                    svn_parser::AttrValuePart::Expression {
                        expression_range, ..
                    } => {
                        let Some(expr) = source
                            .get(expression_range.start as usize..expression_range.end as usize)
                        else {
                            continue;
                        };
                        let trimmed = expr.trim();
                        if trimmed.is_empty() {
                            continue;
                        }
                        let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
                        let start = expression_range.start + leading_ws;
                        let end = start + trimmed.len() as u32;
                        buf.push_str("${");
                        buf.append_with_source(trimmed, svn_core::Range::new(start, end));
                        buf.push_str("}");
                    }
                }
            }
            let _ = writeln!(buf, "`,");
        }
    }
}

fn emit_dom_expression_attr(
    buf: &mut EmitBuffer,
    source: &str,
    e: &svn_parser::ExpressionAttr,
    depth: usize,
) {
    let indent = "    ".repeat(depth);
    let Some(expr) = source.get(e.expression_range.start as usize..e.expression_range.end as usize)
    else {
        return;
    };
    let trimmed = expr.trim();
    if trimmed.is_empty() {
        return;
    }
    let leading_ws = (expr.len() - expr.trim_start().len()) as u32;
    let start = e.expression_range.start + leading_ws;
    let end = start + trimmed.len() as u32;
    let name = e.name.as_str();
    buf.push_str(&indent);
    // Map the synthesized `"name"` key back to the user-source attribute
    // name. tsgo reports excess-property TS2353 ("does not exist in
    // type") at the key position; without this token-map entry the
    // diagnostic mapper drops the diagnostic as falling outside any
    // verbatim region.
    let name_range = svn_core::Range::new(e.range.start, e.range.start + name.len() as u32);
    buf.append_with_source(&format!("\"{name}\""), name_range);
    buf.push_str(": (");
    buf.append_with_source(trimmed, svn_core::Range::new(start, end));
    let _ = writeln!(buf, "),");
}

fn emit_dom_shorthand_attr(
    buf: &mut EmitBuffer,
    source: &str,
    s: &svn_parser::ShorthandAttr,
    depth: usize,
) {
    let indent = "    ".repeat(depth);
    // Shorthand's identifier is emitted as bare `name,` — the
    // property-shorthand object literal form. Name must be a valid JS
    // identifier (it's a DOM attribute name like `value`, `type`).
    //
    // Map the synthesized identifier back to its source byte range
    // (just past the `{` and any whitespace) so TS2322 ("not
    // assignable to type") diagnostics — pinned by tsgo at the
    // shorthand reference position — survive the diagnostic mapper's
    // require-source-map-entry filter.
    let name = s.name.as_str();
    let inner = source
        .get(s.range.start as usize + 1..s.range.end as usize)
        .unwrap_or("");
    let leading_ws = (inner.len() - inner.trim_start().len()) as u32;
    let name_start = s.range.start + 1 + leading_ws;
    let name_end = name_start + name.len() as u32;
    buf.push_str(&indent);
    buf.append_with_source(name, svn_core::Range::new(name_start, name_end));
    buf.push_str(",\n");
}

/// Map a static HTML/SVG tag name to a `HTMLElementTagNameMap['tag']`
/// / `SVGElementTagNameMap['tag']` indexed-access type. Dynamic
/// tags (empty string) fall back to `HTMLElement`. Unknown tag
/// names that aren't in either map would resolve through these
/// indexed accesses to `any` — acceptable, just means the check
/// stays lax for custom elements.
fn element_type_annotation(tag_name: &str) -> String {
    if tag_name.is_empty() {
        return "HTMLElement".to_string();
    }
    // `HTMLElementTagNameMap` covers all standard HTML tags including
    // deprecated ones. TS's DOM lib dispatches at the type level; we
    // just pass the tag as a string-literal key.
    format!("HTMLElementTagNameMap['{tag_name}']")
}

/// Emit a `<Component ...>` node as a call to the component's typed
/// default export:
///
/// ```ts
///     ComponentRoot(__svn_any(), {
///         prop1: "lit",
///         prop2: (expr),
///         prop3,
///         prop4: true,
///         snippetName: (params) => {
///             <snippet body>
///             return __svn_snippet_return();
///         },
///     });
/// ```
///
/// The callable shape is what makes TypeScript's contextual typing
/// work here. The component's `.svelte.ts` overlay exports a
/// `declare function __svn_component_default(anchor, props: Props)`;
/// each prop slot's declared type flows into the consumer's expression
/// at this call site. Callback props destructure the right parameter
/// types (`onchange={({ checked }) => ...}` binds `checked: boolean`
/// instead of implicit-any), snippet props pick up `Snippet<[...]>`
/// contextual types for their arrow parameters, and excess properties
/// fire TS2353 thanks to object-literal inference strictness.
///
/// Directive-attached props (`bind:value`, `on:click`, `use:action`,
/// `class:active`, etc.) and spreads are skipped at analyze time — they
/// don't contribute to the callable's props argument. `__svn_any()`
/// returns a fresh `any`; the first argument slot simulates Svelte's
/// mount-anchor parameter without constraining inference.
///
/// Non-snippet children (text, elements, nested components, blocks) are
/// walked AFTER the call-site scaffolding in the component's own scope.
/// Direct-child `{#snippet name(params)}` blocks ARE consumed as props
/// on the object literal — not walked a second time — so their param
/// destructures pick up contextual types from the parent's Snippet prop
/// shape instead of reading as implicit-any.
fn emit_component_node(
    buf: &mut EmitBuffer,
    source: &str,
    c: &svn_parser::Component,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let snippet_children: Vec<&SnippetBlock> = c
        .children
        .nodes
        .iter()
        .filter_map(|n| match n {
            Node::SnippetBlock(b) => Some(b),
            _ => None,
        })
        .collect();

    let inst = insts.get(&c.range.start);
    // SVELTE-4-COMPAT: `<Foo let:item on:click={() => item.x}>` passes
    // `item` inside the `onclick` prop expression. The slot-let
    // binding must be in scope BEFORE emit_component_call runs, so
    // open the block scope + declare let-bindings up front, then
    // emit the call + children inside.
    let let_names = collect_let_directive_names(source, &c.attributes);
    let (indent, inner_depth) = if let_names.is_empty() {
        (String::new(), depth)
    } else {
        let indent = "    ".repeat(depth);
        let inner = "    ".repeat(depth + 1);
        let _ = writeln!(buf, "{indent}{{");
        for name in &let_names {
            let _ = writeln!(buf, "{inner}let {name}: any;");
            let _ = writeln!(buf, "{inner}void {name};");
        }
        (indent, depth + 1)
    };

    // Only emit the call when analyze collected an instantiation for
    // this node. Components disqualified at analyze time (e.g.
    // multi-part interpolated attribute values) fall back to a plain
    // template-body walk so snippet hoists still emit there.
    if let Some(inst) = inst {
        emit_component_call(
            buf,
            source,
            inst,
            inner_depth,
            &snippet_children,
            insts,
            action_counter,
        );
    }

    if inst.is_none() || snippet_children.is_empty() {
        // Walk children at the same let-binding scope depth.
        for node in &c.children.nodes {
            emit_template_node(buf, source, node, inner_depth, insts, action_counter);
        }
        if !let_names.is_empty() {
            let _ = writeln!(buf, "{indent}}}");
        }
        return;
    }
    // Snippet children consumed as props above — walk the rest.
    for node in &c.children.nodes {
        if matches!(node, Node::SnippetBlock(_)) {
            continue;
        }
        emit_template_node(buf, source, node, inner_depth, insts, action_counter);
    }
    if !let_names.is_empty() {
        let _ = writeln!(buf, "{indent}}}");
    }
}

/// Emit the call-site scaffolding for one component instantiation as
///
/// ```text
/// { const $$_CN = __svn_ensure_component(Comp);
///   new $$_CN({ target: __svn_any(), props: { ... } }); }
/// ```
///
/// — the wrapper + local + `new` form chosen so a single emission
/// handles both our overlay-declared class defaults and third-party
/// `extends SvelteComponent` classes (and bare `Component<Props>`
/// values from user-typed contexts). The intermediate local is what
/// makes generic components' `<T>` resolve at the `new` site — TS
/// binds the construct signature's generics against the concrete prop
/// values there, not at the `__svn_ensure_component` site. See
/// design/phase_a/DESIGN.md for the validation.
///
/// Each instantiation gets its own block scope `{ ... }` so the
/// synthesized `$$_CN` local is siloed from sibling instantiations —
/// avoids shadowing / redeclaration when the same parent fragment
/// contains multiple components.
fn emit_component_call(
    buf: &mut EmitBuffer,
    source: &str,
    inst: &svn_analyze::ComponentInstantiation,
    depth: usize,
    snippet_children: &[&SnippetBlock],
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let indent = "    ".repeat(depth);
    let inner = "    ".repeat(depth + 1);
    let comp = &inst.component_root;
    // Per-call-site synthesized locals. Using the instantiation's byte
    // offset keeps each one unique without threading a counter through
    // the walker. `C_*` holds the ensured-component class; `inst_*` is
    // the instance returned by `new C_*({...})`. Hoisted into a named
    // local when one of the post-construction emits needs it:
    //   - `$inst.$on("evt", h)` per `on:event` directive
    //   - `x = $inst;` for `bind:this={x}` on the component
    let local = format!("__svn_C_{:x}", inst.node_start);
    let inst_local = format!("__svn_inst_{:x}", inst.node_start);
    let hoist_instance = !inst.on_events.is_empty() || inst.bind_this_target.is_some();
    let ctor_lhs = if hoist_instance {
        format!("const {inst_local} = ")
    } else {
        String::new()
    };

    let _ = writeln!(buf, "{indent}{{");
    let _ = writeln!(
        buf,
        "{inner}const {local} = __svn_ensure_component({comp});"
    );

    // Implicit-children synthesis: when the user has non-snippet
    // body content, inject `"children": () => __svn_snippet_return()`
    // into the props literal. Matches upstream svelte2tsx's behavior
    // (`component.addProp(['children'], ['() => __sveltets_2_any(0)'])`)
    // so components declaring `children: Snippet` (required) accept
    // `<Comp>body</Comp>` without a TS2741 at the phase-5 satisfies
    // trailer.
    //
    // Skipped when the user explicitly named a `children` prop OR
    // wrote a `{#snippet children}` block — both paths already emit
    // a `children:` key in the props literal; a second synthesis
    // would fire TS1117 "duplicate property".
    let user_named_children = inst
        .props
        .iter()
        .any(|p| prop_shape_name(p).is_some_and(|n| n == "children"));
    let user_named_children_snippet = snippet_children
        .iter()
        .any(|s| s.name.as_str() == "children");
    let emit_implicit_children =
        inst.has_implicit_children && !user_named_children && !user_named_children_snippet;

    // Missing-required-prop detection is structural at the `new
    // __svn_C({props: {...}})` site: ensure_component's return has
    // `props?: P` (exact, no Partial) so `{}` missing required fields
    // fires TS2741 directly. Matches upstream svelte2tsx's
    // `InlineComponent.ts:96-115` shape (verified against real
    // svelte2tsx output on `language-tools/packages/svelte-check/
    // test-error/Index.svelte`).
    //
    // Earlier `satisfies InstanceType<typeof __svn_C>['$$prop_def']`
    // trailer was a workaround for `__SvnPropsPartial<P>` erasing
    // required props. The shim rewritten to exact `P` lets TS2741
    // surface with the right code at the `new` site. The post-walk
    // `collect_satisfies_token_map` (kept the name for history) now
    // scans `new __svn_C_<hex>(...)` calls and maps them back to the
    // `<Comp` tag position, so TS2741 lands at col 1 (the component-
    // name start) matching upstream's expected position.

    if snippet_children.is_empty() && inst.props.is_empty() && !emit_implicit_children {
        let _ = write!(buf, "{inner}{ctor_lhs}");
        let call_start = buf.len() as u32;
        let _ = write!(buf, "new {local}({{ target: __svn_any(), props: {{}} }})");
        push_component_call_token_map(buf, call_start, inst.node_start);
        buf.push_str(";\n");
        emit_component_bind_widen_trailers(buf, inst, &inner);
        emit_bind_this_assignment(buf, source, inst, &inst_local, &inner);
        emit_on_event_calls(buf, source, inst, &inst_local, &inner);
        let _ = writeln!(buf, "{indent}}}");
        return;
    }

    if snippet_children.is_empty() {
        let _ = write!(buf, "{inner}{ctor_lhs}");
        let call_start = buf.len() as u32;
        let _ = write!(buf, "new {local}({{ target: __svn_any(), props: {{");
        let mut first = true;
        for p in &inst.props {
            if !first {
                let _ = write!(buf, ", ");
            }
            first = false;
            write_prop_shape(buf, source, p);
        }
        if emit_implicit_children {
            if !first {
                let _ = write!(buf, ", ");
            }
            let _ = write!(buf, "children: () => __svn_snippet_return()");
        }
        let _ = write!(buf, "}} }})");
        push_component_call_token_map(buf, call_start, inst.node_start);
        buf.push_str(";\n");
        emit_component_bind_widen_trailers(buf, inst, &inner);
        emit_bind_this_assignment(buf, source, inst, &inst_local, &inner);
        emit_on_event_calls(buf, source, inst, &inst_local, &inner);
        let _ = writeln!(buf, "{indent}}}");
        return;
    }

    // Multi-line form with snippets-as-arrow-props.
    let _ = write!(buf, "{inner}{ctor_lhs}");
    let call_start = buf.len() as u32;
    let _ = writeln!(buf, "new {local}({{");
    let opts_inner = "    ".repeat(depth + 2);
    let props_inner = "    ".repeat(depth + 3);
    let _ = writeln!(buf, "{opts_inner}target: __svn_any(),");
    let _ = writeln!(buf, "{opts_inner}props: {{");
    for p in &inst.props {
        buf.push_str(&props_inner);
        write_prop_shape(buf, source, p);
        let _ = writeln!(buf, ",");
    }
    for s in snippet_children {
        buf.push_str(&props_inner);
        write_snippet_arrow_prop(buf, source, s, depth + 3, insts, action_counter);
        let _ = writeln!(buf, ",");
    }
    // Implicit children and explicit snippet children are mutually
    // exclusive in practice — the user wrote either one or the other
    // — but defensively emit only when we haven't already covered it
    // via `snippet_children` above.
    if emit_implicit_children {
        buf.push_str(&props_inner);
        let _ = writeln!(buf, "children: () => __svn_snippet_return(),");
    }
    let _ = writeln!(buf, "{opts_inner}}},");
    let _ = write!(buf, "{inner}}})");
    push_component_call_token_map(buf, call_start, inst.node_start);
    buf.push_str(";\n");
    emit_component_bind_widen_trailers(buf, inst, &inner);
    emit_bind_this_assignment(buf, source, inst, &inst_local, &inner);
    emit_on_event_calls(buf, source, inst, &inst_local, &inner);
    let _ = writeln!(buf, "{indent}}}");
}

/// Emit `void (() => { TARGET = __svn_any(null); });` after the
/// component's `new` expression for each simple-identifier
/// `bind:NAME={TARGET}` on this instantiation. TS flow analysis sees
/// the assignment inside the uncalled arrow and widens TARGET's
/// inferred type to `any` — models the Svelte runtime's async prop
/// writeback that TS can't see statically. Without this, `let target
/// = $state()` targets stay narrowed to `{}` / `unknown` and
/// downstream reads like `target.focus()` fire TS2339 / TS18046.
///
/// Mirrors upstream svelte2tsx's `() => x = __sveltets_2_any(null);`
/// trailer (emitted inside `/*Ωignore_startΩ*/…/*Ωignore_endΩ*/`
/// markers there, stripped by svelte-check before reporting to the
/// user). Wrapping in a `void (...)` expression here serves the same
/// role: TS type-checks the body but the expression statement
/// itself produces no diagnostic (the assignment is always valid
/// because `__svn_any(null)` returns `any`).
fn emit_component_bind_widen_trailers(
    buf: &mut EmitBuffer,
    inst: &svn_analyze::ComponentInstantiation,
    inner: &str,
) {
    for target in &inst.component_bind_widen_targets {
        // Wrap in ignore-region markers so any diagnostic firing
        // inside this purely-synthetic trailer is filtered out at
        // mapping time. The trailer is emit scaffolding — the user
        // didn't write it and has no ability to fix anything
        // reported here. Mirrors upstream svelte2tsx's
        // `/*Ωignore_startΩ*/ () => target = __sveltets_2_any(null);
        // /*Ωignore_endΩ*/` shape.
        let _ = writeln!(
            buf,
            "{inner}/*svn:ignore_start*/void (() => {{ {target} = __svn_any(null); }});/*svn:ignore_end*/"
        );
    }
}

/// Push a TokenMapEntry for a `new __svn_C_<hex>(...)` component call.
/// Source range is the 1-byte span at `node_start+1` — the first char
/// of the component name after `<`. `translate_position`'s end-clamp
/// collapses any overlay byte inside the call to this single position,
/// which is the column upstream TS reports TS2741 at. Replaces the
/// former post-walk `collect_satisfies_token_map` scanner.
fn push_component_call_token_map(buf: &mut EmitBuffer, call_start: u32, node_start: u32) {
    let call_end = buf.len() as u32;
    let source_start = node_start.saturating_add(1);
    let source_end = source_start.saturating_add(1);
    buf.push_token_map(TokenMapEntry {
        overlay_byte_start: call_start,
        overlay_byte_end: call_end,
        source_byte_start: source_start,
        source_byte_end: source_end,
    });
}

/// Extract the NAME from a `PropShape`, if it has one (spreads
/// don't — they're positional). Used at emit time to detect whether
/// the user explicitly named a prop we'd otherwise synthesize
/// (e.g. `children`).
fn prop_shape_name(p: &svn_analyze::PropShape) -> Option<&str> {
    match p {
        svn_analyze::PropShape::Literal { name, .. }
        | svn_analyze::PropShape::Expression { name, .. }
        | svn_analyze::PropShape::Shorthand { name }
        | svn_analyze::PropShape::BoolShorthand { name }
        | svn_analyze::PropShape::GetSetBinding { name, .. } => Some(name),
        svn_analyze::PropShape::Spread { .. } => None,
    }
}

/// Emit one `$inst.$on("event", (handler))` line per `on:event`
/// directive on this component. No-op when `inst.on_events` is empty —
/// in that case the caller also skips hoisting the instance into a
/// local, so there's no local to reference.
///
/// Mirrors upstream svelte2tsx's shape (`$inst.$on("click", fn)` after
/// `new $C(...)`). Handler expression type-checks against the
/// component's declared `Events` record via
/// `SvelteComponent<Props, Events, Slots>.$on`'s signature — Svelte's
/// own typing chain, no special-casing needed on our side.
fn emit_on_event_calls(
    buf: &mut EmitBuffer,
    source: &str,
    inst: &svn_analyze::ComponentInstantiation,
    inst_local: &str,
    inner: &str,
) {
    for ev in &inst.on_events {
        let expr = &source[ev.handler_range.start as usize..ev.handler_range.end as usize];
        let name = &ev.event_name;
        // Splice the handler expression via append_with_source so the
        // TokenMapEntry (handler-overlay-span → handler_range) lands at
        // emit time — replaces the former post-walk
        // `collect_on_event_token_map` scanner that paired Nth
        // `__svn_inst_<hex>.$on(...)` occurrences with inst.on_events[N].
        let _ = write!(buf, "{inner}{inst_local}.$on(\"{name}\", (");
        buf.append_with_source(expr, ev.handler_range);
        buf.push_str("));\n");
    }
}

/// Emit a `<EXPR> = $inst;` assignment for `bind:this={EXPR}` on a
/// component. EXPR is the verbatim user-source range — covers both
/// simple-identifier (`bind:this={refs}`) and member-expression
/// (`bind:this={refs.instance}`) forms.
///
/// For simple identifiers the declaration-site `!` rewrite (via the
/// `bind_this_targets` collection) handles definite-assignment;
/// member expressions don't have a declaration to rewrite, but the
/// assignment itself provides the async-bind contract and the
/// type-check (LHS accepts RHS = component instance type).
///
/// No-op when the instantiation has no `bind:this` — the caller also
/// skips hoisting the instance into a local in that case, so there's
/// nothing to assign.
fn emit_bind_this_assignment(
    buf: &mut EmitBuffer,
    source: &str,
    inst: &svn_analyze::ComponentInstantiation,
    inst_local: &str,
    inner: &str,
) {
    if let Some(range) = &inst.bind_this_target {
        let Some(expr) = source.get(range.start as usize..range.end as usize) else {
            return;
        };
        let expr = expr.trim();
        if expr.is_empty() {
            return;
        }
        let _ = writeln!(buf, "{inner}{expr} = {inst_local};");
    }
}

/// Write a single property of a component-prop-check object literal,
/// dispatching on the analyze-side `PropShape` variant.
fn write_prop_shape(buf: &mut EmitBuffer, source: &str, p: &svn_analyze::PropShape) {
    match p {
        svn_analyze::PropShape::Literal { name, value } => {
            write_quoted_prop_key(buf, name);
            buf.push_str(": ");
            write_js_string_literal(buf, value);
        }
        svn_analyze::PropShape::Expression { name, expr_range } => {
            let expr = &source[expr_range.start as usize..expr_range.end as usize];
            write_quoted_prop_key(buf, name);
            let _ = write!(buf, ": ({expr})");
        }
        svn_analyze::PropShape::Shorthand { name } => {
            // `{foo}` shorthand is only valid when the key is also a
            // valid JS identifier — otherwise expand to `"foo": foo`.
            if is_simple_js_identifier(name) {
                buf.push_str(name);
            } else {
                write_quoted_prop_key(buf, name);
                let _ = write!(buf, ": {name}");
            }
        }
        svn_analyze::PropShape::BoolShorthand { name } => {
            write_quoted_prop_key(buf, name);
            buf.push_str(": true");
        }
        svn_analyze::PropShape::Spread { expr_range } => {
            let expr = &source[expr_range.start as usize..expr_range.end as usize];
            // Wrap the expression in parens so things like ternaries
            // or `a, b` sequences stay a single operand of `...`.
            let _ = write!(buf, "...({expr})");
        }
        svn_analyze::PropShape::GetSetBinding {
            name,
            getter_range,
            setter_range,
        } => {
            let getter = &source[getter_range.start as usize..getter_range.end as usize];
            let setter = &source[setter_range.start as usize..setter_range.end as usize];
            write_quoted_prop_key(buf, name);
            // Svelte 5 `bind:name={get, set}` — emit through the
            // `__svn_get_set_binding(get, set)` helper so TS infers
            // `T` from the getter's return, checks the setter's
            // parameter against `T`, and flows the return out to the
            // prop slot. Mirrors upstream's `__sveltets_2_get_set_binding`
            // (svelte2tsx/src/htmlxtojsx_v2/nodes/Binding.ts:179).
            // See design/get_set_binding/ for the tsgo-locked fixture.
            let _ = write!(buf, ": __svn_get_set_binding({getter}, {setter})");
        }
    }
}

/// Always-quote variant of `write_object_key` for component prop
/// keys. Matches upstream svelte2tsx's component-instantiation prop
/// emit (`new __$$_C({ target, props: { "name": value } })`), so
/// tsgo's TS2353 ("does not exist in type") echoes the property key
/// as `'"name"'` (the literal form) rather than `'name'` (bare-ident
/// form). The quote-style change lets diagnostics with the same
/// semantics tally as matches against upstream.
fn write_quoted_prop_key(buf: &mut EmitBuffer, name: &str) {
    write_js_string_literal(buf, name);
}

/// Split `params_text` on top-level commas and, for each part that
/// doesn't already carry a top-level type annotation, append `: any`.
/// "Top-level" here means depth 0 in balanced `()`, `[]`, `{}`, `<>` —
/// so object-destructure patterns like `{ a, b }` are treated as one
/// unannotated part (inner `:` colons are inside braces) and get
/// `{ a, b }: any` appended.
///
/// Used only by top-level `{#snippet}` blocks whose params have no
/// parent `Snippet<[...]>` contextual type to flow from. Snippets
/// consumed as direct children of a `<Component>` go through
/// `write_snippet_arrow_prop`, which uses the parent's declared prop
/// type via the callable component shape and therefore doesn't need
/// explicit `: any` annotations.
fn annotate_snippet_params(params_text: &str) -> String {
    let bytes = params_text.as_bytes();
    let mut parts: Vec<(usize, usize)> = Vec::new();
    let mut depth = 0i32;
    let mut start = 0;
    for (i, &b) in bytes.iter().enumerate() {
        match b {
            b'(' | b'[' | b'{' | b'<' => depth += 1,
            b')' | b']' | b'}' | b'>' if depth > 0 => depth -= 1,
            b',' if depth == 0 => {
                parts.push((start, i));
                start = i + 1;
            }
            _ => {}
        }
    }
    parts.push((start, bytes.len()));

    let mut out = String::with_capacity(params_text.len() + 16);
    let mut first = true;
    for (s, e) in parts {
        if !first {
            out.push_str(", ");
        }
        first = false;
        let part = params_text[s..e].trim();
        if part.is_empty() {
            continue;
        }
        let part_bytes = part.as_bytes();
        let mut d = 0i32;
        let mut has_top_colon = false;
        for &b in part_bytes {
            match b {
                b'(' | b'[' | b'{' | b'<' => d += 1,
                b')' | b']' | b'}' | b'>' if d > 0 => d -= 1,
                b':' if d == 0 => {
                    has_top_colon = true;
                    break;
                }
                _ => {}
            }
        }
        out.push_str(part);
        if !has_top_colon {
            if let Some(eq) = find_top_level_eq(part) {
                let before = part[..eq].trim_end();
                let after = &part[eq..];
                out.truncate(out.len() - part.len());
                out.push_str(before);
                out.push_str(": any ");
                out.push_str(after);
            } else {
                out.push_str(": any");
            }
        }
    }
    out
}

/// First top-level `=` in `s`, or `None`. Skips `==` / `===` / `=>`.
fn find_top_level_eq(s: &str) -> Option<usize> {
    let bytes = s.as_bytes();
    let mut d = 0i32;
    for (i, &b) in bytes.iter().enumerate() {
        match b {
            b'(' | b'[' | b'{' | b'<' => d += 1,
            b')' | b']' | b'}' | b'>' if d > 0 => d -= 1,
            b'=' if d == 0 => {
                let next = bytes.get(i + 1).copied();
                if next == Some(b'=') || next == Some(b'>') {
                    continue;
                }
                return Some(i);
            }
            _ => {}
        }
    }
    None
}

/// Write a `{#snippet name(params)}...{/snippet}` block as an
/// arrow-callback property value on the parent component's call-site
/// props object:
///
/// ```ts
///     name: (params) => {
///         <snippet body>
///         return __svn_snippet_return();
///     }
/// ```
///
/// The parameter text is spliced verbatim from the source — that
/// preserves user-provided type annotations, destructure patterns, and
/// default values. TypeScript's contextual typing reads the parent
/// component's declared `Snippet<[...]>` parameter shape through the
/// call signature's props slot and flows each tuple element into the
/// matching arrow parameter, so destructured snippet params pick up
/// real types instead of implicit-any. Parents that type their snippet
/// prop as `Snippet<[any]>` (or parents with no type annotation at all)
/// produce `any`-typed params, which is the correct "silently accept"
/// degradation.
///
/// No more per-parameter `: any` injection. The old satisfies-shape
/// lost the contextual type through `Partial<ComponentProps<typeof X>>`
/// extraction, forcing us to explicitly annotate each param. The
/// callable shape flows the type directly, so a user-written
/// `(x: string)` or an un-annotated `(item)` both type correctly.
///
/// `__svn_snippet_return()` returns `any`, which structurally satisfies
/// the opaque branded return type Svelte's `Snippet<[...]>` expects.
/// The closing `}` is written without a trailing newline so the caller
/// can append `,\n` at the property-value column.
fn write_snippet_arrow_prop(
    buf: &mut EmitBuffer,
    source: &str,
    s: &SnippetBlock,
    depth: usize,
    insts: &std::collections::HashMap<u32, &svn_analyze::ComponentInstantiation>,
    action_counter: &mut usize,
) {
    let indent = "    ".repeat(depth);
    let body_indent = "    ".repeat(depth + 1);
    let params_text = source
        .get(s.parameters_range.start as usize..s.parameters_range.end as usize)
        .unwrap_or("")
        .trim();
    write_object_key(buf, &s.name);
    if params_text.is_empty() {
        let _ = writeln!(buf, ": () => {{");
        emit_template_body(buf, source, &s.body, depth + 1, insts, action_counter);
        let _ = writeln!(buf, "{body_indent}return __svn_snippet_return();");
        let _ = write!(buf, "{indent}}}");
        return;
    }
    let _ = writeln!(buf, ": ({params_text}) => {{");
    emit_template_body(buf, source, &s.body, depth + 1, insts, action_counter);
    for ident in all_identifiers(params_text) {
        let _ = writeln!(buf, "{body_indent}void {ident};");
    }
    let _ = writeln!(buf, "{body_indent}return __svn_snippet_return();");
    let _ = write!(buf, "{indent}}}");
}

/// Write an object-literal key. Plain JS identifiers are emitted bare;
/// anything with a hyphen, a non-ident character, or a JS reserved
/// word lookalike is double-quoted (always safe).
fn write_object_key(buf: &mut EmitBuffer, name: &str) {
    if is_simple_js_identifier(name) {
        buf.push_str(name);
    } else {
        write_js_string_literal(buf, name);
    }
}

/// True for ASCII identifiers `[A-Za-z_$][A-Za-z0-9_$]*`. We don't try
/// to enumerate JS reserved words — modern JS (ES5+) allows reserved
/// words as bare property names anyway.
fn is_simple_js_identifier(s: &str) -> bool {
    let mut chars = s.chars();
    let Some(first) = chars.next() else {
        return false;
    };
    if !(first.is_ascii_alphabetic() || first == '_' || first == '$') {
        return false;
    }
    chars.all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '$')
}

/// Write `value` as a JS double-quoted string literal, escaping the
/// usual unsafe characters. Pure ASCII assumption — Svelte attribute
/// values are decoded earlier in the pipeline.
fn write_js_string_literal(buf: &mut EmitBuffer, value: &str) {
    buf.push('"');
    for c in value.chars() {
        match c {
            '"' => buf.push_str("\\\""),
            '\\' => buf.push_str("\\\\"),
            '\n' => buf.push_str("\\n"),
            '\r' => buf.push_str("\\r"),
            '\t' => buf.push_str("\\t"),
            c if (c as u32) < 0x20 => {
                let _ = write!(buf, "\\u{:04x}", c as u32);
            }
            c => buf.push(c),
        }
    }
    buf.push('"');
}

/// Emit getter/setter tuple placeholders for `bind:foo={getter, setter}`.
/// Same pattern as action-attrs: declare + void inside `__svn_tpl_check`.
fn emit_bind_pair_declarations(out: &mut String, summary: &TemplateSummary, is_ts: bool) {
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_bind_pair_") {
            if is_ts {
                let _ = writeln!(
                    out,
                    "        let {name}: [() => any, (v: any) => void] = [() => undefined as any, () => {{}}];"
                );
            } else {
                let _ = writeln!(
                    out,
                    "        /** @type {{[() => any, (v: any) => void]}} */ let {name} = [() => undefined, () => {{}}];"
                );
            }
            let _ = writeln!(out, "        void {name};");
        }
    }
}

fn emit_void_block(
    out: &mut String,
    summary: &TemplateSummary,
    store_refs: &[SmolStr],
    prop_names: &[SmolStr],
    template_refs: &[SmolStr],
    exported_locals: &[SmolStr],
    is_ts: bool,
) {
    // One `void <name>;` statement per synthesized name — NOT a single
    // `void (a, b, c);` block. The block form uses comma operators which
    // TypeScript flags with TS2695 ("Left side of comma operator is
    // unused and has no side effects"). Per-statement form has no such
    // problem and matches what upstream svelte-check does.
    //
    // Names covered:
    //   - the template-check wrapper (`__svn_tpl_check`)
    //   - store auto-subscribe aliases
    //   - destructured props (the component's public API; treat as used
    //     even if the body doesn't reference them directly)
    //   - script-declared bindings that are referenced from the template
    //     (component imports, locals only used in markup)
    //
    // NOT covered here (intentionally): `__svn_action_attrs_N` and
    // `__svn_bind_pair_N`. Those names are declared *inside* the inner
    // `__svn_tpl_check` function and self-voided there. Voiding them in
    // the outer scope as well would fire TS2304 (cannot find name) since
    // the inner declarations aren't visible from the outer function.
    let mut emitted: HashSet<String> = HashSet::new();
    let mut emit = |out: &mut String, name: &str| {
        if emitted.insert(name.to_string()) {
            let _ = writeln!(out, "    void {name};");
        }
    };
    for name in summary.void_refs.names() {
        if name.starts_with("__svn_action_attrs_") || name.starts_with("__svn_bind_pair_") {
            continue;
        }
        // JS overlays skip `emit_template_check_fn` (TS-only casts), so
        // the `__svn_tpl_check` name never materializes — voiding it
        // would fire TS2304. Every other synthesized name still applies.
        if !is_ts && name == "__svn_tpl_check" {
            continue;
        }
        emit(out, name);
    }
    for name in store_refs {
        emit(out, name);
        // The auto-subscribe alias `$store` references the store, but the
        // underlying `store` const is itself only used in template
        // expressions like `$store` (which the alias receives). Void the
        // base name so TS6133 doesn't fire on the original declaration.
        if let Some(base) = name.strip_prefix('$') {
            emit(out, base);
        }
    }
    for name in prop_names {
        emit(out, name);
    }
    for name in template_refs {
        emit(out, name);
    }
    // Names declared `export const|let|var|function|class` (or
    // `export { x }`) by the user. Stripping the `export` keyword leaves
    // them as plain locals — without voiding, TS6133 fires on the
    // declaration. The user explicitly marked them as public surface so
    // counting them as "used" is the right call.
    for name in exported_locals {
        emit(out, name);
    }
}

/// Pull every identifier-like token out of a destructuring pattern.
///
/// For `id`             → `["id"]`
/// For `[id, label]`    → `["id", "label"]`
/// For `[id, { label }]` → `["id", "label"]`
/// For `{ a: x, b }`    → `["x", "b"]` (only the local-name side of `key:value`)
///
/// Best-effort byte scan — the analyze crate has a real oxc-backed
/// destructuring walk for the *script* path; this helper handles the
/// far smaller set of shapes that appear inside `{#each ... as <pat>}`
/// without the cost of an oxc invocation per each-block.
///
/// Falls back to a single `__svn_each_unused` token when nothing
/// identifier-shaped is found, so the emitted `void` line stays valid.
fn all_identifiers(binding: &str) -> Vec<String> {
    let bytes = binding.as_bytes();
    let mut out: Vec<String> = Vec::new();
    let mut i = 0;
    let mut depth_brace = 0usize; // tracks `{ ... }` for object key:value
    while i < bytes.len() {
        let b = bytes[i];
        match b {
            b'{' => {
                depth_brace += 1;
                i += 1;
            }
            b'}' => {
                depth_brace = depth_brace.saturating_sub(1);
                i += 1;
            }
            b'?' if depth_brace == 0 => {
                // Optional-parameter marker in TS snippet params: `name?:
                // Type`. No-op; the following `:` handles the type skip.
                // Each-block `as` clauses don't use `?`, so this branch
                // is inert for that caller.
                i += 1;
            }
            b':' if depth_brace == 0 => {
                // Top-level `:` on a snippet parameter introduces a TS
                // type annotation (`name: Foo<Bar>`). Skip until the
                // next top-level `,` — tracking paren/bracket/brace/
                // angle nesting so commas inside `Array<A, B>` or
                // `(a: X) => Y` don't terminate the annotation early.
                // Each-block `as` clauses never hit this (Svelte grammar
                // forbids type annotations on destructure targets).
                i += 1;
                let mut depth = 0usize;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' | b'<' => depth += 1,
                        b')' | b']' | b'}' | b'>' if depth > 0 => depth -= 1,
                        b',' if depth == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
            }
            b'=' => {
                // Skip default value `name = expr` — advance past expr to
                // the next comma/closer at the same depth. Conservative:
                // just stop collecting until we see `,` `]` `}`.
                i += 1;
                let mut paren = 0usize;
                while i < bytes.len() {
                    match bytes[i] {
                        b'(' | b'[' | b'{' => paren += 1,
                        b')' | b']' | b'}' if paren > 0 => paren -= 1,
                        b',' | b']' | b'}' if paren == 0 => break,
                        _ => {}
                    }
                    i += 1;
                }
            }
            _ if b.is_ascii_alphabetic() || b == b'_' || b == b'$' => {
                let start = i;
                while i < bytes.len() {
                    let c = bytes[i];
                    if c.is_ascii_alphanumeric() || c == b'_' || c == b'$' {
                        i += 1;
                    } else {
                        break;
                    }
                }
                let name = &binding[start..i];
                let take = if depth_brace > 0 {
                    // Inside an object pattern: `key: local` — only collect
                    // the local. `{ a }` shorthand has no colon so `a`
                    // counts. Look ahead: if the next non-ws byte is `:`,
                    // this identifier is a key and must be skipped;
                    // otherwise it is a binding (either the local after
                    // a colon, or a shorthand entry).
                    let mut j = i;
                    while j < bytes.len() && bytes[j].is_ascii_whitespace() {
                        j += 1;
                    }
                    bytes.get(j) != Some(&b':')
                } else {
                    true
                };
                if take {
                    out.push(name.to_string());
                }
            }
            _ => {
                i += 1;
            }
        }
    }
    if out.is_empty() {
        out.push("__svn_each_unused".to_string());
    }
    out
}

/// Rewrite `let <name>: T;` → `let <name>!: T;` for each bind-target
/// identifier, in-place inside the already-built output buffer.
///
/// Svelte assigns a `bind:this` target asynchronously, after the binding
/// element mounts. TypeScript's flow analysis can't see that, so any
/// closure reading the variable would be flagged "used before being
/// assigned" (TS2454). The `!:` definite-assignment assertion tells
/// TypeScript to trust us.
///
/// Only matches `let <name>:` patterns with the colon — declarations with
/// initializers (`let x = ...`) are already definitely assigned and don't
/// need the `!`. Adding `!` to an initialized declaration is itself a TS
/// error (TS1263).
fn rewrite_definite_assignment_in_place(out: &mut String, target_names: &[SmolStr]) {
    if target_names.is_empty() {
        return;
    }
    let original = std::mem::take(out);
    let bytes = original.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if let Some((stmt_end, insertions)) = try_process_let_statement(bytes, i, target_names) {
            // Emit the let statement with `!` inserted after each matched
            // binding identifier. Insertions are in ascending order by
            // byte position — emit segments between them verbatim.
            let mut cursor = i;
            for pos in &insertions {
                out.push_str(&original[cursor..*pos]);
                out.push('!');
                cursor = *pos;
            }
            out.push_str(&original[cursor..stmt_end]);
            i = stmt_end;
        } else {
            let ch_len = utf8_char_len(bytes[i]);
            out.push_str(&original[i..i + ch_len]);
            i += ch_len;
        }
    }
}

/// At byte position `i`, try to recognize an entire `let …;` statement
/// and collect every binding identifier that needs a `!` definite-
/// assignment assertion. Returns `Some((stmt_end, insertions))` on
/// success, where `insertions` are byte positions (ascending) at which
/// to splice `!`. `stmt_end` is the byte position AFTER the terminating
/// `;` (or at newline / EOF if no `;`).
///
/// A declarator qualifies for insertion when its binding is a target
/// name AND it has a `:` type annotation AND has NO `=` initializer
/// before the next `,` or `;` (per TS1263: definite-assignment
/// assertions are illegal with initializers).
///
/// Handles both the simple shape `let foo: T;` and the multi-
/// declarator shape `let a: A = v, b: B, c: C = v;` — each declarator
/// is checked independently.
fn try_process_let_statement(
    bytes: &[u8],
    i: usize,
    target_names: &[SmolStr],
) -> Option<(usize, Vec<usize>)> {
    // Match the `let ` keyword at this position — not part of a larger
    // identifier (`alphalet` shouldn't trigger) and followed by whitespace.
    if i + 3 > bytes.len() || &bytes[i..i + 3] != b"let" {
        return None;
    }
    if i > 0 && is_ident_byte(bytes[i - 1]) {
        return None;
    }
    let after_let = i + 3;
    if after_let >= bytes.len() || !is_ascii_ws(bytes[after_let]) {
        return None;
    }

    // Walk the declarator list. Each iteration consumes one `NAME:
    // type [= init]` declarator and advances past the trailing `,` or
    // stops at the `;`. Depth tracking keeps `,` inside type args
    // (`Map<K, V>`), object types (`{ k: V }`), and call-signature
    // parens from splitting declarators incorrectly.
    let mut insertions: Vec<usize> = Vec::new();
    let mut p = after_let;
    loop {
        // Skip whitespace before the binding identifier.
        while p < bytes.len() && is_ascii_ws(bytes[p]) {
            p += 1;
        }
        // Only handle the simple-identifier binding shape; `let { a }`
        // and `let [ a ]` destructuring are covered by other passes and
        // aren't target-name candidates here anyway.
        if p >= bytes.len()
            || !(bytes[p].is_ascii_alphabetic() || bytes[p] == b'_' || bytes[p] == b'$')
        {
            return None;
        }
        let name_start = p;
        while p < bytes.len() && is_ident_byte(bytes[p]) {
            p += 1;
        }
        let name_end = p;
        let name = &bytes[name_start..name_end];

        // Phase 1: advance past name, looking for `:` type-annotation
        // start. Whitespace INCLUDING newlines is allowed before `:`
        // (multi-line `let foo\n  : string` is legal TS, if rare).
        let mut s = name_end;
        while s < bytes.len() && is_ascii_ws(bytes[s]) {
            s += 1;
        }
        let has_type_annotation = s < bytes.len() && bytes[s] == b':';
        if has_type_annotation {
            s += 1;
        }

        // Phase 2: scan the declarator body for initializer detection
        // and declarator/statement terminator. NEWLINE at depth 0
        // acts as ASI — but only when the next non-whitespace
        // character isn't a union/intersection continuation (`|` /
        // `&`). Multi-line union types like
        //   `export let ticks: \n  | number \n  | null = undefined;`
        // span newlines at depth 0 between the `:` and the real
        // terminator, and treating every newline as ASI would
        // truncate the type, miss the trailing `= undefined`, and
        // wrongly add `!` to a declarator that already has an
        // initializer (TS1264).
        //
        // Paren/brace tracking spans `() [] {}` plus generic-args `<>`.
        // Subtlety with `>`: TypeScript uses it for both generic close
        // (`Foo<T>` — closes the `<`) and arrow return (`() => R` —
        // not a closer). Distinguishing purely by byte-scan: if the
        // character BEFORE a `>` is `=`, it's the arrow; otherwise
        // treat as generic close. That heuristic holds for hand-
        // written TS and avoids the failure where `((...) => R) | U =
        // v;` scans `=>`'s `>` as if it closed an opener, flipping
        // depth negative and missing the real `=` initializer.
        let mut has_initializer = false;
        let mut paren_depth: i32 = 0;
        while s < bytes.len() {
            let c = bytes[s];
            match c {
                b'(' | b'[' | b'{' | b'<' => paren_depth += 1,
                b')' | b']' | b'}' => paren_depth -= 1,
                b'>' => {
                    // Two non-generic-close forms to guard against:
                    //   `=>` — arrow return (prev byte is `=`)
                    //   `>=` — greater-or-equal (next byte is `=`).
                    // Both should NOT decrement paren_depth. Right-
                    // shift operators (`>>`, `>>=`) are deliberately
                    // NOT special-cased — they're rare in script-scope
                    // code, and `>>` inside nested generic types like
                    // `Partial<Record<K, V>>` must still decrement
                    // correctly (twice).
                    let prev = if s > 0 { Some(bytes[s - 1]) } else { None };
                    let next = bytes.get(s + 1).copied();
                    let skip_decrement = prev == Some(b'=') || next == Some(b'=');
                    if !skip_decrement {
                        paren_depth -= 1;
                    }
                }
                b'=' if paren_depth == 0 => {
                    let next = bytes.get(s + 1).copied();
                    match next {
                        Some(b'>') => {
                            // `=>` arrow at depth 0 — scan past both.
                            s += 2;
                            continue;
                        }
                        Some(b'=') => {
                            // `==` / `===` equality — not an
                            // initializer. Skip one ahead.
                            s += 1;
                        }
                        _ => {
                            has_initializer = true;
                        }
                    }
                }
                b',' | b';' if paren_depth == 0 => break,
                b'\n' if paren_depth == 0 => {
                    // ASI at a statement boundary — but only when the
                    // next non-whitespace character doesn't continue
                    // a type annotation. Multi-line union/
                    // intersection types continue across newlines
                    // with a leading `|` / `&`; single-line
                    // declarations end at the newline. Missing this
                    // distinction either breaks ASI (sucks `let
                    // next_stmt` into the previous declarator) or
                    // truncates types (`export let x:\n  | A\n  |
                    // B = v;` looks like `x: ` followed by a new
                    // statement, loses the `=` initializer, and
                    // produces a false TS1264).
                    let mut k = s + 1;
                    while k < bytes.len() && matches!(bytes[k], b' ' | b'\t') {
                        k += 1;
                    }
                    let next_nonws = bytes.get(k).copied();
                    if !matches!(next_nonws, Some(b'|') | Some(b'&')) {
                        break;
                    }
                }
                _ => {}
            }
            s += 1;
        }

        // Qualify the declarator for `!` insertion: name is a target,
        // has a `:` annotation, and no initializer in THIS declarator.
        if has_type_annotation
            && !has_initializer
            && target_names.iter().any(|t| t.as_bytes() == name)
        {
            insertions.push(name_end);
        }

        // Advance past trailing `,` (another declarator follows) or
        // break on `;` / newline / EOF. Newline is a valid terminator
        // per JS ASI — `let foo: string\nnextStatement();` ends at
        // the newline even without an explicit `;`.
        if s >= bytes.len() {
            return Some((s, insertions));
        }
        match bytes[s] {
            b',' => {
                p = s + 1;
                continue;
            }
            b';' => {
                return Some((s + 1, insertions));
            }
            b'\n' => {
                return Some((s, insertions));
            }
            _ => {
                return Some((s, insertions));
            }
        }
    }
}

/// Scan `out` for `let NAME;` / `let NAME\n` / `let NAME, …` declarations
/// where NAME is in `target_names` AND the declarator has no type
/// annotation AND no initializer. Insert `: any` directly after the
/// binding identifier so strict-mode TS types the symbol as `any`
/// instead of `undefined`.
///
/// The typical source is Svelte 4 `export let data;` — unwrapped by
/// script_split into `let data;` in the body. In strict mode that's
/// inferred as `undefined`, and every template reference
/// (`{#if data}`, `<X data={data}>`) then fires "possibly undefined"
/// despite Svelte-4's actual semantic being "untyped prop is `any`".
///
/// Uses the same declarator scanner as
/// `rewrite_definite_assignment_in_place`; only the decision (insert
/// `: any` instead of `!`) differs. Multi-declarator `let a, b: T, c;`
/// targets each declarator independently — `a` and `c` get widened,
/// `b` keeps its explicit type.
/// SVELTE-4-COMPAT: heuristic detector for components that use Svelte-4
/// conventions, i.e. ones whose consumers are likely to pass `on:event`
/// directives (rewritten to `on<event>` prop keys), `slot="x"` named-slot
/// attrs, and similar Svelte-4-specific surface our Svelte-5 emit doesn't
/// model as declared props. Signals, any of which trips detection:
///
/// 1. Any `export let` declaration — strongest signal; Svelte 5 uses
///    `$props()` and `export { … }` instead.
/// 2. Any `<slot>` element in the template — Svelte 5 uses snippets.
/// 3. `createEventDispatcher` imported or called — Svelte 5 uses prop
///    callbacks instead of the dispatcher.
/// 4. `$$Props` / `$$Events` / `$$Slots` interface declared — explicit
///    Svelte-4 typing convention.
/// 5. `$$slots` / `$$props` / `$$restProps` ambients referenced.
///
/// False positives (a genuinely Svelte-5 file containing one of those
/// substrings in a comment) just add a widen clause that's structurally
/// a no-op against well-formed Svelte-5 consumer code. The reverse is
/// costlier — a missed Svelte-4 file surfaces hundreds of TS2353
/// "property does not exist" errors on every consumer.
fn is_svelte4_component(
    doc: &svn_parser::Document<'_>,
    split: Option<&script_split::SplitScript>,
    has_slot: bool,
) -> bool {
    // Signal 1: export let
    let instance_src = doc
        .instance_script
        .as_ref()
        .map(|s| s.content)
        .unwrap_or("");
    let module_src = doc.module_script.as_ref().map(|s| s.content).unwrap_or("");
    if contains_export_let(instance_src) || contains_export_let(module_src) {
        return true;
    }
    // Signal 2: `<slot>` element in the template. Precomputed from the
    // parsed Fragment (see `fragment_contains_slot`); replaces an
    // earlier `doc.source.contains("<slot")` byte scan that false-
    // positived on comments / string content.
    if has_slot {
        return true;
    }
    // Signal 3: createEventDispatcher
    if instance_src.contains("createEventDispatcher")
        || module_src.contains("createEventDispatcher")
    {
        return true;
    }
    // Signal 4: $$Props / $$Events / $$Slots interface
    if has_double_dollar_interface(instance_src) || has_double_dollar_interface(module_src) {
        return true;
    }
    // Signal 5: $$slots / $$props / $$restProps referenced
    if doc.source.contains("$$slots")
        || doc.source.contains("$$restProps")
        || doc.source.contains("$$props")
    {
        return true;
    }
    // Signal (synthetic): `exported_locals` from split — catches
    // `export function` / `export const` used as component methods on
    // Svelte-4 class form.
    if let Some(s) = split {
        if !s.exported_locals.is_empty() {
            return true;
        }
    }
    false
}

fn contains_export_let(src: &str) -> bool {
    // Loose: we want `export let` at word boundaries. Using substring is
    // too permissive (e.g. `/* export let X */` in a comment), but
    // comments would only false-positive, not false-negative — safe.
    let mut rest = src;
    while let Some(idx) = rest.find("export") {
        let after = &rest[idx + 6..];
        if let Some(non_ws) = after.find(|c: char| !c.is_whitespace()) {
            if after[non_ws..].starts_with("let") {
                let next = after[non_ws + 3..].chars().next();
                if matches!(next, Some(c) if c.is_whitespace() || c == '/') {
                    return true;
                }
            }
        }
        rest = &rest[idx + 6..];
    }
    false
}

fn has_double_dollar_interface(src: &str) -> bool {
    src.contains("interface $$Props")
        || src.contains("interface $$Events")
        || src.contains("interface $$Slots")
}

/// SVELTE-4-COMPAT — v0.3 Item 3. Detect whether the component has a
/// `$$Events` interface or type declaration in its instance or module
/// script. When true, the default-export declaration intersects with
/// `& { readonly __svn_events: $$Events }` so consumers resolve to
/// `__svn_ensure_component`'s typed overload and get narrowed
/// `$on("evt", handler)` signatures.
///
/// `createEventDispatcher<T>()` generic extraction is NOT covered
/// here — that's the Svelte-5-style typed dispatcher pattern, gated
/// on AST walking rather than substring detection. Deferred per
/// NEXT.md's follow-up work; a child using typed dispatcher without
/// `$$Events` still routes through the lax overload, matching the
/// v0.2.5 behavior.
/// Does the parsed template fragment contain a `<slot>` element?
///
/// Replaces an earlier `doc.source.contains("<slot")` substring check.
/// The AST walk is strictly more accurate:
/// - Correctly matches only `<slot>` / `<slot name="x">` (tag name is
///   exactly `slot`), not `<slotfoo>` or `<Slot>`.
/// - Skips comments and string content — those produce Text / Comment
///   nodes, not Element nodes.
/// - Recurses into all block children (if/each/await/key/snippet)
///   and nested elements so a `<slot>` inside a branch of an
///   `{#if}` is detected.
///
/// Used by:
/// - `is_svelte4_component` — Signal 2 of the Svelte-4-detection
///   heuristic: rendering a `<slot>` is a strong Svelte-4 signal
///   (Svelte-5 uses `{@render children()}` instead).
/// - `widen_for` / `svelte4_with_slot` — the `__SvnSvelte4PropsWiden`
///   intersection for consumer-side `<Foo slot="x">` compatibility.
fn fragment_contains_slot(fragment: &svn_parser::Fragment) -> bool {
    use svn_parser::Node;
    for node in &fragment.nodes {
        match node {
            Node::Element(e) => {
                if e.name.as_str() == "slot" {
                    return true;
                }
                if fragment_contains_slot(&e.children) {
                    return true;
                }
            }
            Node::Component(c) => {
                if fragment_contains_slot(&c.children) {
                    return true;
                }
            }
            Node::SvelteElement(e) => {
                if fragment_contains_slot(&e.children) {
                    return true;
                }
            }
            Node::IfBlock(b) => {
                if fragment_contains_slot(&b.consequent) {
                    return true;
                }
                for arm in &b.elseif_arms {
                    if fragment_contains_slot(&arm.body) {
                        return true;
                    }
                }
                if let Some(alt) = &b.alternate
                    && fragment_contains_slot(alt)
                {
                    return true;
                }
            }
            Node::EachBlock(b) => {
                if fragment_contains_slot(&b.body) {
                    return true;
                }
                if let Some(alt) = &b.alternate
                    && fragment_contains_slot(alt)
                {
                    return true;
                }
            }
            Node::AwaitBlock(b) => {
                if let Some(p) = &b.pending
                    && fragment_contains_slot(p)
                {
                    return true;
                }
                if let Some(t) = &b.then_branch
                    && fragment_contains_slot(&t.body)
                {
                    return true;
                }
                if let Some(c) = &b.catch_branch
                    && fragment_contains_slot(&c.body)
                {
                    return true;
                }
            }
            Node::KeyBlock(b) => {
                if fragment_contains_slot(&b.body) {
                    return true;
                }
            }
            Node::SnippetBlock(b) => {
                if fragment_contains_slot(&b.body) {
                    return true;
                }
            }
            Node::Text(_) | Node::Comment(_) | Node::Interpolation(_) => {}
        }
    }
    false
}

fn has_strict_events(doc: &svn_parser::Document<'_>) -> bool {
    let instance_src = doc
        .instance_script
        .as_ref()
        .map(|s| s.content)
        .unwrap_or("");
    let module_src = doc.module_script.as_ref().map(|s| s.content).unwrap_or("");
    let has_interface =
        |src: &str| src.contains("interface $$Events") || src.contains("type $$Events ");
    has_interface(instance_src) || has_interface(module_src)
}

/// SVELTE-4-COMPAT: Detect the `<script strictEvents>` bare attribute
/// that upstream svelte2tsx uses as a user opt-in for event-typing
/// narrowing without requiring a `$$Events` interface. One of the
/// three triggers that turns on event narrowing.
fn has_strict_events_attr(doc: &svn_parser::Document<'_>) -> bool {
    doc.instance_script.as_ref().is_some_and(|s| {
        s.attrs
            .iter()
            .any(|a| a.name.eq_ignore_ascii_case("strictEvents") && a.value.is_none())
    })
}

/// Infer Svelte 5 runes mode from the document source. Mirrors
/// `svn_lint::walk::infer_runes_mode` (intentionally duplicated rather
/// than dep'ing on lint — emit needs the signal with no circular dep
/// in the other direction).
///
/// Looks for any rune call (`$state(…)`, `$props(…)`, `$derived(…)`,
/// `$effect(…)`, `$bindable(…)`, `$inspect(…)`, `$host(…)`) or a
/// `.svelte.js` / `.svelte.ts` filename. Runes are always called, so
/// requiring `(` after the name excludes the ambient `$$props` store
/// pattern cheaply. Dotted variants (`$state.raw`, `$derived.by`) are
/// matched by walking past the `.word` chain before the `(`.
fn is_runes_mode(doc: &svn_parser::Document<'_>) -> bool {
    let source = doc.source;
    for marker in [
        "$state",
        "$derived",
        "$effect",
        "$props",
        "$bindable",
        "$inspect",
        "$host",
    ] {
        let bytes = source.as_bytes();
        let mbytes = marker.as_bytes();
        let mut i = 0;
        while let Some(rel) = bytes[i..].windows(mbytes.len()).position(|w| w == mbytes) {
            let pos = i + rel;
            // Skip `$$props` ambient (preceding `$`).
            if pos.checked_sub(1).and_then(|p| bytes.get(p)).copied() == Some(b'$') {
                i = pos + mbytes.len();
                continue;
            }
            let mut after = pos + mbytes.len();
            while bytes.get(after) == Some(&b'.') {
                after += 1;
                while after < bytes.len()
                    && (bytes[after].is_ascii_alphanumeric() || bytes[after] == b'_')
                {
                    after += 1;
                }
            }
            while after < bytes.len() && matches!(bytes[after], b' ' | b'\t') {
                after += 1;
            }
            if bytes.get(after) == Some(&b'(') {
                return true;
            }
            i = pos + mbytes.len();
        }
    }
    false
}

/// SVELTE-4-COMPAT: de-narrow a typed-with-initializer exported
/// declaration. Scans `out` for `let NAME: T = EXPR;` where NAME is
/// in `target_names`, then inserts `NAME = undefined as any;`
/// immediately after the terminating `;`. The cast widens TS's
/// flow-narrowed type back to the declared annotation, so later
/// comparisons like `NAME === 'other-literal'` don't fire TS2367.
///
/// Declarations without a type annotation or without an initializer
/// are skipped — those are already handled by the widen / definite-
/// assign passes.
fn denarrow_typed_exported_props_in_place(out: &mut String, target_names: &[SmolStr]) {
    if target_names.is_empty() {
        return;
    }
    let original = std::mem::take(out);
    let bytes = original.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if let Some((stmt_end, matched_names)) =
            try_process_let_statement_for_denarrow(bytes, i, target_names)
        {
            // Emit the original statement verbatim (start..stmt_end)
            // then append `NAME = undefined as any;\n` for each matched
            // name. Keeps byte positions of the original unchanged —
            // only appends.
            out.push_str(&original[i..stmt_end]);
            for name in &matched_names {
                out.push('\n');
                out.push_str(name);
                out.push_str(" = undefined as any;");
            }
            i = stmt_end;
        } else {
            let ch_len = utf8_char_len(bytes[i]);
            out.push_str(&original[i..i + ch_len]);
            i += ch_len;
        }
    }
}

/// Declarator scanner matched to `try_process_let_statement_*` twins.
/// Qualifies a declarator when: name IS a target AND has a `:` type
/// annotation AND has an `=` initializer. Returns the matched names
/// so the caller can append assignments after the statement.
fn try_process_let_statement_for_denarrow(
    bytes: &[u8],
    i: usize,
    target_names: &[SmolStr],
) -> Option<(usize, Vec<SmolStr>)> {
    if i + 3 > bytes.len() || &bytes[i..i + 3] != b"let" {
        return None;
    }
    if i > 0 && is_ident_byte(bytes[i - 1]) {
        return None;
    }
    let after_let = i + 3;
    if after_let >= bytes.len() || !is_ascii_ws(bytes[after_let]) {
        return None;
    }

    let mut matched: Vec<SmolStr> = Vec::new();
    let mut p = after_let;
    loop {
        while p < bytes.len() && is_ascii_ws(bytes[p]) {
            p += 1;
        }
        if p >= bytes.len()
            || !(bytes[p].is_ascii_alphabetic() || bytes[p] == b'_' || bytes[p] == b'$')
        {
            return None;
        }
        let name_start = p;
        while p < bytes.len() && is_ident_byte(bytes[p]) {
            p += 1;
        }
        let name_end = p;
        let name_bytes = &bytes[name_start..name_end];

        let mut s = name_end;
        while s < bytes.len() && is_ascii_ws(bytes[s]) {
            s += 1;
        }
        // Definite-assign `!` follows the name before `:` in
        // declarations already rewritten by the def-assign pass.
        // Skip it so we still see the type annotation.
        if s < bytes.len() && bytes[s] == b'!' {
            s += 1;
            while s < bytes.len() && is_ascii_ws(bytes[s]) {
                s += 1;
            }
        }
        let has_type_annotation = s < bytes.len() && bytes[s] == b':';
        if has_type_annotation {
            s += 1;
        }

        let mut has_initializer = false;
        let mut paren_depth: i32 = 0;
        while s < bytes.len() {
            let c = bytes[s];
            match c {
                b'(' | b'[' | b'{' | b'<' => paren_depth += 1,
                b')' | b']' | b'}' => paren_depth -= 1,
                b'>' => {
                    let prev = if s > 0 { Some(bytes[s - 1]) } else { None };
                    if prev != Some(b'=') {
                        paren_depth -= 1;
                    }
                }
                b'=' if paren_depth == 0 => {
                    let next = bytes.get(s + 1).copied();
                    match next {
                        Some(b'>') => {
                            s += 2;
                            continue;
                        }
                        Some(b'=') => {
                            s += 1;
                        }
                        _ => {
                            has_initializer = true;
                        }
                    }
                }
                b',' | b';' if paren_depth == 0 => break,
                // `\n` terminates in most cases. Two continuation
                // patterns need to survive the newline, because a
                // `;` or `;`-less line-terminator would truncate a
                // legitimate multi-line initializer:
                //
                //   Previous non-ws is `=` — `let x: T =\n  value;`
                //     (dangling assignment, continuation is RHS).
                //
                //   Next non-ws is `?` or `:` (ternary continuation)
                //     — `let x: T = cond\n  ? a\n  : b;`.
                //
                // Both survive by not treating `\n` as a terminator.
                // Other cases — `let x = 1\nlet y = 2` — do terminate
                // at the newline, per JS ASI.
                b'\n' if paren_depth == 0 => {
                    let mut prev = s;
                    while prev > 0 {
                        prev -= 1;
                        let b = bytes[prev];
                        if b != b' ' && b != b'\t' {
                            break;
                        }
                    }
                    let prev_continues = bytes[prev] == b'=';
                    let mut next = s + 1;
                    while next < bytes.len()
                        && (bytes[next] == b' ' || bytes[next] == b'\t' || bytes[next] == b'\n')
                    {
                        next += 1;
                    }
                    let next_continues = next < bytes.len()
                        && matches!(
                            bytes[next],
                            // Ternary `?:`, optional-chain `?.`,
                            // method/property access `.`, binary/
                            // logical ops `&& || ?? + - * / % | & ^`,
                            // type-assertion `as`. All valid line-
                            // continuation starts that ASI won't
                            // insert a break before.
                            b'?' | b':'
                                | b'.'
                                | b'&'
                                | b'|'
                                | b'+'
                                | b'-'
                                | b'*'
                                | b'/'
                                | b'%'
                                | b'^'
                                | b'='
                        );
                    if !prev_continues && !next_continues {
                        break;
                    }
                }
                _ => {}
            }
            s += 1;
        }

        if has_type_annotation
            && has_initializer
            && target_names.iter().any(|t| t.as_bytes() == name_bytes)
        {
            if let Ok(name_str) = std::str::from_utf8(name_bytes) {
                matched.push(SmolStr::from(name_str));
            }
        }

        if s >= bytes.len() {
            return Some((s, matched));
        }
        match bytes[s] {
            b',' => {
                p = s + 1;
                continue;
            }
            b';' => return Some((s + 1, matched)),
            b'\n' => return Some((s, matched)),
            _ => return Some((s, matched)),
        }
    }
}

/// SVELTE-4-COMPAT: emit `let $$slots = …; let $$props = …; let
/// $$restProps = …;` at the top of the render function when the source
/// references them.
///
/// Substring detection is deliberately loose — we don't parse to see
/// whether the occurrence is a real identifier vs. string content. A
/// spurious injection is harmless (the declared local just goes
/// unused), whereas a missed one fires TS2304 across every reference
/// and cascades through the surrounding expression's typing.
///
/// Types: `Record<string, any>` for all three. Upstream's
/// `__sveltets_2_slotsType({…slot names…})` is more precise (each
/// slot is typed as `boolean | ''`), but that requires walking the
/// template to collect slot names and emit a shape literal. We'll do
/// that in Phase 2 if the loose ambient isn't sufficient.
fn emit_svelte4_ambients(out: &mut String, doc: &svn_parser::Document<'_>, is_ts: bool) {
    let src = doc.source;
    // In TS overlays we emit inline `: T` annotations. In JS overlays
    // we must not — tsgo fires TS8010 ("Type annotations can only be
    // used in TypeScript files"), and even worse tsgo's semantic
    // check aborts project-wide once TS8010 is hit, silently
    // suppressing every legitimate TS2322/TS7005/… diagnostic
    // elsewhere. Emit JSDoc casts on the RHS for JS overlays.
    if src.contains("$$slots") {
        if is_ts {
            out.push_str("    let $$slots: Record<string, boolean | undefined> = {};\n");
        } else {
            out.push_str(
                "    let $$slots = /** @type {Record<string, boolean | undefined>} */ ({});\n",
            );
        }
        out.push_str("    void $$slots;\n");
    }
    if src.contains("$$restProps") {
        if is_ts {
            out.push_str("    let $$restProps: Record<string, any> = {};\n");
        } else {
            out.push_str("    let $$restProps = /** @type {Record<string, any>} */ ({});\n");
        }
        out.push_str("    void $$restProps;\n");
    }
    // `$$props` detection has to avoid `$$restProps` — the word
    // boundary check: must not be preceded by `rest` (the only
    // Svelte-4 form where $$props appears as a suffix).
    if let Some(idx) = src.find("$$props") {
        let prev = src.as_bytes().get(idx.saturating_sub(4)..idx);
        let is_rest = matches!(prev, Some(b"rest"));
        if !is_rest || src.matches("$$props").count() > src.matches("$$restProps").count() {
            if is_ts {
                out.push_str("    let $$props: Record<string, any> = {};\n");
            } else {
                out.push_str("    let $$props = /** @type {Record<string, any>} */ ({});\n");
            }
            out.push_str("    void $$props;\n");
        }
    }
}

/// JS-overlay equivalent of `rewrite_definite_assignment_in_place` +
/// `widen_untyped_exported_props_in_place` rolled into one. For each
/// `let NAME[, NAME…];` declaration where NAME is a target AND that
/// declarator has no initializer, splice `= /** @type {any} */ (null)`
/// between NAME (or its type annotation) and the terminator — turning
/// `let b;` into `let b = /** @type {any} */ (null);`.
///
/// Fixes three TS-strict-mode JS-overlay diagnostics in one pass:
///   - TS7034/TS7005 on the declaration ("variable implicitly any in
///     some locations") — the initializer's `any` gives TS an explicit
///     type for subsequent flow.
///   - TS2454 on later reads ("used before being assigned") — the
///     initializer satisfies definite-assign flow.
///   - TS2367/TS2322 on type-check expressions that would have
///     otherwise narrowed against a body-local `undefined`-inferred
///     type.
///
/// User-authored JSDoc `/** @type {T} */` preceding the declaration is
/// preserved and takes priority: TS reads user's `@type` to declare
/// NAME as `T`, the initializer's `any` is assignable to `T` via JS-loose
/// rules, no TS2322 secondary fires.
///
/// No TS-only syntax is emitted, so tsgo doesn't fire TS8010 on the
/// generated `.svelte.svn.js` file. Mirrors the outcome of upstream
/// svelte2tsx's `let NAME; NAME = __sveltets_2_any(NAME);` shape
/// (wrapped in `/*Ωignore_startΩ*/…/*Ωignore_endΩ*/` markers upstream
/// uses to suppress diagnostics the self-assign would otherwise fire)
/// without needing the ignore-range filtering machinery.
fn widen_untyped_exports_jsdoc_in_place(
    out: &mut String,
    target_names: &[SmolStr],
    route_kind: Option<sveltekit::RouteKind>,
) {
    if target_names.is_empty() {
        return;
    }
    let original = std::mem::take(out);
    let bytes = original.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if let Some((stmt_end, insertions)) =
            try_process_let_statement_for_widening(bytes, i, target_names)
        {
            let mut cursor = i;
            for (pos, name) in &insertions {
                out.push_str(&original[cursor..*pos]);
                let kit_type = route_kind.and_then(|k| sveltekit::kit_widen_type(name, k));
                match kit_type {
                    // Kit types must launder through `any` first — a
                    // direct cast from `null` to `PageData` fires
                    // TS2352 in strict mode when PageData doesn't
                    // overlap with `null`. Matches upstream's
                    // `data = __sveltets_2_any(data)` any-assign
                    // trick in spirit.
                    Some(ty) => {
                        out.push_str(" = /** @type {");
                        out.push_str(ty);
                        out.push_str("} */ (/** @type {any} */ (null))");
                    }
                    None => {
                        out.push_str(" = /** @type {any} */ (null)");
                    }
                }
                cursor = *pos;
            }
            out.push_str(&original[cursor..stmt_end]);
            i = stmt_end;
        } else {
            let ch_len = utf8_char_len(bytes[i]);
            out.push_str(&original[i..i + ch_len]);
            i += ch_len;
        }
    }
}

fn widen_untyped_exported_props_in_place(
    out: &mut String,
    target_names: &[SmolStr],
    route_kind: Option<sveltekit::RouteKind>,
) {
    if target_names.is_empty() {
        return;
    }
    let original = std::mem::take(out);
    let bytes = original.as_bytes();
    let mut i = 0;
    while i < bytes.len() {
        if let Some((stmt_end, insertions)) =
            try_process_let_statement_for_widening(bytes, i, target_names)
        {
            let mut cursor = i;
            for (pos, name) in &insertions {
                out.push_str(&original[cursor..*pos]);
                // SvelteKit route files get `import('./$types.js').PageData`
                // injected for `data`/`form`/`snapshot` — matches upstream
                // `svelte2tsx/src/svelte2tsx/nodes/ExportedNames.ts:424-440`.
                // All other names widen to `: any` as before.
                let widen_type = route_kind
                    .and_then(|k| sveltekit::kit_widen_type(name, k))
                    .unwrap_or("any");
                out.push_str(": ");
                out.push_str(widen_type);
                cursor = *pos;
            }
            out.push_str(&original[cursor..stmt_end]);
            i = stmt_end;
        } else {
            let ch_len = utf8_char_len(bytes[i]);
            out.push_str(&original[i..i + ch_len]);
            i += ch_len;
        }
    }
}

/// Declarator scanner twin of `try_process_let_statement`. The
/// traversal is byte-for-byte identical; only the qualification rule
/// flips: widen when name IS a target AND has NO type AND NO
/// initializer.
fn try_process_let_statement_for_widening(
    bytes: &[u8],
    i: usize,
    target_names: &[SmolStr],
) -> Option<(usize, Vec<(usize, SmolStr)>)> {
    if i + 3 > bytes.len() || &bytes[i..i + 3] != b"let" {
        return None;
    }
    if i > 0 && is_ident_byte(bytes[i - 1]) {
        return None;
    }
    let after_let = i + 3;
    if after_let >= bytes.len() || !is_ascii_ws(bytes[after_let]) {
        return None;
    }

    let mut insertions: Vec<(usize, SmolStr)> = Vec::new();
    let mut p = after_let;
    loop {
        while p < bytes.len() && is_ascii_ws(bytes[p]) {
            p += 1;
        }
        if p >= bytes.len()
            || !(bytes[p].is_ascii_alphabetic() || bytes[p] == b'_' || bytes[p] == b'$')
        {
            return None;
        }
        let name_start = p;
        while p < bytes.len() && is_ident_byte(bytes[p]) {
            p += 1;
        }
        let name_end = p;
        let name = &bytes[name_start..name_end];

        let mut s = name_end;
        while s < bytes.len() && is_ascii_ws(bytes[s]) {
            s += 1;
        }
        let has_type_annotation = s < bytes.len() && bytes[s] == b':';
        if has_type_annotation {
            s += 1;
        }

        let mut has_initializer = false;
        // When the initializer is literally `undefined` or `null`, we
        // still want to widen. Upstream widens Svelte-4 `export let x
        // = <literal>` via a trailing `x = __sveltets_2_any(x)`
        // reassignment; our equivalent is to annotate `: any` so the
        // declared type doesn't narrow to the literal. Without this,
        // `export let zIndex = undefined;` narrows to `zIndex:
        // undefined` and downstream reads fire TS7005 / TS7034.
        let mut initializer_is_nullish = false;
        let mut paren_depth: i32 = 0;
        while s < bytes.len() {
            let c = bytes[s];
            match c {
                b'(' | b'[' | b'{' | b'<' => paren_depth += 1,
                b')' | b']' | b'}' => paren_depth -= 1,
                b'>' => {
                    let prev = if s > 0 { Some(bytes[s - 1]) } else { None };
                    if prev != Some(b'=') {
                        paren_depth -= 1;
                    }
                }
                b'=' if paren_depth == 0 => {
                    let next = bytes.get(s + 1).copied();
                    match next {
                        Some(b'>') => {
                            s += 2;
                            continue;
                        }
                        Some(b'=') => {
                            s += 1;
                        }
                        _ => {
                            has_initializer = true;
                            // Peek past whitespace for a literal
                            // `undefined` / `null` initializer.
                            let mut p2 = s + 1;
                            while p2 < bytes.len() && is_ascii_ws(bytes[p2]) {
                                p2 += 1;
                            }
                            let rest = &bytes[p2..];
                            let is_word_end = |off: usize| {
                                bytes
                                    .get(p2 + off)
                                    .copied()
                                    .map(|b| !is_ident_byte(b))
                                    .unwrap_or(true)
                            };
                            if (rest.starts_with(b"undefined") && is_word_end(9))
                                || (rest.starts_with(b"null") && is_word_end(4))
                            {
                                initializer_is_nullish = true;
                            }
                        }
                    }
                }
                b',' | b';' | b'\n' if paren_depth == 0 => break,
                _ => {}
            }
            s += 1;
        }

        // Widen when: target name, NO type annotation, AND either NO
        // initializer OR the initializer is a bare `undefined`/`null`
        // literal (Svelte-4 `export let x = undefined` pattern).
        let should_widen = !has_type_annotation
            && (!has_initializer || initializer_is_nullish)
            && target_names.iter().any(|t| t.as_bytes() == name);
        if should_widen {
            let name_str = std::str::from_utf8(name).ok().map(SmolStr::from)?;
            insertions.push((name_end, name_str));
        }

        if s >= bytes.len() {
            return Some((s, insertions));
        }
        match bytes[s] {
            b',' => {
                p = s + 1;
                continue;
            }
            b';' => return Some((s + 1, insertions)),
            b'\n' => return Some((s, insertions)),
            _ => return Some((s, insertions)),
        }
    }
}

#[inline]
fn is_ascii_ws(b: u8) -> bool {
    matches!(b, b' ' | b'\t' | b'\n' | b'\r')
}

#[inline]
fn is_ident_byte(b: u8) -> bool {
    b.is_ascii_alphanumeric() || b == b'_' || b == b'$'
}

#[inline]
fn utf8_char_len(b: u8) -> usize {
    if b < 0xC0 {
        1
    } else if b < 0xE0 {
        2
    } else if b < 0xF0 {
        3
    } else {
        4
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::path::PathBuf;
    use svn_analyze::walk_template;
    use svn_parser::{parse_all_template_runs, parse_sections};

    fn def_assign(src: &str, targets: &[&str]) -> String {
        let mut out = String::from(src);
        let targets: Vec<SmolStr> = targets.iter().map(|s| SmolStr::from(*s)).collect();
        rewrite_definite_assignment_in_place(&mut out, &targets);
        out
    }

    fn widen(src: &str, targets: &[&str]) -> String {
        let mut out = String::from(src);
        let targets: Vec<SmolStr> = targets.iter().map(|s| SmolStr::from(*s)).collect();
        widen_untyped_exported_props_in_place(&mut out, &targets, None);
        out
    }

    // ---------- extract_property_chains (Phase 3.2) ----------
    // Gate the AST-based rewrite against the canonical shapes the
    // byte walker handled.

    fn chains(text: &str) -> Vec<String> {
        extract_property_chains(text)
    }

    #[test]
    fn chains_plain_identifier() {
        assert_eq!(chains("foo"), vec!["foo"]);
    }

    #[test]
    fn chains_member_access() {
        assert_eq!(chains("ctx.GhostButton"), vec!["ctx.GhostButton"]);
    }

    #[test]
    fn chains_optional_member_access() {
        assert_eq!(chains("ctx?.GhostButton"), vec!["ctx?.GhostButton"]);
    }

    #[test]
    fn chains_logical_and_chain() {
        assert_eq!(
            chains("editable && ctx.GhostButton && options.length < max"),
            vec!["editable", "ctx.GhostButton", "options.length", "max"]
        );
    }

    #[test]
    fn chains_nullish_coalescing_with_equality() {
        // Regression: the byte walker returned `name1` via its balanced-
        // paren skip + next-identifier pickup. The AST walker must
        // produce the same chain list.
        assert_eq!(chains("(name1 ?? \"bla\") == \"world\""), vec!["name1"]);
    }

    #[test]
    fn chains_call_keeps_callee_not_args() {
        // Arrow body in the arg list must NOT leak: `m`, `m.role`
        // are arrow-scope bindings.
        assert_eq!(
            chains("messages.some((m) => m.role === 'x')"),
            vec!["messages.some"]
        );
    }

    #[test]
    fn chains_await_argument_recurses() {
        // Regression: condition `await promise` must emit `[promise]`
        // as the ref marker. The AST walker was dropping
        // AwaitExpression in an earlier iteration.
        assert_eq!(chains("await promise"), vec!["promise"]);
    }

    #[test]
    fn chains_dedup_preserves_first_order() {
        assert_eq!(chains("a && b && a.c && a"), vec!["a", "b", "a.c"]);
    }

    #[test]
    fn chains_filters_keywords() {
        // `typeof x === 'string'` — `typeof` is a keyword, skip.
        assert_eq!(chains("typeof x === 'string'"), vec!["x"]);
    }

    #[test]
    fn chains_filters_dollar_ident() {
        // Svelte auto-subscribe `$store` is handled separately; it
        // shouldn't appear in the marker.
        assert_eq!(chains("$store && ok"), vec!["ok"]);
    }

    #[test]
    fn chains_empty_input_returns_empty() {
        assert!(chains("").is_empty());
    }

    #[test]
    fn widen_untyped_uninitialized_target() {
        // Svelte-4 `export let data;` lands in body as `let data;` —
        // untyped, uninitialized. Widen to `let data: any;` so strict
        // mode treats it as `any` rather than `undefined`.
        let got = widen("let data;", &["data"]);
        assert_eq!(got, "let data: any;");
    }

    #[test]
    fn widen_skips_typed_declaration() {
        // Already has `: Type` — don't double up.
        let got = widen("let foo: string;", &["foo"]);
        assert_eq!(got, "let foo: string;");
    }

    #[test]
    fn widen_skips_initialized_declaration() {
        // Has `= init` — TS will infer a type.
        let got = widen("let foo = 0;", &["foo"]);
        assert_eq!(got, "let foo = 0;");
    }

    #[test]
    fn widen_skips_untarget_name() {
        // Name not in the widen list — body-local, user intent is
        // undefined-inference. Leave alone.
        let got = widen("let temp;", &["data"]);
        assert_eq!(got, "let temp;");
    }

    #[test]
    fn widen_multi_declarator_per_decl() {
        // Three declarators, mixed shapes. Only the untyped-uninitialized
        // exported ones get widened.
        let got = widen("let a, b: string, c = 0, d;", &["a", "b", "c", "d"]);
        assert_eq!(got, "let a: any, b: string, c = 0, d: any;");
    }

    #[test]
    fn widen_then_def_assign_composes_cleanly() {
        // Pipeline order: widen runs first, then definite-assign.
        // `let data;` → `let data: any;` (widen) → `let data!: any;` (def_assign).
        let mut out = String::from("let data;");
        let targets: Vec<SmolStr> = vec![SmolStr::from("data")];
        widen_untyped_exported_props_in_place(&mut out, &targets, None);
        rewrite_definite_assignment_in_place(&mut out, &targets);
        assert_eq!(out, "let data!: any;");
    }

    #[test]
    fn widen_preserves_arrow_typed_prop() {
        // Regression: naive scanner that hides the `:` annotation behind
        // `!` would re-widen already-typed props. With widen running
        // BEFORE def-assign, the typed declarator is left alone.
        let got = widen("let onChange: (value: string) => void;", &["onChange"]);
        assert_eq!(got, "let onChange: (value: string) => void;");
    }

    #[test]
    fn def_assign_single_declarator() {
        let got = def_assign("let foo: string;", &["foo"]);
        assert_eq!(got, "let foo!: string;");
    }

    #[test]
    fn def_assign_skips_declaration_with_initializer() {
        // Has `=` before `;` → TS1263 forbids `!`, so leave alone.
        let got = def_assign("let foo: string = 'hi';", &["foo"]);
        assert_eq!(got, "let foo: string = 'hi';");
    }

    #[test]
    fn def_assign_skips_untyped_declaration() {
        // No `:`, no type annotation → no assertion site.
        let got = def_assign("let foo;", &["foo"]);
        assert_eq!(got, "let foo;");
    }

    #[test]
    fn def_assign_skips_non_target_name() {
        let got = def_assign("let other: string;", &["foo"]);
        assert_eq!(got, "let other: string;");
    }

    #[test]
    fn def_assign_multi_declarator_mixed_init() {
        // Core regression: second declarator is uninitialized-typed.
        let got = def_assign(
            "let name3: string = '', name4: string;",
            &["name3", "name4"],
        );
        assert_eq!(got, "let name3: string = '', name4!: string;");
    }

    #[test]
    fn def_assign_multi_declarator_all_need_assertion() {
        let got = def_assign("let a: string, b: number, c: boolean;", &["a", "b", "c"]);
        assert_eq!(got, "let a!: string, b!: number, c!: boolean;");
    }

    #[test]
    fn def_assign_multi_declarator_only_targets_assert() {
        let got = def_assign("let a: string, b: number, c: boolean;", &["a", "c"]);
        assert_eq!(got, "let a!: string, b: number, c!: boolean;");
    }

    #[test]
    fn def_assign_inside_generic_types_not_tripped_by_angle_brackets() {
        // `<T = U>` is a default-type-param, not a let-initializer.
        let got = def_assign("let foo: Map<string, number>;", &["foo"]);
        assert_eq!(got, "let foo!: Map<string, number>;");
    }

    #[test]
    fn def_assign_inside_function_type_not_tripped_by_arrow() {
        let got = def_assign("let foo: () => void;", &["foo"]);
        assert_eq!(got, "let foo!: () => void;");
    }

    #[test]
    fn def_assign_arrow_in_type_plus_initializer_correctly_detected() {
        // Real-world regression: `let foo: (x: T) => R = () => ...;`
        // has a `=` inside `=>`, a `>` after it, AND a real `=` before
        // the initializer. The scanner must not flip paren_depth
        // negative on the arrow's `>`, and must detect the real `=`.
        let got = def_assign("let foo: () => void = () => {};", &["foo"]);
        assert_eq!(got, "let foo: () => void = () => {};", "has init → no !");
    }

    #[test]
    fn def_assign_complex_function_type_with_init() {
        let got = def_assign(
            "let onclick: ((e: MouseEvent) => void) | undefined = undefined;",
            &["onclick"],
        );
        assert_eq!(
            got, "let onclick: ((e: MouseEvent) => void) | undefined = undefined;",
            "union of function type + initializer → no !",
        );
    }

    #[test]
    fn def_assign_fn_type_with_nested_object_and_init() {
        let got = def_assign(
            "let onclick: (e: MouseEvent, { data }: { data: any }) => any = () => {};",
            &["onclick"],
        );
        assert_eq!(
            got, "let onclick: (e: MouseEvent, { data }: { data: any }) => any = () => {};",
            "function type with destructure param + arrow-body init → no !",
        );
    }

    #[test]
    fn def_assign_real_emit_shape() {
        // The exact body shape our emit produces for ts-export-list-runes.v5.
        // ASI-terminated name1 initializer must not swallow name2 through.
        let src = "    let name1: string = \"world\"\n    let name2: string;\n    let name3: string = '', name4: string;\n";
        let got = def_assign(src, &["name1", "name2", "name3", "name4"]);
        // name1 has init → no !. name2, name4 typed-no-init → ! each.
        assert!(
            got.contains("let name2!: string;"),
            "name2 should get !, got: {got:?}"
        );
        assert!(
            got.contains("name4!: string;"),
            "name4 should get !, got: {got:?}"
        );
        assert!(
            got.contains("let name1: string = \"world\""),
            "name1 unchanged (has init): {got:?}"
        );
    }

    #[test]
    fn def_assign_preserves_surrounding_content() {
        let got = def_assign("before();\nlet name: string;\nafter();\n", &["name"]);
        assert_eq!(got, "before();\nlet name!: string;\nafter();\n");
    }

    fn emit_str(src: &str) -> String {
        emit_str_with_path(src, "/test/Anonymous.svelte")
    }

    fn emit_str_with_path(src: &str, path: &str) -> String {
        let (doc, errors) = parse_sections(src);
        assert!(errors.is_empty(), "parse errors: {errors:?}");
        let (fragment, errors) = parse_all_template_runs(src, &doc.template.text_runs);
        assert!(errors.is_empty(), "template parse errors: {errors:?}");
        let summary = walk_template(&fragment, src);
        emit_document(&doc, &fragment, &summary, &PathBuf::from(path)).typescript
    }

    #[test]
    fn empty_source_still_emits_scaffold() {
        let out = emit_str("");
        assert!(out.contains("function $$render_"));
        assert!(out.contains("__svn_tpl_check"));
        assert!(
            out.contains("void __svn_tpl_check;"),
            "expected per-statement void of __svn_tpl_check:\n{out}"
        );
    }

    #[test]
    fn render_name_includes_hash_suffix() {
        let out = emit_str("");
        // Scan for the function name and verify it has 8 hex chars after
        // the `$$render_` prefix.
        let idx = out.find("function $$render_").unwrap();
        let tail = &out[idx + "function $$render_".len()..];
        let suffix: String = tail.chars().take(8).collect();
        assert_eq!(suffix.len(), 8, "8-char suffix expected, got {suffix:?}");
        assert!(
            suffix.chars().all(|c| c.is_ascii_hexdigit()),
            "suffix should be hex, got {suffix:?}"
        );
    }

    #[test]
    fn different_paths_produce_different_render_names() {
        let a = emit_str_with_path("<p>hi</p>", "/test/A.svelte");
        let b = emit_str_with_path("<p>hi</p>", "/test/B.svelte");
        // Same content, different paths → different render names. This is
        // what stops the TS2393 cascade across multiple components in one
        // overlay project.
        let a_name = extract_render_name(&a);
        let b_name = extract_render_name(&b);
        assert_ne!(
            a_name, b_name,
            "different paths must hash to different render names"
        );
    }

    #[test]
    fn same_path_produces_stable_render_name() {
        let a1 = emit_str_with_path("<p>hi</p>", "/test/Foo.svelte");
        let a2 = emit_str_with_path("<p>hi</p>", "/test/Foo.svelte");
        assert_eq!(extract_render_name(&a1), extract_render_name(&a2));
    }

    fn extract_render_name(out: &str) -> String {
        let idx = out.find("function $$render_").unwrap();
        let tail = &out[idx + "function ".len()..];
        tail.chars()
            .take_while(|c| *c != '(' && *c != '<')
            .collect()
    }

    #[test]
    fn does_not_emit_svelte_reference_directive() {
        // /// <reference types="svelte" /> would trigger TS2688 in fixtures
        // that don't have the svelte package installed. We rely on the
        // user's environment to have svelte (or our future shim file)
        // rather than asserting it here.
        let out = emit_str("");
        assert!(!out.contains("<reference types=\"svelte\""));
    }

    #[test]
    fn imports_hoisted_above_render_function() {
        let src = "<script lang=\"ts\">\
                   import { writable } from 'svelte/store';\
                   const x = writable(0);\
                   </script>";
        let out = emit_str(src);
        let import_pos = out.find("import { writable }").expect("import present");
        let render_pos = out.find("function $$render_").expect("render present");
        assert!(
            import_pos < render_pos,
            "imports must be hoisted above the render function (found imports at {import_pos}, render at {render_pos})"
        );
    }

    #[test]
    fn imports_only_appear_once() {
        // Hoisted to module top-level — must NOT also appear inside
        // $$render. The body should have whitespace where the import was.
        let src = "<script lang=\"ts\">\
                   import { writable } from 'svelte/store';\
                   const x = writable(0);\
                   </script>";
        let out = emit_str(src);
        let count = out.matches("import { writable }").count();
        assert_eq!(count, 1);
    }

    #[test]
    fn passes_module_script_verbatim() {
        let out = emit_str("<script context=\"module\">export const A = 1;</script>");
        assert!(out.contains("export const A = 1;"));
    }

    #[test]
    fn template_check_wrapper_in_void_block() {
        let out = emit_str("<p>hi</p>");
        assert!(out.contains("void __svn_tpl_check;"));
    }

    #[test]
    fn use_directive_emits_action_attrs() {
        let out = emit_str("<div use:tooltip>x</div>");
        assert!(out.contains("__svn_action_attrs_0"));
        assert!(out.contains("let __svn_action_attrs_0"));
    }

    #[test]
    fn bind_pair_emits_bind_pair_declaration() {
        let out = emit_str("<input bind:value={() => g(), (v) => s(v)} />");
        assert!(out.contains("__svn_bind_pair_0"));
        assert!(out.contains("let __svn_bind_pair_0"));
    }

    #[test]
    fn render_function_is_referenced() {
        let out = emit_str("<p>hi</p>");
        // Self-reference is `<render_name>;` on its own line.
        assert!(out.contains("$$render_"));
        let render_name = extract_render_name(&out);
        assert!(out.contains(&format!("{render_name};")));
    }

    #[test]
    fn void_block_uses_per_statement_form() {
        // Switched from `void (a, b, c);` to `void X; void Y; void Z;`
        // — the consolidated form triggers TS2695 ("Left side of comma
        // operator is unused"). Each synthesized name gets its own
        // `void X;` line, and we should never emit the parenthesized
        // multi-name form.
        let out = emit_str("<div use:a use:b>x</div>");
        assert!(
            !out.contains("    void ("),
            "no parenthesized void(...) form expected:\n{out}"
        );
        assert!(out.contains("void __svn_action_attrs_0;"));
        assert!(out.contains("void __svn_action_attrs_1;"));
    }

    #[test]
    fn each_block_without_as_clause_uses_placeholder_binding() {
        let out = emit_str("{#each items}<span>x</span>{/each}");
        assert!(out.contains("for (const"), "missing for-of loop:\n{out}");
        assert!(
            !out.contains("for (const  of"),
            "empty binding produced double-space-before-`of`:\n{out}"
        );
    }

    #[test]
    fn each_block_with_binding_uses_user_name() {
        let out = emit_str("{#each items as item}<span>{item}</span>{/each}");
        assert!(out.contains("for (const item of"));
    }

    #[test]
    fn each_with_destructured_pattern() {
        let out = emit_str("{#each pairs as { a, b }}<x />{/each}");
        assert!(out.contains("for (const"));
        assert!(!out.contains("for (const  of"));
    }

    #[test]
    fn bind_this_target_gets_definite_assignment() {
        let src = "<script lang=\"ts\">let inputEl: HTMLDivElement;</script>\
                   <div bind:this={inputEl}></div>";
        let out = emit_str(src);
        assert!(
            out.contains("let inputEl!:"),
            "missing definite-assignment rewrite:\n{out}"
        );
        assert!(
            !out.contains("let inputEl: "),
            "still has un-rewritten declaration:\n{out}"
        );
    }

    #[test]
    fn non_bind_target_let_unchanged() {
        let src = "<script lang=\"ts\">let other: number = 1;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("let other: number"),
            "non-bind-target should not be rewritten:\n{out}"
        );
        assert!(!out.contains("let other!"));
    }

    #[test]
    fn bind_target_with_initializer_unchanged() {
        let src = "<script lang=\"ts\">let inputEl = null as any as HTMLDivElement;</script>\
                   <div bind:this={inputEl}></div>";
        let out = emit_str(src);
        assert!(
            !out.contains("let inputEl!"),
            "shouldn't add `!` to declarations with initializers:\n{out}"
        );
    }

    #[test]
    fn no_generics_attribute_emits_plain_function() {
        let out = emit_str("<script lang=\"ts\">let x = 1;</script>");
        let render = extract_render_name(&out);
        assert!(out.contains(&format!("{render}() {{")));
        assert!(!out.contains(&format!("{render}<")));
    }

    #[test]
    fn simple_generics_attribute_threaded_into_function_signature() {
        // `<script generics="T">` puts T in scope inside the body.
        let src = "<script lang=\"ts\" generics=\"T\">let x: T;</script>";
        let out = emit_str(src);
        let render = extract_render_name(&out);
        assert!(
            out.contains(&format!("{render}<T>() {{")),
            "generic T should appear in function signature:\n{out}"
        );
    }

    #[test]
    fn generics_with_constraint_threaded_verbatim() {
        let src = "<script lang=\"ts\" generics=\"T extends Record<string, unknown>\">\
                   let x: T;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("<T extends Record<string, unknown>>"),
            "constrained generic should be spliced verbatim:\n{out}"
        );
    }

    #[test]
    fn multiple_generics_threaded() {
        let src = "<script lang=\"ts\" generics=\"T, K extends keyof T\">\
                   let x: T;</script>";
        let out = emit_str(src);
        assert!(
            out.contains("<T, K extends keyof T>"),
            "multi-param generics should be spliced verbatim:\n{out}"
        );
    }

    #[test]
    fn empty_generics_attribute_treated_as_absent() {
        let src = "<script lang=\"ts\" generics=\"\">let x = 1;</script>";
        let out = emit_str(src);
        let render = extract_render_name(&out);
        assert!(out.contains(&format!("{render}() {{")));
        assert!(!out.contains(&format!("{render}<")));
    }
}
